INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 1, 'LIBRO de la generación de Jesucristo, hijo de David, hijo de Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 2, 'Abraham engendró á Isaac: é Isaac engendró á Jacob: y Jacob engendró á Judas y á sus hermanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 3, 'Y Judas engendró de Thamar á Phares y á Zara: y Phares engendró á Esrom: y Esrom engendró á Aram:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 4, 'Y Aram engendró á Aminadab: y Aminadab engendró á Naassón: y Naassón engendró á Salmón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 5, 'Y Salmón engendró de Rachâb á Booz, y Booz engendró de Ruth á Obed y Obed engendró á Jessé:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 6, 'Y Jessé engendró al rey David: y el rey David engendró á Salomón de la que fué mujer de Urías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 7, 'Y Salomón engendró á Roboam: y Roboam engendró á Abía: y Abía engendró á Asa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 8, 'Y Asa engendró á Josaphat: y Josaphat engendró á Joram: y Joram engendró á Ozías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 9, 'Y Ozías engendró á Joatam: y Joatam engendró á Achâz: y Achâz engendró á Ezechîas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 10, 'Y Ezechîas engendró á Manasés: y Manasés engendró á Amón: y Amón engendró á Josías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 11, 'Y Josías engendró á Jechônías y á sus hermanos, en la transmigración de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 12, 'Y después de la transmigración de Babilonia, Jechônías engendró á Salathiel: y Salathiel engendró á Zorobabel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 13, 'Y Zorobabel engendró á Abiud: y Abiud engendró á Eliachîm: y Eliachîm engendró á Azor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 14, 'Y Azor engendró á Sadoc: y Sadoc engendró á Achîm: y Achîm engendró á Eliud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 15, 'Y Eliud engendró á Eleazar: y Eleazar engendró á Mathán: y Mathán engendró á Jacob:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 16, 'Y Jacob engendró á José, marido de María, de la cual nació Jesús, el cual es llamado el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 17, 'De manera que todas las generaciones desde Abraham hasta David son catorce generaciones: y desde David hasta la transmigración de Babilonia, catorce generaciones: y desde la transmigración de Babilonia hasta Cristo, catorce generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 18, 'Y el nacimiento de Jesucristo fué así: Que siendo María su madre desposada con José, antes que se juntasen, se halló haber concebido del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 19, 'Y José su marido, como era justo, y no quisiese infamarla, quiso dejarla secretamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 20, 'Y pensando él en esto, he aquí el ángel del Señor le aparece en sueños, diciendo: José, hijo de David, no temas de recibir á María tu mujer, porque lo que en ella es engendrado, del Espíritu Santo es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 21, 'Y parirá un hijo, y llamarás su nombre JESUS, porque él salvará á su pueblo de sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 22, 'Todo esto aconteció para que se cumpliese lo que fué dicho por el Señor, por el profeta que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 23, 'He aquí la virgen concebirá y parirá un hijo, Y llamarás su nombre Emmanuel, que declarado, es: Con nosotros Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 24, 'Y despertando José del sueño, hizo como el ángel del Señor le había mandado, y recibió á su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 1, 25, 'Y no la conoció hasta que parió á su hijo primogénito: y llamó su nombre JESUS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 1, 'Y COMO fué nacido Jesús en Bethlehem de Judea en días del rey Herodes, he aquí unos magos vinieron del oriente á Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 2, 'Diciendo: ¿Dónde está el Rey de los Judíos, que ha nacido? porque su estrella hemos visto en el oriente, y venimos á adorarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 3, 'Y oyendo esto el rey Herodes, se turbó, y toda Jerusalem con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 4, 'Y convocados todos los príncipes de los sacerdotes, y los escribas del pueblo, les preguntó dónde había de nacer el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 5, 'Y ellos le dijeron: En Bethlehem de Judea; porque así está escrito por el profeta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 6, 'Y tú, Bethlehem, de tierra de Judá, No eres muy pequeña entre los príncipes de Judá; Porque de ti saldrá un guiador, Que apacentará á mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 7, 'Entonces Herodes, llamando en secreto á los magos, entendió de ellos diligentemente el tiempo del aparecimiento de la estrella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 8, 'Y enviándolos á Bethlehem, dijo: Andad allá, y preguntad con diligencia por el niño; y después que le hallareis, hacédmelo saber, para que yo también vaya y le adore.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 9, 'Y ellos, habiendo oído al rey, se fueron: y he aquí la estrella que habían visto en el oriente, iba delante de ellos, hasta que llegando, se puso sobre donde estaba el niño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 10, 'Y vista la estrella, se regocijaron con muy grande gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 11, 'Y entrando en la casa, vieron al niño con su madre María, y postrándose, le adoraron; y abriendo sus tesoros, le ofrecieron dones, oro, é incienso y mirra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 12, 'Y siendo avisados por revelación en sueños que no volviesen á Herodes, se volvieron á su tierra por otro camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 13, 'Y partidos ellos, he aquí el ángel del Señor aparece en sueños á José, diciendo: Levántate, y toma al niño y á su madre, y huye á Egipto, y estáte allá hasta que yo te lo diga; porque ha de acontecer, que Herodes buscará al niño para matarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 14, 'Y él despertando, tomó al niño y á su madre de noche, y se fué á Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 15, 'Y estuvo allá hasta la muerte de Herodes: para que se cumpliese lo que fué dicho por el Señor, por el profeta que dijo: De Egipto llamé á mi Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 16, 'Herodes entonces, como se vió burlado de los magos, se enojó mucho, y envió, y mató á todos los niños que había en Bethlehem y en todos sus términos, de edad de dos años abajo, conforme al tiempo que había entendido de los magos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 17, 'Entonces fué cumplido lo que se había dicho por el profeta Jeremías, que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 18, 'Voz fué oída en Ramá, Grande lamentación, lloro y gemido: Rachêl que llora sus hijos, Y no quiso ser consolada, porque perecieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 19, 'Mas muerto Herodes, he aquí el ángel del Señor aparece en sueños á José en Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 20, 'Diciendo: Levántate, y toma al niño y á su madre, y vete á tierra de Israel; que muertos son los que procuraban la muerte del niño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 21, 'Entonces él se levantó, y tomó al niño y á su madre, y se vino á tierra de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 22, 'Y oyendo que Archelao reinaba en Judea en lugar de Herodes su padre, temió ir allá: mas amonestado por revelación en sueños, se fué á las partes de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 2, 23, 'Y vino, y habitó en la ciudad que se llama Nazaret: para que se cumpliese lo que fué dicho por los profetas, que había de ser llamado Nazareno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 1, 'Y EN aquellos días vino Juan el Bautista predicando en el desierto de Judea,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 2, 'Y diciendo: Arrepentíos, que el reino de los cielos se ha acercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 3, 'Porque éste es aquel del cual fué dicho por el profeta Isaías, que dijo: Voz de uno que clama en el desierto: Aparejad el camino del Señor, Enderezad sus veredas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 4, 'Y tenía Juan su vestido de pelos de camellos, y una cinta de cuero alrededor de sus lomos; y su comida era langostas y miel silvestre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 5, 'Entonces salía á él Jerusalem, y toda Judea, y toda la provincia de alrededor del Jordán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 6, 'Y eran bautizados de él en el Jordán, confesando sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 7, 'Y viendo él muchos de los Fariseos y de los Saduceos, que venían á su bautismo, decíales: Generación de víboras, ¿quién os ha enseñado á huir de la ira que vendrá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 8, 'Haced pues frutos dignos de arrepentimiento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 9, 'Y no penséis decir dentro de vosotros: á Abraham tenemos por padre: porque yo os digo, que puede Dios despertar hijos á Abraham aun de estas piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 10, 'Ahora, ya también la segur está puesta á la raíz de los árboles; y todo árbol que no hace buen fruto, es cortado y echado en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 11, 'Yo á la verdad os bautizo en agua para arrepentimiento; mas el que viene tras mí, más poderoso es que yo; los zapatos del cual yo no soy digno de llevar; él os bautizará en Espíritu Santo y en fuego');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 12, 'Su aventador en su mano está, y aventará su era: y allegará su trigo en el alfolí, y quemará la paja en fuego que nunca se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 13, 'Entonces Jesús vino de Galilea á Juan al Jordán, para ser bautizado de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 14, 'Mas Juan lo resistía mucho, diciendo: Yo he menester ser bautizado de ti, ¿y tú vienes á mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 15, 'Empero respondiendo Jesús le dijo: Deja ahora; porque así nos conviene cumplir toda justicia. Entonces le dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 16, 'Y Jesús, después que fué bautizado, subió luego del agua; y he aquí los cielos le fueron abiertos, y vió al Espíritu de Dios que descendía como paloma, y venía sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 3, 17, 'Y he aquí una voz de los cielos que decía: Este es mi Hijo amado, en el cual tengo contentamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 1, 'ENTONCES Jesús fué llevado del Espíritu al desierto, para ser tentado del diablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 2, 'Y habiendo ayunado cuarenta días y cuarenta noches, después tuvo hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 3, 'Y llegándose á él el tentador, dijo: Si eres Hijo de Dios, di que estas piedras se hagan pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 4, 'Mas él respondiendo, dijo: Escrito está: No con solo el pan vivirá el hombre, mas con toda palabra que sale de la boca de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 5, 'Entonces el diablo le pasa á la santa ciudad, y le pone sobre las almenas del templo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 6, 'Y le dice: Si eres Hijo de Dios, échate abajo; que escrito está: A sus ángeles mandará por ti, Y te alzarán en las manos, Para que nunca tropieces con tu pie en piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 7, 'Jesús le dijo: Escrito está además: No tentarás al Señor tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 8, 'Otra vez le pasa el diablo á un monte muy alto, y le muestra todos los reinos del mundo, y su gloria,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 9, 'Y dícele: Todo esto te daré, si postrado me adorares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 10, 'Entonces Jesús le dice: Vete, Satanás, que escrito está: Al Señor tu Dios adorarás y á él solo servirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 11, 'El diablo entonces le dejó: y he aquí los ángeles llegaron y le servían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 12, 'Mas oyendo Jesús que Juan era preso, se volvió á Galilea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 13, 'Y dejando á Nazaret, vino y habitó en Capernaum, ciudad marítima, en los confines de Zabulón y de Nephtalim:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 14, 'Para que se cumpliese lo que fué dicho por el profeta Isaías, que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 15, 'La tierra de Zabulón, y la tierra de Nephtalim, Camino de la mar, de la otra parte del Jordán, Galilea de los Gentiles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 16, 'El pueblo asentado en tinieblas, Vió gran luz; Y á los sentados en región y sombra de muerte, Luz les esclareció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 17, 'Desde entonces comenzó Jesús á predicar, y á decir: Arrepentíos, que el reino de los cielos se ha acercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 18, 'Y andando Jesús junto á la mar de Galilea, vió á dos hermanos, Simón, que es llamado Pedro, y Andrés su hermano, que echaban la red en la mar; porque eran pescadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 19, 'Y díceles: Venid en pos de mí, y os haré pescadores de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 20, 'Ellos entonces, dejando luego las redes, le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 21, 'Y pasando de allí vió otros dos hermanos, Jacobo, hijo de Zebedeo, y Juan su hermano, en el barco con Zebedeo, su padre, que remendaban sus redes; y los llamó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 22, 'Y ellos, dejando luego el barco y á su padre, le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 23, 'Y rodeó Jesús toda Galilea, enseñando en las sinagogas de ellos, y predicando el evangelio del reino, y sanando toda enfermedad y toda dolencia en el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 24, 'Y corría su fama por toda la Siria; y le trajeron todos los que tenían mal: los tomados de diversas enfermedades y tormentos, y los endemoniados, y lunáticos, y paralíticos, y los sanó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 4, 25, 'Y le siguieron muchas gentes de Galilea y de Decápolis y de Jerusalem y de Judea y de la otra parte del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 1, 'Y VIENDO las gentes, subió al monte; y sentándose, se llegaron á él sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 2, 'Y abriendo su boca, les enseñaba, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 3, 'Bienaventurados los pobres en espíritu: porque de ellos es el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 4, 'Bienaventurados los que lloran: porque ellos recibirán consolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 5, 'Bienaventurados los mansos: porque ellos recibirán la tierra por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 6, 'Bienaventurados los que tienen hambre y sed de justicia: porque ellos serán hartos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 7, 'Bienaventurados los misericordiosos: porque ellos alcanzarán misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 8, 'Bienaventurados los de limpio corazón: porque ellos verán á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 9, 'Bienaventurados los pacificadores: porque ellos serán llamados hijos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 10, 'Bienaventurados los que padecen persecución por causa de la justicia: porque de ellos es el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 11, 'Bienaventurados sois cuando os vituperaren y os persiguieren, y dijeren de vosotros todo mal por mi causa, mintiendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 12, 'Gozaos y alegraos; porque vuestra merced es grande en los cielos: que así persiguieron á los profetas que fueron antes de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 13, 'Vosotros sois la sal de la tierra: y si la sal se desvaneciere ¿con qué será salada? no vale más para nada, sino para ser echada fuera y hollada de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 14, 'Vosotros sois la luz del mundo: una ciudad asentada sobre un monte no se puede esconder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 15, 'Ni se enciende una lámpara y se pone debajo de un almud, mas sobre el candelero, y alumbra á todos los que están en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 16, 'Así alumbre vuestra luz delante de los hombres, para que vean vuestras obras buenas, y glorifiquen á vuestro Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 17, 'No penséis que he venido para abrogar la ley ó los profetas: no he venido para abrogar, sino á cumplir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 18, 'Porque de cierto os digo, que hasta que perezca el cielo y la tierra, ni una jota ni un tilde perecerá de la ley, hasta que todas las cosas sean hechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 19, 'De manera que cualquiera que infringiere uno de estos mandamientos muy pequeños, y así enseñare á los hombres, muy pequeño será llamado en el reino de los cielos: mas cualquiera que hiciere y enseñare, éste será llamado grande en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 20, 'Porque os digo, que si vuestra justicia no fuere mayor que la de los escribas y de los Fariseos, no entraréis en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 21, 'Oísteis que fué dicho á los antiguos: No matarás; mas cualquiera que matare, será culpado del juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 22, 'Mas yo os digo, que cualquiera que se enojare locamente con su hermano, será culpado del juicio; y cualquiera que dijere á su hermano, Raca, será culpado del concejo; y cualquiera que dijere, Fatuo, será culpado del infierno del fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 23, 'Por tanto, si trajeres tu presente al altar, y allí te acordares de que tu hermano tiene algo contra ti,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 24, 'Deja allí tu presente delante del altar, y vete, vuelve primero en amistad con tu hermano, y entonces ven y ofrece tu presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 25, 'Concíliate con tu adversario presto, entre tanto que estás con él en el camino; porque no acontezca que el adversario te entregue al juez, y el juez te entregue al alguacil, y seas echado en prisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 26, 'De cierto te digo, que no saldrás de allí, hasta que pagues el último cuadrante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 27, 'Oísteis que fué dicho: No adulterarás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 28, 'Mas yo os digo, que cualquiera que mira á una mujer para codiciarla, ya adulteró con ella en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 29, 'Por tanto, si tu ojo derecho te fuere ocasión de caer, sácalo, y échalo de ti: que mejor te es que se pierda uno de tus miembros, que no que todo tu cuerpo sea echado al infierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 30, 'Y si tu mano derecha te fuere ocasión de caer, córtala, y échala de ti: que mejor te es que se pierda uno de tus miembros, que no que todo tu cuerpo sea echado al infierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 31, 'También fué dicho: Cualquiera que repudiare á su mujer, déle carta de divorcio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 32, 'Mas yo os digo, que el que repudiare á su mujer, fuera de causa de fornicación, hace que ella adultere; y el que se casare con la repudiada, comete adulterio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 33, 'Además habéis oído que fué dicho á los antiguos: No te perjurarás; mas pagarás al Señor tus juramentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 34, 'Mas yo os digo: No juréis en ninguna manera: ni por el cielo, porque es el trono de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 35, 'Ni por la tierra, porque es el estrado de sus pies; ni por Jerusalem, porque es la ciudad del gran Rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 36, 'Ni por tu cabeza jurarás, porque no puedes hacer un cabello blanco ó negro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 37, 'Mas sea vuestro hablar: Sí, sí; No, no; porque lo que es más de esto, de mal procede.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 38, 'Oísteis que fué dicho á los antiguos: Ojo por ojo, y diente por diente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 39, 'Mas yo os digo: No resistáis al mal; antes á cualquiera que te hiriere en tu mejilla diestra, vuélvele también la otra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 40, 'Y al que quisiere ponerte á pleito y tomarte tu ropa, déjale también la capa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 41, 'Y á cualquiera que te cargare por una milla, ve con él dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 42, 'Al que te pidiere, dale; y al que quisiere tomar de ti prestado, no se lo rehuses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 43, 'Oísteis que fué dicho: Amarás á tu prójimo, y aborrecerás á tu enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 44, 'Mas yo os digo: Amad á vuestros enemigos, bendecid á los que os maldicen, haced bien á los que os aborrecen, y orad por los que os ultrajan y os persiguen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 45, 'Para que seáis hijos de vuestro Padre que está en los cielos: que hace que su sol salga sobre malos y buenos, y llueve sobre justos é injustos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 46, 'Porque si amareis á los que os aman, ¿qué recompensa tendréis? ¿no hacen también lo mismo los publicanos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 47, 'Y si abrazareis á vuestros hermanos solamente, ¿qué hacéis de más? ¿no hacen también así los Gentiles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 5, 48, 'Sed, pues, vosotros perfectos, como vuestro Padre que está en los cielos es perfecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 1, 'MIRAD que no hagáis vuestra justicia delante de los hombres, para ser vistos de ellos: de otra manera no tendréis merced de vuestro Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 2, 'Cuando pues haces limosna, no hagas tocar trompeta delante de ti, como hacen los hipócritas en las sinagogas y en las plazas, para ser estimados de los hombres: de cierto os digo, que ya tienen su recompensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 3, 'Mas cuando tú haces limosna, no sepa tu izquierda lo que hace tu derecha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 4, 'Para que sea tu limosna en secreto: y tu Padre que ve en secreto, él te recompensará en público.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 5, 'Y cuando oras, no seas como los hipócritas; porque ellos aman el orar en las sinagogas, y en los cantones de las calles en pie, para ser vistos de los hombres: de cierto os digo, que ya tienen su pago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 6, 'Mas tú, cuando oras, éntrate en tu cámara, y cerrada tu puerta, ora á tu Padre que está en secreto; y tu Padre que ve en secreto, te recompensará en público.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 7, 'Y orando, no seáis prolijos, como los Gentiles; que piensan que por su parlería serán oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 8, 'No os hagáis, pues, semejantes á ellos; porque vuestro Padre sabe de qué cosas tenéis necesidad, antes que vosotros le pidáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 9, 'Vosotros pues, oraréis así: Padre nuestro que estás en los cielos, santificado sea tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 10, 'Venga tu reino. Sea hecha tu voluntad, como en el cielo, así también en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 11, 'Danos hoy nuestro pan cotidiano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 12, 'Y perdónanos nuestras deudas, como también nosotros perdonamos á nuestros deudores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 13, 'Y no nos metas en tentación, mas líbranos del mal: porque tuyo es el reino, y el poder, y la gloria, por todos los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 14, 'Porque si perdonareis á los hombres sus ofensas, os perdonará también á vosotros vuestro Padre celestial.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 15, 'Mas si no perdonareis á los hombres sus ofensas, tampoco vuestro Padre os perdonará vuestras ofensas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 16, 'Y cuando ayunáis, no seáis como los hipócritas, austeros; porque ellos demudan sus rostros para parecer á los hombres que ayunan: de cierto os digo, que ya tienen su pago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 17, 'Mas tú, cuando ayunas, unge tu cabeza y lava tu rostro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 18, 'Para no parecer á los hombres que ayunas, sino á tu Padre que está en secreto: y tu Padre que ve en secreto, te recompensará en público.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 19, 'No os hagáis tesoros en la tierra, donde la polilla y el orín corrompe, y donde ladronas minan y hurtan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 20, 'Mas haceos tesoros en el cielo, donde ni polilla ni orín corrompe, y donde ladrones no minan ni hurtan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 21, 'Porque donde estuviere vuestro tesoro, allí estará vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 22, 'La lámpara del cuerpo es el ojo: así que, si tu ojo fuere sincero, todo tu cuerpo será luminoso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 23, 'Mas si tu ojo fuere malo, todo tu cuerpo será tenebroso. Así que, si la lumbre que en ti hay son tinieblas, ¿cuántas serán las mismas tinieblas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 24, 'Ninguno puede servir á dos señores; porque ó aborrecerá al uno y amará al otro, ó se llegará al uno y menospreciará al otro: no podéis servir á Dios y á Mammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 25, 'Por tanto os digo: No os congojéis por vuestra vida, qué habéis de comer, ó que habéis de beber; ni por vuestro cuerpo, qué habéis de vestir: ¿no es la vida más que el alimento, y el cuerpo que el vestido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 26, 'Mirad las aves del cielo, que no siembran, ni siegan, ni allegan en alfolíes; y vuestro Padre celestial las alimenta. ¿No sois vosotros mucho mejores que ellas?.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 27, 'Mas ¿quién de vosotros podrá, congojándose, añadir á su estatura un codo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 28, 'Y por el vestido ¿por qué os congojáis? Reparad los lirios del campo, cómo crecen; no trabajan ni hilan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 29, 'Mas os digo, que ni aun Salomón con toda su gloria fué vestido así como uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 30, 'Y si la hierba del campo que hoy es, y mañana es echada en el horno, Dios la viste así, ¿no hará mucho más á vosotros, hombres de poca fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 31, 'No os congojéis pues, diciendo: ¿Qué comeremos, ó qué beberemos, ó con qué nos cubriremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 32, 'Porque los Gentiles buscan todas estas cosas: que vuestro Padre celestial sabe que de todas estas cosas habéis menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 33, 'Mas buscad primeramente el reino de Dios y su justicia, y todas estas cosas os serán añadidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 6, 34, 'Así que, no os congojéis por el día de mañana; que el día de mañana traerá su fatiga: basta al día su afán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 1, 'NO juzguéis, para que no seáis juzgados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 2, 'Porque con el juicio con que juzgáis, seréis juzgados; y con la medida con que medís, os volverán á medir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 3, 'Y ¿por qué miras la mota que está en el ojo de tu hermano, y no echas de ver la viga que está en tu ojo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 4, 'O ¿cómo dirás á tu hermano: Espera, echaré de tu ojo la mota, y he aquí la viga en tu ojo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 5, '¡Hipócrita! echa primero la viga de tu ojo, y entonces mirarás en echar la mota del ojo de tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 6, 'No deis lo santo á los perros, ni echéis vuestras perlas delante de los puercos; porque no las rehuellen con sus pies, y vuelvan y os despedacen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 7, 'Pedid, y se os dará; buscad, y hallaréis; llamad, y se os abrirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 8, 'Porque cualquiera que pide, recibe; y el que busca, halla; y al que llama, se abrirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 9, '¿Qué hombre hay de vosotros, á quien si su hijo pidiere pan, le dará una piedra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 10, '¿Y si le pidiere un pez, le dará una serpiente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 11, 'Pues si vosotros, siendo malos, sabéis dar buenas dádivas á vuestros hijos, ¿cuánto más vuestro Padre que está en los cielos, dará buenas cosas á los que le piden?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 12, 'Así que, todas las cosas que quisierais que los hombres hiciesen con vosotros, así también haced vosotros con ellos; porque esta es la ley y los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 13, 'Entrad por la puerta estrecha: porque ancha es la puerta, y espacioso el camino que lleva á perdición, y muchos son los que entran por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 14, 'Porque estrecha es la puerta, y angosto el camino que lleva á la vida, y pocos son los que la hallan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 15, 'Y guardaos de los falsos profetas, que vienen á vosotros con vestidos de ovejas, mas de dentro son lobos rapaces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 16, 'Por sus frutos los conoceréis. ¿Cógense uvas de los espinos, ó higos de los abrojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 17, 'Así, todo buen árbol lleva buenos frutos; mas el árbol maleado lleva malos frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 18, 'No puede el buen árbol llevar malos frutos, ni el árbol maleado llevar frutos buenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 19, 'Todo árbol que no lleva buen fruto, córtase y échase en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 20, 'Así que, por sus frutos los conoceréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 21, 'No todo el que me dice: Señor, Señor, entrará en el reino de los cielos: mas el que hiciere la voluntad de mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 22, 'Muchos me dirán en aquel día: Señor, Señor, ¿no profetizamos en tu nombre, y en tu nombre lanzamos demonios, y en tu nombre hicimos mucho milagros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 23, 'Y entonces les protestaré: Nunca os conocí; apartaos de mí, obradores de maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 24, 'Cualquiera, pues, que me oye estas palabras, y las hace, le compararé á un hombre prudente, que edificó su casa sobre la peña;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 25, 'Y descendió lluvia, y vinieron ríos, y soplaron vientos, y combatieron aquella casa; y no cayó: porque estaba fundada sobre la peña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 26, 'Y cualquiera que me oye estas palabras, y no las hace, le compararé á un hombre insensato, que edificó su casa sobre la arena;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 27, 'Y descendió lluvia, y vinieron ríos, y soplaron vientos, é hicieron ímpetu en aquella casa; y cayó, y fué grande su ruina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 28, 'Y fué que, como Jesús acabó estas palabras, las gentes se admiraban de su doctrina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 7, 29, 'Porque les enseñaba como quien tiene autoridad, y no como los escribas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 1, 'Y COMO descendió del monte, le seguían muchas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 2, 'Y he aquí un leproso vino, y le adoraba, diciendo: Señor, si quisieres, puedes limpiarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 3, 'Y extendiendo Jesús su mano, le tocó, diciendo: Quiero; sé limpio. Y luego su lepra fué limpiada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 4, 'Entonces Jesús le dijo: Mira, no lo digas á nadie; mas ve, muéstrate al sacerdote, y ofrece el presente que mandó Moisés, para testimonio á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 5, 'Y entrando Jesús en Capernaum, vino á él un centurión, rogándole,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 6, 'Y diciendo: Señor, mi mozo yace en casa paralítico, gravemente atormentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 7, 'Y Jesús le dijo: Yo iré y le sanaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 8, 'Y respondió el centurión, y dijo: Señor, no soy digno de que entres debajo de mi techado; mas solamente di la palabra, y mi mozo sanará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 9, 'Porque también yo soy hombre bajo de potestad, y tengo bajo de mí soldados: y digo á éste: Ve, y va; y al otro: Ven, y viene; y á mi siervo: Haz esto, y lo hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 10, 'Y oyendo Jesús, se maravilló, y dijo á los que le seguían: De cierto os digo, que ni aun en Israel he hallado fe tanta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 11, 'Y os digo que vendrán muchos del oriente y del occidente, y se sentarán con Abraham, é Isaac, y Jacob, en el reino de los cielos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 12, 'Mas los hijos del reino serán echados á las tinieblas de afuera: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 13, 'Entonces Jesús dijo al centurión: Ve, y como creiste te sea hecho. Y su mozo fué sano en el mismo momento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 14, 'Y vino Jesús á casa de Pedro, y vió á su suegra echada en cama, y con fiebre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 15, 'Y tocó su mano, y la fiebre la dejó: y ella se levantó, y les servía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 16, 'Y como fué ya tarde, trajeron á él muchos endemoniados: y echó los demonios con la palabra, y sanó á todos los enfermos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 17, 'Para que se cumpliese lo que fué dicho por el profeta Isaías, que dijo: El mismo tomó nuestras enfermedades, y llevó nuestras dolencias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 18, 'Y viendo Jesús muchas gentes alrededor de sí, mandó pasar á la otra parte del lago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 19, 'Y llegándose un escriba, le dijo: Maestro, te seguiré á donde quiera que fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 20, 'Y Jesús le dijo: Las zorras tienen cavernas, y las aves del cielo nidos; mas el Hijo del hombre no tiene donde recueste su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 21, 'Y otro de sus discípulos le dijo: Señor, dame licencia para que vaya primero, y entierre á mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 22, 'Y Jesús le dijo: Sígueme; deja que los muertos entierren á sus muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 23, 'Y entrando él en el barco, sus discípulos le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 24, 'Y he aquí, fué hecho en la mar un gran movimiento, que el barco se cubría de las ondas; mas él dormía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 25, 'Y llegándose sus discípulos, le despertaron, diciendo: Señor, sálvanos, que perecemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 26, 'Y él les dice: ¿Por qué teméis, hombres de poca fe? Entonces, levantándose, reprendió á los vientos y á la mar; y fué grande bonanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 27, 'Y los hombres se maravillaron, diciendo: ¿Qué hombre es éste, que aun los vientos y la mar le obedecen?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 28, 'Y como él hubo llegado en la otra ribera al país de los Gergesenos, le vinieron al encuentro dos endemoniados que salían de los sepulcros, fieros en gran manera, que nadie podía pasar por aquel camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 29, 'Y he aquí clamaron, diciendo: ¿Qué tenemos contigo, Jesús, Hijo de Dios? ¿has venido acá á molestarnos antes de tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 30, 'Y estaba lejos de ellos un hato de muchos puercos paciendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 31, 'Y los demonios le rogaron, diciendo: Si nos echas, permítenos ir á aquel hato de puercos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 32, 'Y les dijo: Id. Y ellos salieron, y se fueron á aquel hato de puercos: y he aquí, todo el hato de los puercos se precipitó de un despeñadero en la mar, y murieron en las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 33, 'Y los porqueros huyeron, y viniendo á la ciudad, contaron todas las cosas, y lo que había pasado con los endemoniados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 8, 34, 'Y he aquí, toda la ciudad salió á encontrar á Jesús: Y cuando le vieron, le rogaban que saliese de sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 1, 'ENTONCES entrando en el barco, pasó á la otra parte, y vino á su ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 2, 'Y he aquí le trajeron un paralítico, echado en una cama: y viendo Jesús la fe de ellos, dijo al paralítico: Confía, hijo; tus pecados te son perdonados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 3, 'Y he aquí, algunos de los escribas decían dentro de sí: Este blasfema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 4, 'Y viendo Jesús sus pensamientos, dijo: ¿Por qué pensáis mal en vuestros corazones?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 5, 'Porque, ¿qué es más fácil, decir: Los pecados te son perdonados; ó decir: Levántate, y anda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 6, 'Pues para que sepáis que el Hijo del hombre tiene potestad en la tierra de perdonar pecados, (dice entonces al paralítico): Levántate, toma tu cama, y vete á tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 7, 'Entonces él se levantó y se fué á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 8, 'Y las gentes, viéndolo, se maravillaron, y glorificaron á Dios, que había dado tal potestad á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 9, 'Y pasando Jesús de allí, vió á un hombre que estaba sentado al banco de los públicos tributos, el cual se llamaba Mateo; y dícele: Sígueme. Y se levantó, y le siguió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 10, 'Y aconteció que estando él sentado á la mesa en casa, he aquí que muchos publicanos y pecadores, que habían venido, se sentaron juntamente á la mesa con Jesús y sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 11, 'Y viendo esto los Fariseos, dijeron á sus discípulos: ¿Por qué come vuestro Maestro con los publicanos y pecadores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 12, 'Y oyéndolo Jesús, le dijo: Los que están sanos no tienen necesidad de médico, sino los enfermos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 13, 'Andad pues, y aprended qué cosa es: Misericordia quiero, y no sacrificio: porque no he venido á llamar justos, sino pecadores á arrepentimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 14, 'Entonces los discípulos de Juan vienen á él, diciendo: ¿Por qué nosotros y los Fariseos ayunamos muchas veces, y tus discípulos no ayunan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 15, 'Y Jesús les dijo: ¿Pueden los que son de bodas tener luto entre tanto que el esposo está con ellos? mas vendrán días cuando el esposo será quitado de ellos, y entonces ayunarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 16, 'Y nadie echa remiendo de paño recio en vestido viejo; porque el tal remiendo tira del vestido, y se hace peor la rotura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 17, 'Ni echan vino nuevo en cueros viejos: de otra manera los cueros se rompen, y el vino se derrama, y se pierden los cueros; mas echan el vino nuevo en cueros nuevos, y lo uno y lo otro se conserva juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 18, 'Hablando él estas cosas á ellos, he aquí vino un principal, y le adoraba, diciendo: Mi hija es muerta poco ha: mas ven y pon tu mano sobre ella, y vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 19, 'Y se levantó Jesús, y le siguió, y sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 20, 'Y he aquí una mujer enferma de flujo de sangre doce años había, llegándose por detrás, tocó la franja de su vestido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 21, 'Porque decía entre sí: Si tocare solamente su vestido, seré salva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 22, 'Mas Jesús volviéndose, y mirándola, dijo: Confía, hija, tu fe te ha salvado. Y la mujer fué salva desde aquella hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 23, 'Y llegado Jesús á casa del principal, viendo los tañedores de flautas, y la gente que hacía bullicio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 24, 'Díceles: Apartaos, que la muchacha no es muerta, mas duerme. Y se burlaban de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 25, 'Y como la gente fué echada fuera, entró, y tomóla de la mano, y se levantó la muchacha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 26, 'Y salió esta fama por toda aquella tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 27, 'Y pasando Jesús de allí, le siguieron dos ciegos, dando voces y diciendo: Ten misericordia de nosotros, Hijo de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 28, 'Y llegado á la casa, vinieron á él los ciegos; y Jesús les dice: ¿Creéis que puedo hacer esto? Ellos dicen: Sí, Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 29, 'Entonces tocó los ojos de ellos, diciendo: Conforme á vuestra fe os sea hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 30, 'Y los ojos de ellos fueron abiertos. Y Jesús les encargó rigurosamente, diciendo: Mirad que nadie lo sepa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 31, 'Mas ellos salidos, divulgaron su fama por toda aquella tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 32, 'Y saliendo ellos, he aquí, le trajeron un hombre mudo, endemoniado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 33, 'Y echado fuera el demonio, el mudo habló; y las gentes se maravillaron, diciendo: Nunca ha sido vista cosa semejante en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 34, 'Mas los Fariseos decían: Por el príncipe de los demonios echa fuera los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 35, 'Y rodeaba Jesús por todas las ciudades y aldeas, enseñando en las sinagogas de ellos, y predicando el evangelio del reino, y sanando toda enfermedad y todo achaque en el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 36, 'Y viendo las gentes, tuvo compasión de ellas; porque estaban derramadas y esparcidas como ovejas que no tienen pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 37, 'Entonces dice á sus discípulos: A la verdad la mies es mucha, mas los obreros pocos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 9, 38, 'Rogad, pues, al Señor de la mies, que envíe obreros á su mies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 1, 'ENTONCES llamando á sus doce discípulos, les dió potestad contra los espíritus inmundos, para que los echasen fuera, y sanasen toda enfermedad y toda dolencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 2, 'Y los nombres de los doce apóstoles son estos: el primero, Simón, que es dicho Pedro, y Andrés su hermano; Jacobo, hijo de Zebedeo, y Juan su hermano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 3, 'Felipe, y Bartolomé; Tomás, y Mateo el publicano; Jacobo hijo de Alfeo, y Lebeo, por sobrenombre Tadeo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 4, 'Simón el Cananita y Judas Iscariote, que también le entregó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 5, 'á estos doce envió Jesús, á los cuales dió mandamiento, diciendo: Por el camino de los Gentiles no iréis, y en ciudad de Samaritanos no entréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 6, 'Mas id antes á las ovejas perdidas de la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 7, 'Y yendo, predicad, diciendo: El reino de los cielos se ha acercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 8, 'Sanad enfermos, limpiad leprosos, resucitad muertos, echad fuera demonios: de gracia recibisteis, dad de gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 9, 'No aprestéis oro, ni plata, ni cobre en vuestras bolsas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 10, 'Ni alforja para el camino, ni dos ropas de vestir, ni zapatos, ni bordón; porque el obrero digno es de su alimento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 11, 'Mas en cualquier ciudad, ó aldea donde entrareis, investigad quién sea en ella digno, y reposad allí hasta que salgáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 12, 'Y entrando en la casa, saludadla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 13, 'Y si la casa fuere digna, vuestra paz vendrá sobre ella; mas si no fuere digna, vuestra paz se volverá á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 14, 'Y cualquiera que no os recibiere, ni oyere vuestras palabras, salid de aquella casa ó ciudad, y sacudid el polvo de vuestros pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 15, 'De cierto os digo, que el castigo será más tolerable á la tierra de los de Sodoma y de los de Gomorra en el día del juicio, que á aquella ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 16, 'He aquí, yo os envío como á ovejas en medio de lobos: sed pues prudentes como serpientes, y sencillos como palomas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 17, 'Y guardaos de los hombres: porque os entregarán en concilios, y en sus sinagogas os azotarán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 18, 'Y aun á príncipes y á reyes seréis llevados por causa de mí, por testimonio á ellos y á los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 19, 'Mas cuando os entregaren, no os apuréis por cómo ó qué hablaréis; porque en aquella hora os será dado qué habéis de hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 20, 'Porque no sois vosotros los que habláis, sino el Espíritu de vuestro Padre que habla en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 21, 'Y el hermano entregará al hermano á la muerte, y el padre al hijo; y los hijos se levantarán contra los padres, y los harán morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 22, 'Y seréis aborrecidos de todos por mi nombre; mas el que soportare hasta el fin, éste será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 23, 'Mas cuando os persiguieren en esta ciudad, huid á la otra: porque de cierto os digo, que no acabaréis de andar todas las ciudades de Israel, que no venga el Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 24, 'El discípulo no es más que su maestro, ni el siervo más que su señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 25, 'Bástale al discípulo ser como su maestro, y al siervo como su señor. Si al padre de la familia llamaron Beelzebub, ¿cuánto más á los de su casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 26, 'Así que, no los temáis; porque nada hay encubierto, que no haya de ser manifestado; ni oculto, que no haya de saberse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 27, 'Lo que os digo en tinieblas, decidlo en la luz; y lo que oís al oído predicadlo desde los terrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 28, 'Y no temáis á los que matan el cuerpo, mas al alma no pueden matar: temed antes á aquel que puede destruir el alma y el cuerpo en el infierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 29, '¿No se venden dos pajarillos por un cuarto? Con todo, ni uno de ellos cae á tierra sin vuestro Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 30, 'Pues aun vuestros cabellos están todos contados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 31, 'Así que, no temáis: más valéis vosotros que muchos pajarillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 32, 'Cualquiera pues que me confesare delante de los hombres, le confesaré yo también delante de mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 33, 'Y cualquiera que me negare delante de los hombres, le negaré yo también delante de mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 34, 'No penséis que he venido para meter paz en la tierra: no he venido para meter paz, sino espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 35, 'Porque he venido para hacer disensión del hombre contra su padre, y de la hija contra su madre, y de la nuera contra su suegra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 36, 'Y los enemigos del hombre serán los de su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 37, 'El que ama padre ó madre más que á mí, no es digno de mí; y el que ama hijo ó hija más que á mí, no es digno de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 38, 'Y el que no toma su cruz, y sigue en pos de mí, no es digno de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 39, 'El que hallare su vida, la perderá; y el que perdiere su vida por causa de mí, la hallará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 40, 'El que os recibe á vosotros, á mí recibe; y el que á mí recibe, recibe al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 41, 'El que recibe profeta en nombre de profeta, merced de profeta recibirá; y el que recibe justo en nombre de justo, merced de justo recibirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 10, 42, 'Y cualquiera que diere á uno de estos pequeñitos un vaso de agua fría solamente, en nombre de discípulo, de cierto os digo, que no perderá su recompensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 1, 'Y FUÉ, que acabando Jesús de dar mandamientos á sus doce discípulos, se fué de allí á enseñar y á predicar en las ciudades de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 2, 'Y oyendo Juan en la prisión los hechos de Cristo, le envió dos de sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 3, 'Diciendo: ¿Eres tú aquél que había de venir, ó esperaremos á otro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 4, 'Y respondiendo Jesús, les dijo: Id, y haced saber á Juan las cosas que oís y veis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 5, 'Los ciegos ven, y los cojos andan; los leprosos son limpiados, y los sordos oyen; los muertos son resucitados, y á los pobres es anunciado el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 6, 'Y bienaventurado es el que no fuere escandalizado en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 7, 'E idos ellos, comenzó Jesús á decir de Juan á las gentes: ¿Qué salisteis á ver al desierto? ¿una caña que es meneada del viento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 8, 'Mas ¿qué salisteis á ver? ¿un hombre cubierto de delicados vestidos? He aquí, los que traen vestidos delicados, en las casas de los reyes están.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 9, 'Mas ¿qué salisteis á ver? ¿un profeta? También os digo, y más que profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 10, 'Porque éste es de quien está escrito: He aquí, yo envío mi mensajero delante de tu faz, Que aparejará tu camino delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 11, 'De cierto os digo, que no se levantó entre los que nacen de mujeres otro mayor que Juan el Bautista; mas el que es muy más pequeño en el reino de los cielos, mayor es que él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 12, 'Desde los días de Juan el Bautista hasta ahora, al reino de los cielos se hace fuerza, y los valientes lo arrebatan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 13, 'Porque todos los profetas y la ley hasta Juan profetizaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 14, 'Y si queréis recibir, él es aquel Elías que había de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 15, 'El que tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 16, 'Mas ¿á quién compararé esta generación? Es semejante á los muchachos que se sientan en las plazas, y dan voces á sus compañeros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 17, 'Y dicen: Os tañimos flauta, y no bailasteis; os endechamos, y no lamentasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 18, 'Porque vino Juan, que ni comía ni bebía, y dicen: Demonio tiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 19, 'Vino el Hijo del hombre, que come y bebe, y dicen: He aquí un hombre comilón, y bebedor de vino, amigo de publicanos y de pecadores. Mas la sabiduría es justificada por sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 20, 'Entonces comenzó á reconvenir á las ciudades en las cuales habían sido hechas muy muchas de sus maravillas, porque no se habían arrepentido, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 21, '¡Ay de ti, Corazín! ¡Ay de ti, Bethsaida! porque si en Tiro y en Sidón fueran hechas las maravillas que han sido hechas en vosotras, en otro tiempo se hubieran arrepentido en saco y en ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 22, 'Por tanto os digo, que á Tiro y á Sidón será más tolerable el castigo en el día del juicio, que á vosotras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 23, 'Y tú, Capernaum, que eres levantada hasta el cielo, hasta los infiernos serás abajada; porque si en los de Sodoma fueran hechas las maravillas que han sido hechas en ti, hubieran quedado hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 24, 'Por tanto os digo, que á la tierra de los de Sodoma será más tolerable el castigo en el día del juicio, que á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 25, 'En aquel tiempo, respondiendo Jesús, dijo: Te alabo, Padre, Señor del cielo y de la tierra, que hayas escondido estas cosas de los sabios y de los entendidos, y las hayas revelado á los niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 26, 'Así, Padre, pues que así agradó en tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 27, 'Todas las cosas me son entregadas de mi Padre: y nadie conoció al Hijo, sino el Padre; ni al Padre conoció alguno, sino el Hijo, y aquel á quien el Hijo lo quisiere revelar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 28, 'Venid á mí todos los que estáis trabajados y cargados, que yo os haré descansar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 29, 'Llevad mi yugo sobre vosotros, y aprended de mí, que soy manso y humilde de corazón; y hallaréis descanso para vuestras almas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 11, 30, 'Porque mi yugo es fácil, y ligera mi carga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 1, 'EN aquel tiempo iba Jesús por los sembrados en sábado; y sus discípulos tenían hambre, y comenzaron á coger espigas, y á comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 2, 'Y viéndolo los Fariseos, le dijeron: He aquí tus discípulos hacen lo que no es lícito hacer es sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 3, 'Y él les dijo: ¿No habéis leído qué hizo David, teniendo él hambre y los que con él estaban:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 4, 'Cómo entró en la casa de Dios, y comió los panes de la proposición, que no le era lícito comer, ni á los que estaban con él, sino á solos los sacerdotes¿');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 5, 'O ¿no habéis leído en la ley, que los sábados en el templo los sacerdotes profanan el sábado, y son sin culpa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 6, 'Pues os digo que uno mayor que el templo está aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 7, 'Mas si supieseis qué es: Misericordia quiero y no sacrificio, no condenarías á los inocentes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 8, 'Porque Señor es del sábado el Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 9, 'Y partiéndose de allí, vino á la sinagoga de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 10, 'Y he aquí había allí uno que tenía una mano seca: y le preguntaron, diciendo: ¿Es lícito curar en sábado? por acusarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 11, 'Y él les dijo: ¿Qué hombre habrá de vosotros, que tenga una oveja, y si cayere ésta en una fosa en sábado, no le eche mano, y la levante?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 12, 'Pues ¿cuánto más vale un hombre que una oveja? Así que, lícito es en los sábados hacer bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 13, 'Entonces dijo á aquel hombre: Extiende tu mano. Y él la extendió, y fué restituída sana como la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 14, 'Y salidos los Fariseos, consultaron contra él para destruirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 15, 'Mas sabiendo lo Jesús, se apartó de allí: y le siguieron muchas gentes, y sanaba á todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 16, 'Y él les encargaba eficazmente que no le descubriesen:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 17, 'Para que se cumpliese lo que estaba dicho por el profeta Isaías, que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 18, 'He aquí mi siervo, al cual he escogido; Mi Amado, en el cual se agrada mi alma: Pondré mi Espíritu sobre él Y á los Gentiles anunciará juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 19, 'No contenderá, ni voceará: Ni nadie oirá en las calles su voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 20, 'La caña cascada no quebrará, Y el pábilo que humea no apagará, Hasta que saque á victoria el juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 21, 'Y en su nombre esperarán los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 22, 'Entonces fué traído á él un endemoniado, ciego y mudo, y le sanó; de tal manera, que el ciego y mudo hablaba y veía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 23, 'Y todas las gentes estaban atónitas, y decían: ¿Será éste aquel Hijo de David?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 24, 'Mas los Fariseos, oyéndolo, decían: Este no echa fuera los demonios, sino por Beelzebub, príncipe de los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 25, 'Y Jesús, como sabía los pensamientos de ellos, les dijo: Todo reino dividido contra sí mismo, es desolado; y toda ciudad ó casa dividida contra sí misma, no permanecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 26, 'Y si Satanás echa fuera á Satanás, contra sí mismo está dividido; ¿cómo, pues, permanecerá su reino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 27, 'Y si yo por Beelzebub echo fuera los demonios, ¿vuestros hijos por quién los echan? Por tanto, ellos serán vuestros jueces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 28, 'Y si por espíritu de Dios yo echo fuera los demonios, ciertamente ha llegado á vosotros el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 29, 'Porque, ¿cómo puede alguno entrar en la casa del valiente, y saquear sus alhajas, si primero no prendiere al valiente? y entonces saqueará su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 30, 'El que no es conmigo, contra mí es; y el que conmigo no recoge, derrama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 31, 'Por tanto os digo: Todo pecado y blasfemia será perdonado á los hombres: mas la blasfemia contra el Espíritu no será perdonada á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 32, 'Y cualquiera que hablare contra el Hijo del hombre, le será perdonado: mas cualquiera que hablare contra el Espíritu Santo, no le será perdonado, ni en este siglo, ni en el venidero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 33, 'O haced el árbol bueno, y su fruto bueno, ó haced el árbol corrompido, y su fruto dañado; porque por el fruto es conocido el árbol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 34, 'Generación de víboras, ¿cómo podéis hablar bien, siendo malos? porque de la abundancia del corazón habla la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 35, 'El hombre bueno del buen tesoro del corazón saca buenas cosas: y el hombre malo del mal tesoro saca malas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 36, 'Mas yo os digo, que toda palabra ociosa que hablaren los hombres, de ella darán cuenta en el día del juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 37, 'Porque por tus palabras serás justificado, y por tus palabras serás condenado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 38, 'Entonces respondiendo algunos de los escribas y de los Fariseos, diciendo: Maestro, deseamos ver de ti señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 39, 'Y él respondió, y les dijo: La generación mala y adulterina demanda señal; mas señal no le será dada, sino la señal de Jonás profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 40, 'Porque como estuvo Jonás en el vientre de la ballena tres días y tres noches, así estará el Hijo del hombre en el corazón de la tierra tres días y tres noches.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 41, 'Los hombres de Nínive se levantarán en el juicio con esta generación, y la condenarán; porque ellos se arrepintieron á la predicación de Jonás; y he aquí más que Jonás en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 42, 'La reina del Austro se levantará en el juicio con esta generación, y la condenará; porque vino de los fines de la tierra para oir la sabiduría de Salomón: y he aquí más que Salomón en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 43, 'Cuando el espíritu inmundo ha salido del hombre, anda por lugares secos, buscando reposo, y no lo halla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 44, 'Entonces dice: Me volvere á mi casa de donde salí: y cuando viene, la halla desocupada, barrida y adornada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 45, 'Entonces va, y toma consigo otros siete espíritus peores que él, y entrados, moran allí; y son peores las cosas; últimas del tal hombre que las primeras: así también acontecerá á esta generación mala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 46, 'Y estando él aún hablando á las gentes, he aquí su madre y sus hermanos estaban fuera, que le querían hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 47, 'Y le dijo uno: He aquí tu madre y tus hermanos están fuera, que te quieren hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 48, 'Y respondiendo él al que le decía esto, dijo: ¿Quién es mi madre y quiénes son mis hermanos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 49, 'Y extendiendo su mano hacia sus discípulos, dijo: He aquí mi madre y mis hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 12, 50, 'Porque todo aquel que hiciere la voluntad de mi Padre que está en los cielos, ese es mi hermano, y hermana, y madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 1, 'Y AQUEL día, saliendo Jesús de casa, se sentó junto á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 2, 'Y se allegaron á él muchas gentes; y entrándose él en el barco, se sentó, y toda la gente estaba á la ribera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 3, 'Y les habló muchas cosas por parábolas, diciendo: He aquí el que sembraba salió á sembrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 4, 'Y sembrando, parte de la simiente cayó junto al camino; y vinieron las aves, y la comieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 5, 'Y parte cayó en pedregales, donde no tenía mucha tierra; y nació luego, porque no tenía profundidad de tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 6, 'Mas en saliendo el sol, se quemó; y secóse, porque no tenía raíz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 7, 'Y parte cayó en espinas; y las espinas crecieron, y la ahogaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 8, 'Y parte cayó en buena tierra, y dió fruto, cuál a ciento, cuál á sesenta, y cuál á treinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 9, 'Quien tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 10, 'Entonces, llegándose los discípulos, le dijeron: ¿Por qué les hablas por parábolas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 11, 'Y él respondiendo, les dijo: Por que á vosotros es concedido saber los misterios del reino de los cielos; mas á ellos no es concedido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 12, 'Porque á cualquiera que tiene, se le dará, y tendrá más; pero al que no tiene, aun lo que tiene le será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 13, 'Por eso les hablo por parábolas; porque viendo no ven, y oyendo no oyen, ni entienden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 14, 'De manera que se cumple en ellos la profecía de Isaías, que dice: De oído oiréis, y no entenderéis; Y viendo veréis, y no miraréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 15, 'Porque el corazón de este pueblo está engrosado, Y de los oídos oyen pesadamente, Y de sus ojos guiñan: Para que no vean de los ojos, Y oigan de los oídos, Y del corazón entiendan, Y se conviertan, Y yo los sane.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 16, 'Mas bienaventurados vuestros ojos, porque ven; y vuestros oídos, porque oyen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 17, 'Porque de cierto os digo, que muchos profetas y justos desearon ver lo que veis, y no lo vieron: y oir lo que oís, y no lo oyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 18, 'Oid, pues, vosotros la parábola del que siembra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 19, 'Oyendo cualquiera la palabra del reino, y no entendiéndola, viene el malo, y arrebata lo que fué sembrado en su corazón: éste es el que fué sembrado junto al camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 20, 'Y el que fué sembrado en pedregales, éste es el que oye la palabra, y luego la recibe con gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 21, 'Mas no tiene raíz en sí, antes es temporal que venida la aflicción ó la persecución por la palabra, luego se ofende.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 22, 'Y el que fué sembrado en espinas, éste es el que oye la palabra; pero el afán de este siglo y el engaño de las riquezas, ahogan la palabra, y hácese infructuosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 23, 'Mas el que fué sembrado en buena tierra, éste es el que oye y entiende la palabra, y el que lleva fruto: y lleva uno á ciento, y otro á sesenta, y otro á treinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 24, 'Otra parábola les propuso, diciendo: El reino de los cielos es semejante al hombre que siembra buena simiente en su campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 25, 'Mas durmiendo los hombres, vino su enemigo, y sembró cizaña entre el trigo, y se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 26, 'Y como la hierba salió é hizo fruto, entonces apareció también la cizaña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 27, 'Y llegándose los siervos del padre de la familia, le dijeron: Señor, ¿no sembraste buena simiente en tu campo? ¿de dónde, pues, tiene cizaña?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 28, 'Y él les dijo: Un hombre enemigo ha hecho esto. Y los siervos le dijeron: ¿Quieres, pues, que vayamos y la cojamos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 29, 'Y él dijo: No; porque cogiendo la cizaña, no arranquéis también con ella el trigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 30, 'Dejad crecer juntamente lo uno y lo otro hasta la siega; y al tiempo de la siega yo diré á los segadores: Coged primero la cizaña, y atadla en manojos para quemarla; mas recoged el trigo en mi alfolí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 31, 'Otra parábola les propuso, diciendo: El reino de los cielos es semejante al grano de mostaza, que tomándolo alguno lo sembró en su campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 32, 'El cual á la verdad es la más pequeña de todas las simientes; mas cuando ha crecido, es la mayor de las hortalizas, y se hace árbol, que vienen las aves del cielo y hacen nidos en sus ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 33, 'Otra parábola les dijo: El reino de los cielos es semejante á la levadura que tomó una mujer, y escondió en tres medidas de harina, hasta que todo quedó leudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 34, 'Todo esto habló Jesús por parábolas á las gentes, y sin parábolas no les hablaba:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 35, 'Para que se cumpliese lo que fué dicho por el profeta, que dijo: Abriré en parábolas mi boca; Rebosaré cosas escondidas desde la fundación del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 36, 'Entonces, despedidas las gentes, Jesús se vino á casa; y llegándose á él sus discípulos, le dijeron: Decláranos la parábola de la cizaña del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 37, 'Y respondiendo él, les dijo: El que siembra la buena simiente es el Hijo del hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 38, 'Y el campo es el mundo; y la buena simiente son los hijos del reino, y la cizaña son los hijos del malo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 39, 'Y el enemigo que la sembró, es el diablo; y la siega es el fin del mundo, y los segadores son los ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 40, 'De manera que como es cogida la cizaña, y quemada al fuego, así será en el fin de este siglo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 41, 'Enviará el Hijo del hombre sus ángeles, y cogerán de su reino todos los escándalos, y los que hacen iniquidad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 42, 'Y los echarán en el horno de fuego: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 43, 'Entonces los justos resplandecerán como el sol en el reino de su Padre: el que tiene oídos para oir, oiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 44, 'Además, el reino de los cielos es semejante al tesoro escondido en el campo; el cual hallado, el hombre lo encubre, y de gozo de ello va, y vende todo lo que tiene, y compra aquel campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 45, 'También el reino de los cielos es semejante al hombre tratante, que busca buenas perlas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 46, 'Que hallando una preciosa perla, fué y vendió todo lo que tenía, y la compró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 47, 'Asimismo el reino de los cielos es semejante á la red, que echada en la mar, coge de todas suertes de peces:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 48, 'La cual estando llena, la sacaron á la orilla; y sentados, cogieron lo bueno en vasos, y lo malo echaron fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 49, 'Así será al fin del siglo: saldrán los ángeles, y apartarán á los malos de entre los justos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 50, 'Y los echarán en el horno del fuego: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 51, 'Díceles Jesús: ¿Habéis entendido todas estas cosas? Ellos responden: Sí, Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 52, 'Y él les dijo: Por eso todo escriba docto en el reino de los cielos, es semejante á un padre de familia, que saca de su tesoro cosas nuevas y cosas viejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 53, 'Y aconteció que acabando Jesús estas parábolas, pasó de allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 54, 'Y venido á su tierra, les enseñaba en la sinagoga de ellos, de tal manera que ellos estaban atónitos, y decían: ¿De dónde tiene éste esta sabiduría, y estas maravillas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 55, '¿No es éste el hijo del carpintero? ¿no se llama su madre María, y sus hermanos Jacobo y José, y Simón, y Judas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 56, '¿Y no están todas sus hermanas con nosotros? ¿De dónde, pues, tiene éste todas estas cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 57, 'Y se escandalizaban en él. Mas Jesús les dijo: No hay profeta sin honra sino en su tierra y en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 13, 58, 'Y no hizo allí muchas maravillas, á causa de la incredulidad de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 1, 'EN aquel tiempo Herodes el tetrarca oyó la fama de Jesús,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 2, 'Y dijo á sus criados: Este es Juan el Bautista: él ha resucitado de los muertos, y por eso virtudes obran en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 3, 'Porque Herodes había prendido á Juan, y le había aprisionado y puesto en la cárcel, por causa de Herodías, mujer de Felipe su hermano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 4, 'Porque Juan le decía: No te es lícito tenerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 5, 'Y quería matarle, mas temía al pueblo; porque le tenían como á profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 6, 'Mas celebrándose el día del nacimiento de Herodes, la hija de Herodías danzó en medio, y agradó á Herodes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 7, 'Y prometió él con juramento de darle todo lo que pidiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 8, 'Y ella, instruída primero de su madre, dijo: Dame aquí en un plato la cabeza de Juan el Bautista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 9, 'Entonces el rey se entristeció; mas por el juramento, y por los que estaban juntamente á la mesa, mandó que se le diese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 10, 'Y enviando, degolló á Juan en la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 11, 'Y fué traída su cabeza en un plato y dada á la muchacha; y ella la presentó á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 12, 'Entonces llegaron sus discípulos, y tomaron el cuerpo, y lo enterraron; y fueron, y dieron las nuevas á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 13, 'Y oyéndo lo Jesús, se apartó de allí en un barco á un lugar descierto, apartado: y cuando las gentes lo oyeron, le siguieron á pie de las ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 14, 'Y saliendo Jesús, vió un gran gentío, y tuvo compasión de ellos, y sanó á los que de ellos había enfermos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 15, 'Y cuando fué la tarde del día, se llegaron á él sus discípulos, diciendo: El lugar es desierto, y el tiempo es ya pasado: despide las gentes, para que se vayan por las aldeas, y compren para sí de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 16, 'Y Jesús les dijo: No tienen necesidad de irse: dadles vosotros de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 17, 'Y ellos dijeron: No tenemos aquí sino cinco panes y dos peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 18, 'Y él les dijo: Traédmelos acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 19, 'Y mandando á las gentes recostarse sobre la hierba, tomando los cinco panes y los dos peces, alzando los ojos al cielo, bendijo, y partió y dió los panes á los discípulos, y los discípulos á las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 20, 'Y comieron todos, y se hartaron; y alzaron lo que sobró de los pedazos, doce cestas llenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 21, 'Y los que comieron fueron como cinco mil hombres, sin las mujeres y los niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 22, 'Y luego Jesús hizo á sus discípulos entrar en el barco, é ir delante de él á la otra parte del lago, entre tanto que él despedía á las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 23, 'Y despedidas las gentes, subió al monte, apartado, á orar: y como fué la tarde del día, estaba allí solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 24, 'Y ya el barco estaba en medio de la mar, atormentado de las ondas; porque el viento era contrario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 25, 'Mas á la cuarta vela de la noche, Jesús fué á ellos andando sobre la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 26, 'Y los discípulos, viéndole andar sobre la mar, se turbaron, diciendo: Fantasma es. Y dieron voces de miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 27, 'Mas luego Jesús les habló, diciendo: Confiad, yo soy; no tengáis miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 28, 'Entonces le respondió Pedro, y dijo: Señor, si tú eres, manda que yo vaya á ti sobre las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 29, 'Y él dijo: Ven. Y descendiendo Pedro del barco, andaba sobre las aguas para ir á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 30, 'Mas viendo el viento fuerte, tuvo miedo; y comenzándose á hundir, dió voces, diciendo: Señor, sálvame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 31, 'Y luego Jesús, extendiendo la mano, trabó de él, y le dice: Oh hombre de poca fe, ¿por qué dudaste?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 32, 'Y como ellos entraron en el barco, sosegóse el viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 33, 'Entonces los que estaban en el barco, vinieron y le adoraron, diciendo: Verdaderamente eres Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 34, 'Y llegando á la otra parte, vinieron á la tierra de Genezaret.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 35, 'Y como le conocieron los hombres de aquel lugar, enviaron por toda aquella tierra alrededor, y trajeron á él todos los enfermos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 14, 36, 'Y le rogaban que solamente tocasen el borde de su manto; y todos los que tocaron, quedaron sanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 1, 'ENTONCES llegaron á Jesús ciertos escribas y Fariseos de Jerusalem, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 2, '¿Por qué tus discípulos traspasan la tradición de los ancianos? porque no se lavan las manos cuando comen pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 3, 'Y él respondiendo, les dijo: ¿Por qué también vosotros traspasáis el mandamiento de Dios por vuestra tradición?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 4, 'Porque Dios mandó, diciendo: Honra al padre y á la madre, y, El que maldijere al padre ó á la madre, muera de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 5, 'Mas vosotros decís: Cualquiera que dijere al padre ó á la madre: Es ya ofrenda mía á Dios todo aquello con que pudiera valerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 6, 'No deberá honrar á su padre ó á su madre con socorro. Así habéis invalidado el mandamiento de Dios por vuestra tradición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 7, 'Hipócritas, bien profetizó de vosotros Isaías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 8, 'Este pueblo de labios me honra; Mas su corazón lejos está de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 9, 'Mas en vano me honran, Enseñando doctrinas y mandamientos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 10, 'Y llamando á sí las gentes, les dijo: Oid, y entended:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 11, 'No lo que entra en la boca contamina al hombre; mas lo que sale de la boca, esto contamina al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 12, 'Entonces llegándose sus discípulos, le dijeron: ¿Sabes que los Fariseos oyendo esta palabra se ofendieron?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 13, 'Mas respondiendo él, dijo: Toda planta que no plantó mi Padre celestial, será desarraigada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 14, 'Dejadlos: son ciegos guías de ciegos; y si el ciego guiare al ciego, ambos caerán en el hoyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 15, 'Y respondiendo Pedro, le dijo: Decláranos esta parábola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 16, 'Y Jesús dijo: ¿Aun también vosotros sois sin entendimiento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 17, '¿No entendéis aún, que todo lo que entra en la boca, va al vientre, y es echado en la letrina?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 18, 'Mas lo que sale de la boca, del corazón sale; y esto contamina al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 19, 'Porque del corazón salen los malos pensamientos, muertes, adulterios, fornicaciones, hurtos, falsos testimonios, blasfemias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 20, 'Estas cosas son las que contaminan al hombre: que comer con las manos por lavar no contamina al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 21, 'Y saliendo Jesús de allí, se fué á las partes de Tiro y de Sidón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 22, 'Y he aquí una mujer Cananea, que había salido de aquellos términos, clamaba, diciéndole: Señor, Hijo de David, ten misericordia de mí; mi hija es malamente atormentada del demonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 23, 'Mas él no le respondió palabra. Entonces llegándose sus discípulos, le rogaron, diciendo: Despáchala, pues da voces tras nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 24, 'Y él respondiendo, dijo: No soy enviado sino á las ovejas perdidas de la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 25, 'Entonces ella vino, y le adoró, diciendo: Señor socórreme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 26, 'Y respondiendo él, dijo: No es bien tomar el pan de los hijos, y echarlo á los perrillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 27, 'Y ella dijo: Sí, Señor; mas los perrillos comen de las migajas que caen de la mesa de sus señores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 28, 'Entonces respondiendo Jesús, dijo: Oh mujer, grande es tu fe; sea hecho contigo como quieres. Y fué sana su hija desde aquella hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 29, 'Y partido Jesús de allí, vino junto al mar de Galilea: y subiendo al monte, se sentó allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 30, 'Y llegaron á él muchas gentes, que tenían consigo cojos, ciegos, mudos, mancos, y otros muchos enfermos: y los echaron á los pies de Jesús, y los sanó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 31, 'De manera que se maravillaban las gentes, viendo hablar los mudos, los mancos sanos, andar los cojos, y ver los ciegos: y glorificaron al Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 32, 'Y Jesús llamando á sus discípulos, dijo: Tengo lástima de la gente, que ya hace tres días que perseveran conmigo, y no tienen qué comer; y enviarlos ayunos no quiero, porque no desmayen en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 33, 'Entonces sus discípulos le dicen: ¿Dónde tenemos nosotros tantos panes en el desierto, que hartemos á tan gran compañía?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 34, 'Y Jesús les dice: ¿Cuántos panes tenéis? Y ellos dijeron: Siete, y unos pocos pececillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 35, 'Y mandó á las gentes que se recostasen sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 36, 'Y tomando los siete panes y los peces, haciendo gracias, partió y dió á sus discípulos; y los discípulos á la gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 37, 'Y comieron todos, y se hartaron: y alzaron lo que sobró de los pedazos, siete espuertas llenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 38, 'Y eran los que habían comido, cuatro mil hombres, sin las mujeres y los niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 15, 39, 'Entonces, despedidas las gentes, subió en el barco: y vino á los términos de Magdalá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 1, 'Y LLEGANDOSE los Fariseos y los Saduceos para tentarle, le pedían que les mostrase señal del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 2, 'Mas él respondiendo, les dijo: Cuando es la tarde del día, decís: Sereno; porque el cielo tiene arreboles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 3, 'Y á la mañana: Hoy tempestad; porque tiene arreboles el cielo triste. Hipócritas, que sabéis hacer diferencia en la faz del cielo; ¿y en las señales de los tiempos no podéis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 4, 'La generación mala y adulterina demanda señal; mas señal no le será dada, sino la señal de Jonás profeta. Y dejándolos, se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 5, 'Y viniendo sus discípulos de la otra parte del lago, se habían olvidado de tomar pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 6, 'Y Jesús les dijo: Mirad, y guardaos de la levadura de los Fariseos y de los Saduceos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 7, 'Y ellos pensaban dentro de sí, diciendo: Esto dice porque no tomamos pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 8, 'Y entendiéndolo Jesús, les dijo: ¿Por qué pensáis dentro de vosotros, hombres de poca fe, que no tomasteis pan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 9, '¿No entendéis aún, ni os acordáis de los cinco panes entre cinco mil hombres, y cuántos cestos alzasteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 10, '¿Ni de los siete panes entre cuatro mil, y cuántas espuertas tomasteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 11, '¿Cómo es que no entendéis que no por el pan os dije, que os guardaseis de la levadura de los Fariseos y de los Saduceos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 12, 'Entonces entendieron que no les había dicho que se guardasen de la levadura de pan, sino de la doctrina de los Fariseos y de los Saduceos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 13, 'Y viniendo Jesús á las partes de Cesarea de Filipo, preguntó á sus discípulos, diciendo: ¿Quién dicen los hombres que es el Hijo del hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 14, 'Y ellos dijeron: Unos, Juan el Bautista; y otros, Elías; y otros; Jeremías, ó alguno de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 15, 'El les dice: Y vosotros, ¿quién decís que soy?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 16, 'Y respondiendo Simón Pedro, dijo: Tú eres el Cristo, el Hijo del Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 17, 'Entonces, respondiendo Jesús, le dijo: Bienaventurado eres, Simón, hijo de Jonás; porque no te lo reveló carne ni sangre, mas mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 18, 'Mas yo también te digo, que tú eres Pedro, y sobre esta piedra edificaré mi iglesia; y las puertas del infierno no prevalecerán contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 19, 'Y á ti daré las llaves del reino de los cielos; y todo lo que ligares en la tierra será ligado en los cielos; y todo lo que desatares en la tierra será desatado en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 20, 'Entonces mandó á sus discípulos que á nadie dijesen que él era Jesús el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 21, 'Desde aquel tiempo comenzó Jesús á declarar á sus discípulos que le convenía ir á Jerusalem, y padecer mucho de los ancianos, y de los príncipes de los sacerdotes, y de los escribas; y ser muerto, y resucitar al tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 22, 'Y Pedro, tomándolo aparte, comenzó á reprenderle, diciendo: Señor, ten compasión de ti: en ninguna manera esto te acontezca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 23, 'Entonces él, volviéndose, dijo á Pedro: Quítate de delante de mí, Satanás; me eres escándalo; porque no entiendes lo que es de Dios sino lo que es de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 24, 'Entonces Jesús dijo á sus discípulos: Si alguno quiere venir en pos de mí, niéguese á sí mismo, y tome su cruz, y sígame.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 25, 'Porque cualquiera que quisiere salvar su vida, la perderá, y cualquiera que perdiere su vida por causa de mí, la hallará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 26, 'Porque ¿de qué aprovecha al hombre, si granjeare todo el mundo, y perdiere su alma? O ¿qué recompensa dará el hombre por su alma?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 27, 'Porque el Hijo del hombre vendrá en la gloria de su Padre con sus ángeles, y entonces pagará á cada uno conforme á sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 16, 28, 'De cierto os digo: hay algunos de los que están aquí, que no gustarán la muerte, hasta que hayan visto al Hijo del hombre viniendo en su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 1, 'Y DESPUÉS de seis días, Jesús toma á Pedro, y á Jacobo, y á Juan su hermano, y los lleva aparte á un monte alto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 2, 'Y se transfiguró delante de ellos; y resplandeció su rostro como el sol, y sus vestidos fueron blancos como la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 3, 'Y he aquí les aparecieron Moisés y Elías, hablando con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 4, 'Y respondiendo Pedro, dijo á Jesús: Señor, bien es que nos quedemos aquí: si quieres, hagamos aquí tres pabellones: para ti uno, y para Moisés otro, y otro para Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 5, 'Y estando aún él hablando, he aquí una nube de luz que los cubrió; y he aquí una voz de la nube, que dijo: Este es mi Hijo amado, en el cual tomo contentamiento: á él oíd.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 6, 'Y oyendo esto los discípulos, cayeron sobre sus rostros, y temieron en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 7, 'Entonces Jesús llegando, los tocó, y dijo: Levantaos, y no temáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 8, 'Y alzando ellos sus ojos, á nadie vieron, sino á solo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 9, 'Y como descendieron del monte, les mandó Jesús, diciendo: No digáis á nadie la visión, hasta que el Hijo del hombre resucite de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 10, 'Entonces sus discípulos le preguntaron, diciendo: ¿Por qué dicen pues los escribas que es menester que Elías venga primero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 11, 'Y respondiendo Jesús, les dijo: á la verdad, Elías vendrá primero, y restituirá todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 12, 'Mas os digo, que ya vino Elías, y no le conocieron; antes hicieron en él todo lo que quisieron: así también el Hijo del hombre padecerá de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 13, 'Los discípulos entonces entendieron, que les habló de Juan el Bautista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 14, 'Y como ellos llegaron al gentío, vino á él un hombre hincándosele de rodillas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 15, 'Y diciendo: Señor, ten misericordia de mi hijo, que es lunático, y padece malamente; porque muchas veces cae en el fuego, y muchas en el agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 16, 'Y le he presentado á tus discípulos, y no le han podido sanar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 17, 'Y respondiendo Jesús, dijo: ¡Oh generación infiel y torcida! ¿hasta cuándo tengo de estar con vosotros? ¿hasta cuándo os tengo de sufrir? traédmele acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 18, 'Y Jesús le reprendió, y salió el demonio de él; y el mozo fué sano desde aquella hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 19, 'Entonces, llegándose los discípulos á Jesús, aparte, dijeron: ¿Por qué nosotros no lo pudimos echar fuera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 20, 'Y Jesús les dijo: Por vuestra incredulidad; porque de cierto os digo, que si tuviereis fe como un grano de mostaza, diréis á este monte: Pásate de aquí allá: y se pasará: y nada os será imposible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 21, 'Mas este linaje no sale sino por oración y ayuno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 22, 'Y estando ellos en Galilea, Jesús les dijo: El Hijo del hombre será entregado en manos de hombres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 23, 'Y le matarán; mas al tercer día resucitará. Y ellos se entristecieron en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 24, 'Y como llegaron á Capernaum, vinieron á Pedro los que cobraban las dos dracmas, y dijeron: ¿Vuestro Maestro no paga las dos dracmas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 25, 'El dice: Sí. Y entrando él en casa, Jesús le habló antes, diciendo: ¿Qué te parece, Simón? Los reyes de la tierra, ¿de quién cobran los tributos ó el censo? ¿de sus hijos ó de los extraños?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 26, 'Pedro le dice: De los extraños. Jesús le dijo: Luego los hijos son francos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 17, 27, 'Mas porque no los escandalicemos, ve á la mar, y echa el anzuelo, y el primer pez que viniere, tómalo, y abierta su boca, hallarás un estatero: tómalo, y dáselo por mí y por ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 1, 'EN aquel tiempo se llegaron los discípulos á Jesús, diciendo: ¿Quién es el mayor en el reino de los cielos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 2, 'Y llamando Jesús á un niño, le puso en medio de ellos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 3, 'Y dijo: De cierto os digo, que si no os volviereis, y fuereis como niños, no entraréis en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 4, 'Así que, cualquiera que se humillare como este niño, éste es el mayor en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 5, 'Y cualquiera que recibiere á un tal niño en mi nombre, á mí recibe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 6, 'Y cualquiera que escandalizare á alguno de estos pequeños que creen en mí, mejor le fuera que se le colgase al cuello una piedra de molino de asno, y que se le anegase en el profundo de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 7, '¡Ay del mundo por los escándalos! porque necesario es que vengan escándalos; mas ¡ay de aquel hombre por el cual viene el escándalo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 8, 'Por tanto, si tu mano ó tu pie te fuere ocasión de caer, córtalo y echaló de ti: mejor te es entrar cojo ó manco en la vida, que teniendo dos manos ó dos pies ser echado en el fuego eterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 9, 'Y si tu ojo te fuere ocasión de caer, sácalo y échalo de ti: mejor te es entrar con un solo ojo en la vida, que teniendo dos ojos ser echado en el infierno del fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 10, 'Mirad no tengáis en poco á alguno de estos pequeños; porque os digo que sus ángeles en los cielos ven siempre la faz de mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 11, 'Porque el Hijo del hombre ha venido para salvar lo que se había perdido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 12, '¿Qué os parece? Si tuviese algún hombre cien ovejas, y se descarriase una de ellas, ¿no iría por los montes, dejadas las noventa y nueve, á buscar la que se había descarriado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 13, 'Y si aconteciese hallarla, de cierto os digo, que más se goza de aquélla, que de las noventa y nueve que no se descarriaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 14, 'Así, no es la voluntad de vuestro Padre que está en los cielos, que se pierda uno de estos pequeños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 15, 'Por tanto, si tu hermano pecare contra ti, ve, y redargúyele entre ti y él solo: si te oyere, has ganado á tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 16, 'Mas si no te oyere, toma aún contigo uno ó dos, para que en boca de dos ó de tres testigos conste toda palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 17, 'Y si no oyere á ellos, dilo á la iglesia: y si no oyere á la iglesia, tenle por étnico y publicano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 18, 'De cierto os digo que todo lo que ligareis en la tierra, será ligado en el cielo; y todo lo que desatareis en la tierra, será desatado en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 19, 'Otra vez os digo, que si dos de vosotros se convinieren en la tierra, de toda cosa que pidieren, les será hecho por mi Padre que está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 20, 'Porque donde están dos ó tres congregados en mi nombre, allí estoy en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 21, 'Entonces Pedro, llegándose á él, dijo: Señor, ¿cuántas veces perdonaré á mi hermano que pecare contra mí? ¿hasta siete?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 22, 'Jesús le dice: No te digo hasta siete, mas aun hasta setenta veces siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 23, 'Por lo cual, el reino de los cielos es semejante á un hombre rey, que quiso hacer cuentas con sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 24, 'Y comenzando á hacer cuentas, le fué presentado uno que le debía diez mil talentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 25, 'Mas á éste, no pudiendo pagar, mandó su señor venderle, y á su mujer é hijos, con todo lo que tenía, y que se le pagase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 26, 'Entonces aquel siervo, postrado, le adoraba, diciendo: Señor, ten paciencia conmigo, y yo te lo pagaré todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 27, 'El señor, movido á misericordia de aquel siervo, le soltó y le perdonó la deuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 28, 'Y saliendo aquel siervo, halló á uno de sus consiervos, que le debía cien denarios; y trabando de él, le ahogaba, diciendo: Págame lo que debes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 29, 'Entonces su consiervo, postrándose á sus pies, le rogaba, diciendo: Ten paciencia conmigo, y yo te lo pagaré todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 30, 'Mas él no quiso; sino fué, y le echó en la cárcel hasta que pagase la deuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 31, 'Y viendo sus consiervos lo que pasaba, se entristecieron mucho, y viniendo, declararon á su señor todo lo que había pasado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 32, 'Entonces llamándole su señor, le dice: Siervo malvado, toda aquella deuda te perdoné, porque me rogaste:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 33, '¿No te convenía también á ti tener misericordia de tu consiervo, como también yo tuve misericordia de ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 34, 'Entonces su señor, enojado, le entregó á los verdugos, hasta que pagase todo lo que le debía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 18, 35, 'Así también hará con vosotros mi Padre celestial, si no perdonareis de vuestros corazones cada uno á su hermano sus ofensas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 1, 'Y ACONTECIO que acabando Jesús estas palabras, se pasó de Galilea, y vino á los términos de Judea, pasado el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 2, 'Y le siguieron muchas gentes, y los sanó allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 3, 'Entonces se llegaron á él los Fariseos, tentándole, y diciéndole: ¿Es lícito al hombre repudiar á su mujer por cualquiera causa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 4, 'Y él respondiendo, les dijo: ¿No habéis leído que el que los hizo al principio, macho y hembra los hizo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 5, 'Y dijo: Por tanto, el hombre dejará padre y madre, y se unirá á su mujer, y serán dos en una carne?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 6, 'Así que, no son ya más dos, sino una carne: por tanto, lo que Dios juntó, no lo aparte el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 7, 'Dícenle: ¿Por qué, pues, Moisés mandó dar carta de divorcio, y repudiarla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 8, 'Díceles: Por la dureza de vuestro corazón Moisés os permitió repudiar á vuestras mujeres: mas al principio no fué así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 9, 'Y yo os digo que cualquiera que repudiare á su mujer, si no fuere por causa de fornicación, y se casare con otra, adultera: y el que se casare con la repudiada, adultera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 10, 'Dícenle sus discípulos: Si así es la condición del hombre con su mujer, no conviene casarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 11, 'Entonces él les dijo: No todos reciben esta palabra, sino aquellos á quienes es dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 12, 'Porque hay eunucos que nacieron así del vientre de su madre; y hay eunucos, que son hechos eunucos por los hombres; y hay eunucos que se hicieron á sí mismos eunucos por causa del reino de los cielos; el que pueda ser capaz de eso, séalo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 13, 'Entonces le fueron presentados unos niños, para que pusiese las manos sobre ellos, y orase; y los discípulos les riñeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 14, 'Y Jesús dijo: Dejad á los niños, y no les impidáis de venir á mí; porque de los tales es el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 15, 'Y habiendo puesto sobre ellos las manos se partió de allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 16, 'Y he aquí, uno llegándose le dijo: Maestro bueno, ¿qué bien haré para tener la vida eterna?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 17, 'Y él le dijo: ¿Por qué me llamas bueno? Ninguno es bueno sino uno, es á saber, Dios: y si quieres entrar en la vida, guarda los mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 18, 'Dícele: ¿Cuáles? Y Jesús dijo: No mataras: No adulterarás: No hurtarás: No dirás falso testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 19, 'Honra á tu padre y á tu madre: y, Amarás á tu prójimo como á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 20, 'Dícele el mancebo: Todo esto guardé desde mi juventud: ¿qué más me falta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 21, 'Dícele Jesús: Si quieres ser perfecto, anda, vende lo que tienes, y da lo á los pobres, y tendrás tesoro en el cielo; y ven, sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 22, 'Y oyendo el mancebo esta palabra, se fué triste, porque tenía muchas posesiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 23, 'Entonces Jesús dijo á sus discípulos: De cierto os digo, que un rico difícilmente entrará en el reino de los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 24, 'Mas os digo, que más liviano trabajo es pasar un camello por el ojo de una aguja, que entrar un rico en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 25, 'Mas sus discípulos, oyendo estas cosas, se espantaron en gran manera, diciendo: ¿Quién pues podrá ser salvo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 26, 'Y mirándo los Jesús, les dijo: Para con los hombres imposible es esto; mas para con Dios todo es posible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 27, 'Entonces respondiendo Pedro, le dijo: He aquí, nosotros hemos dejado todo, y te hemos seguido: ¿qué pues tendremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 28, 'Y Jesús les dijo: De cierto os digo, que vosotros que me habéis seguido, en la regeneración, cuando se sentará el Hijo del hombre en el trono de su gloria, vosotros también os sentaréis sobre doce tronos, para juzgar á las doce tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 29, 'Y cualquiera que dejare casas, ó hermanos, ó hermanas, ó padre, ó madre, ó mujer, ó hijos, ó tierras, por mi nombre, recibirá cien veces tanto, y heredará la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 19, 30, 'Mas muchos primeros serán postreros, y postreros primeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 1, 'PORQUE el reino de los cielos es semejante á un hombre, padre de familia, que salió por la mañana á ajustar obreros para su viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 2, 'Y habiéndose concertado con los obreros en un denario al día, los envió á su viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 3, 'Y saliendo cerca de la hora de las tres, vió otros que estaban en la plaza ociosos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 4, 'Y les dijo: Id también vosotros á mi viña, y os daré lo que fuere justo. Y ellos fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 5, 'Salió otra vez cerca de las horas sexta y nona, é hizo lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 6, 'Y saliendo cerca de la hora undécima, halló otros que estaban ociosos; y díceles: ¿Por qué estáis aquí todo el día ociosos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 7, 'Dícenle: Porque nadie nos ha ajustado. Díceles: Id también vosotros á la viña, y recibiréis lo que fuere justo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 8, 'Y cuando fué la tarde del día, el señor de la viña dijo á su mayordomo: Llama á los obreros y págales el jornal, comenzando desde los postreros hasta los primeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 9, 'Y viniendo los que habían ido cerca de la hora undécima, recibieron cada uno un denario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 10, 'Y viniendo también los primeros, pensaron que habían de recibir más; pero también ellos recibieron cada uno un denario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 11, 'Y tomándolo, murmuraban contra el padre de la familia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 12, 'Diciendo: Estos postreros sólo han trabajado una hora, y los has hecho iguales á nosotros, que hemos llevado la carga y el calor del día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 13, 'Y él respondiendo, dijo á uno de ellos: Amigo, no te hago agravio; ¿no te concertaste conmigo por un denario?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 14, 'Toma lo que es tuyo, y vete; mas quiero dar á este postrero, como á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 15, '¿No me es lícito á mi hacer lo que quiero con lo mío? ó ¿es malo tu ojo, porque yo soy bueno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 16, 'Así los primeros serán postreros, y los postreros primeros: porque muchos son llamados, mas pocos escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 17, 'Y subiendo Jesús á Jerusalem, tomó sus doce discípulos aparte en el camino, y les dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 18, 'He aquí subimos á Jerusalem, y el Hijo del hombre será entregado á los principes de los sacerdotes y á los escribas, y le condenarán á muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 19, 'Y le entregarán á los Gentiles para que le escarnezcan, y azoten, y crucifiquen; mas al tercer día resucitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 20, 'Entonces se llegó á él la madre de los hijos de Zebedeo con sus hijos, adorándo le, y pidiéndole algo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 21, 'Y él le dijo: ¿Qué quieres? Ella le dijo: Di que se sienten estos dos hijos míos, el uno á tu mano derecha, y el otro á tu izquierda, en tu reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 22, 'Entonces Jesús respondiendo, dijo: No sabéis lo que pedís: ¿podéis beber el vaso que yo he de beber, y ser bautizados del bautismo de que yo soy bautizado? Y ellos le dicen: Podemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 23, 'Y él les dice: A la verdad mi vaso beberéis, y del bautismo de que yo soy bautizado, seréis bautizados; mas el sentaros á mi mano derecha y á mi izquierda, no es mío dar lo, sino á aquellos para quienes está aparejado de mi Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 24, 'Y como los diez oyeron esto, se enojaron de los dos hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 25, 'Entonces Jesús llamándolos, dijo: Sabéis que los príncipes de los Gentiles se enseñorean sobre ellos, y los que son grandes ejercen sobre ellos potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 26, 'Mas entre vosotros no será así; sino el que quisiere entre vosotros hacerse grande, será vuestro servidor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 27, 'Y el que quisiere entre vosotros ser el primero, será vuestro siervo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 28, 'Como el Hijo del hombre no vino para ser servido, sino para servir, y para dar su vida en rescate por muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 29, 'Entonces saliendo ellos de Jericó, le seguía gran compañía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 30, 'Y he aquí dos ciegos sentados junto al camino, como oyeron que Jesús pasaba, clamaron, diciendo: Señor, Hijo de David, ten misericordia de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 31, 'Y la gente les reñía para que callasen; mas ellos clamaban más, diciendo: Señor, Hijo de David, ten misericordia de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 32, 'Y parándose Jesús, los llamó, y dijo: ¿Qué queréis que haga por vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 33, 'Ellos le dicen: Señor, que sean abiertos nuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 20, 34, 'Entonces Jesús, teniendo misericordia de ellos, les tocó los ojos, y luego sus ojos recibieron la vista; y le siguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 1, 'Y COMO se acercaron á Jerusalem, y vinieron á Bethfagé, al monte de las Olivas, entonces Jesús envió dos discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 2, 'Diciéndoles: Id á la aldea que está delante de vosotros, y luego hallaréis una asna atada, y un pollino con ella: desatad la, y traédme los.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 3, 'Y si alguno os dijere algo, decid: El Señor los ha menester. Y luego los dejará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 4, 'Y todo esto fué hecho, para que se cumpliese lo que fué dicho por el profeta, que dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 5, 'Decid á la hija de Sión: He aquí, tu Rey viene á ti, Manso, y sentado sobre una asna, Y sobre un pollino, hijo de animal de yugo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 6, 'Y los discípulos fueron, é hicieron como Jesús les mandó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 7, 'Y trajeron el asna y el pollino, y pusieron sobre ellos sus mantos; y se sentó sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 8, 'Y la compañía, que era muy numerosa, tendía sus mantos en el camino: y otros cortaban ramos de los árboles, y los tendían por el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 9, 'Y las gentes que iban delante, y las que iban detrás, aclamaban diciendo: ¡Hosanna al Hijo de David! ¡Bendito el que viene en el nombre del Señor! ¡Hosanna en las alturas!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 10, 'Y entrando él en Jerusalem, toda la ciudad se alborotó, diciendo. ¿Quién es éste?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 11, 'Y las gentes decían: Este es Jesús, el profeta, de Nazaret de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 12, 'Y entró Jesús en el templo de Dios, y echó fuera todos los que vendían y compraban en el templo, y trastornó las mesas de los cambiadores, y las sillas de los que vendían palomas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 13, 'Y les dice: Escrito está: Mi casa, casa de oración será llamada; mas vosotros cueva de ladrones la habéis hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 14, 'Entonces vinieron á él ciegos y cojos en el templo, y los sanó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 15, 'Mas los príncipes de los sacerdotes y los escribas, viendo las maravillas que hacía, y á los muchachos aclamando en el templo y diciendo: ¡Hosanna al Hijo de David! se indignaron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 16, 'Y le dijeron: ¿Oyes lo que éstos dicen? Y Jesús les dice: Sí: ¿nunca leísteis: De la boca de los niños y de los que maman perfeccionaste la alabanza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 17, 'Y dejándolos, se salió fuera de la ciudad, á Bethania; y posó allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 18, 'Y por la mañana volviendo á la ciudad, tuvo hambre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 19, 'Y viendo una higuera cerca del camino, vino á ella, y no halló nada en ella, sino hojas solamente, y le dijo: Nunca más para siempre nazca de ti fruto. Y luego se secó la higuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 20, 'Y viendo esto los discípulos, maravillados decían: ¿Cómo se secó luego la higuera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 21, 'Y respondiendo Jesús les dijo: De cierto os digo, que si tuviereis fe, y no dudareis, no sólo haréis esto de la higuera: mas si á este monte dijereis: Quítate y échate en la mar, será hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 22, 'Y todo lo que pidiereis en oración, creyendo, lo recibiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 23, 'Y como vino al templo, llegáronse á él cuando estaba enseñando, los príncipes de los sacerdotes y los ancianos del pueblo, diciendo. ¿Con qué autoridad haces esto? ¿y quién te dió esta autoridad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 24, 'Y respondiendo Jesús, les dijo: Yo también os preguntaré una palabra, la cual si me dijereis, también yo os diré con qué autoridad hago esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 25, 'El bautismo de Juan, ¿de dónde era? ¿del cielo, ó de los hombres? Ellos entonces pensaron entre sí, diciendo: Si dijéremos, del cielo, nos dirá: ¿Por qué pues no le creísteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 26, 'Y si dijéremos, de los hombres, tememos al pueblo; porque todos tienen á Juan por profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 27, 'Y respondiendo á Jesús, dijeron: No sabemos. Y él también les dijo: Ni yo os digo con qué autoridad hago esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 28, 'Mas, ¿qué os parece? Un hombre tenía dos hijos, y llegando al primero, le dijo: Hijo, ve hoy á trabajar en mi viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 29, 'Y respondiendo él, dijo: No quiero; mas después, arrepentido, fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 30, 'Y llegando al otro, le dijo de la misma manera; y respondiendo él, dijo: Yo, señor, voy. Y no fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 31, '¿Cuál de los dos hizo la voluntad de su padre? Dicen ellos: El primero. Díceles Jesús: De cierto os digo, que los publicanos y las rameras os van delante al reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 32, 'Porque vino á vosotros Juan en camino de justicia, y no le creísteis; y los publicanos y las rameras le creyeron; y vosotros, viendo esto, no os arrepentisteis después para creerle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 33, 'Oíd otra parábola: Fué un hombre, padre de familia, el cual plantó una viña; y la cercó de vallado, y cavó en ella un lagar, y edificó una torre, y la dió á renta á labradores, y se partió lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 34, 'Y cuando se acercó el tiempo de los frutos, envió sus siervos á los labradores, para que recibiesen sus frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 35, 'Mas los labradores, tomando á los siervos, al uno hirieron, y al otro mataron, y al otro apedrearon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 36, 'Envió de nuevo otros siervos, más que los primeros; é hicieron con ellos de la misma manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 37, 'Y á la postre les envió su hijo, diciendo: Tendrán respeto á mi hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 38, 'Mas los labradores, viendo al hijo, dijeron entre sí: Este es el heredero; venid, matémosle, y tomemos su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 39, 'Y tomado, le echaron fuera de la viña, y le mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 40, 'Pues cuando viniere el señor de la viña, ¿qué hará á aquellos labradores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 41, 'Dícenle: á los malos destruirá miserablemente, y su viña dará á renta á otros labradores, que le paguen el fruto á sus tiempos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 42, 'Díceles Jesús: ¿Nunca leísteis en las Escrituras: La piedra que desecharon los que edificaban, Esta fué hecha por cabeza de esquina: Por el Señor es hecho esto, Y es cosa maravillosa en nuestros ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 43, 'Por tanto os digo, que el reino de Dios será quitado de vosotros, y será dado á gente que haga los frutos de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 44, 'Y el que cayere sobre esta piedra, será quebrantado; y sobre quien ella cayere, le desmenuzará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 45, 'Y oyendo los príncipes de los sacerdotes y los Fariseos sus parábolas, entendieron que hablaba de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 21, 46, 'Y buscando cómo echarle mano, temieron al pueblo; porque le tenían por profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 1, 'Y RESPONDIENDO Jesús, les volvió á hablar en parábolas, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 2, 'El reino de los cielos es semejante á un hombre rey, que hizo bodas á su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 3, 'Y envió sus siervos para que llamasen los llamados á las bodas; mas no quisieron venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 4, 'Volvió á enviar otros siervos, diciendo: Decid á los llamados: He aquí, mi comida he aparejado; mis toros y animales engordados son muertos, y todo está prevenido: venid á las bodas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 5, 'Mas ellos no se cuidaron, y se fueron, uno á su labranza, y otro á sus negocios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 6, 'Y otros, tomando á sus siervos, los afrentaron y los mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 7, 'Y el rey, oyendo esto, se enojó; y enviando sus ejércitos, destruyó á aquellos homicidas, y puso fuego á su ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 8, 'Entonces dice á sus siervos: Las bodas á la verdad están aparejadas; mas los que eran llamados no eran dignos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 9, 'Id pues á las salidas de los caminos, y llamad á las bodas á cuantos hallareis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 10, 'Y saliendo los siervos por los caminos, juntaron á todos los que hallaron, juntamente malos y buenos: y las bodas fueron llenas de convidados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 11, 'Y entró el rey para ver los convidados, y vió allí un hombre no vestido de boda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 12, 'Y le dijo: Amigo, ¿cómo entraste aquí no teniendo vestido de boda? Mas él cerró la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 13, 'Entonces el rey dijo á los que servían: Atado de pies y de manos tomadle, y echadle en las tinieblas de afuera: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 14, 'Porque muchos son llamados, y pocos escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 15, 'Entonces, idos los Fariseos, consultaron cómo le tomarían en alguna palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 16, 'Y envían á él los discípulos de ellos, con los Herodianos, diciendo: Maestro, sabemos que eres amador de la verdad, y que enseñas con verdad el camino de Dios, y que no te curas de nadie, porque no tienes acepción de persona de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 17, 'Dinos pues, ¿qué te parece? ¿es lícito dar tributo á César, ó no?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 18, 'Mas Jesús, entendida la malicia de ellos, les dice: ¿Por qué me tentáis, hipócritas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 19, 'Mostradme la moneda del tributo. Y ellos le presentaron un denario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 20, 'Entonces les dice: ¿Cúya es esta figura, y lo que está encima escrito?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 21, 'Dícenle: De César. Y díceles: Pagad pues á César lo que es de César, y á Dios lo que es de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 22, 'Y oyendo esto, se maravillaron, y dejándole se fueron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 23, 'Aquel día llegaron á él los Saduceos, que dicen no haber resurrección, y le preguntaron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 24, 'Diciendo: Maestro, Moisés dijo: Si alguno muriere sin hijos, su hermano se casará con su mujer, y despertará simiente á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 25, 'Fueron pues, entre nosotros siete hermanos: y el primero tomó mujer, y murió; y no teniendo generación, dejó su mujer á su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 26, 'De la misma manera también el segundo, y el tercero, hasta los siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 27, 'Y después de todos murió también la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 28, 'En la resurrección pues, ¿de cuál de los siete será ella mujer? porque todos la tuvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 29, 'Entonces respondiendo Jesús, les dijo: Erráis ignorando las Escrituras, y el poder de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 30, 'Porque en la resurrección, ni los hombres tomarán mujeres, ni las mujeres marido; mas son como los ángeles de Dios en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 31, 'Y de la resurrección de los muertos, ¿no habéis leído lo que os es dicho por Dios, que dice:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 32, 'Yo soy el Dios de Abraham, y el Dios de Isaac, y el Dios de Jacob? Dios no es Dios de muertos, sino de vivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 33, 'Y oyendo esto las gentes, estaban atónitas de su doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 34, 'Entonces los Fariseos, oyendo que había cerrado la boca á los Saduceos, se juntaron á una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 35, 'Y preguntó uno de ellos, intérprete de la ley, tentándole y diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 36, 'Maestro, ¿cuál es el mandamiento grande en la ley?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 37, 'Y Jesús le dijo: Amarás al Señor tu Dios de todo tu corazón, y de toda tu alma, y de toda tu mente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 38, 'Este es el primero y el grande mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 39, 'Y el segundo es semejante á éste: Amarás á tu prójimo como á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 40, 'De estos dos mandamientos depende toda la ley y los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 41, 'Y estando juntos los Fariseos, Jesús les preguntó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 42, 'Diciendo: ¿Qué os parece del Cristo? ¿de quién es Hijo? Dícenle: De David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 43, 'El les dice: ¿Pues cómo David en Espíritu le llama Señor, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 44, 'Dijo el Señor á mi Señor: Siéntate á mi diestra, Entre tanto que pongo tus enemigos por estrado de tus pies?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 45, 'Pues si David le llama Señor, ¿cómo es su Hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 22, 46, 'Y nadie le podía responder palabra; ni osó alguno desde aquel día preguntarle más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 1, 'ENTONCES habló Jesús á las gentes y á sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 2, 'Diciendo: Sobre la cátedra de Moisés se sentaron los escribas y los Fariseos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 3, 'Así que, todo lo que os dijeren que guardéis, guardad lo y haced lo; mas no hagáis conforme á sus obras: porque dicen, y no hacen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 4, 'Porque atan cargas pesadas y difíciles de llevar, y las ponen sobre los hombros de los hombres; mas ni aun con su dedo las quieren mover.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 5, 'Antes, todas sus obras hacen para ser mirados de los hombres; porque ensanchan sus filacterias, y extienden los flecos de sus mantos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 6, 'Y aman los primeros asientos en las cenas, y las primeras sillas en las sinagogas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 7, 'Y las salutaciones en las plazas, y ser llamados de los hombres Rabbí, Rabbí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 8, 'Mas vosotros, no queráis ser llamados Rabbí; porque uno es vuestro Maestro, el Cristo; y todos vosotros sois hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 9, 'Y vuestro padre no llaméis á nadie en la tierra; porque uno es vuestro Padre, el cual está en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 10, 'Ni seáis llamados maestros; porque uno es vuestro Maestro, el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 11, 'El que es el mayor de vosotros, sea vuestro siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 12, 'Porque el que se ensalzare, será humillado; y el que se humillare, será ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 13, 'Mas ¡ay de vosotros, escribas y Fariseos, hipócritas! porque cerráis el reino de los cielos delante de los hombres; que ni vosotros entráis, ni á los que están entrando dejáis entrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 14, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque coméis las casas de las viudas, y por pretexto hacéis larga oración: por esto llevaréis mas grave juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 15, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque rodeáis la mar y la tierra por hacer un prosélito; y cuando fuere hecho, le hacéis hijo del infierno doble más que vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 16, '¡Ay de vosotros, guías ciegos! que decís: Cualquiera que jurare por el templo es nada; mas cualquiera que jurare por el oro del templo, deudor es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 17, '¡Insensatos y ciegos! porque ¿cuál es mayor, el oro, ó el templo que santifica al oro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 18, 'Y: Cualquiera que jurare por el altar, es nada; mas cualquiera que jurare por el presente que está sobre él, deudor es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 19, '¡Necios y ciegos! porque, ¿cuál es mayor, el presente, ó el altar que santifica al presente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 20, 'Pues el que jurare por el altar, jura por él, y por todo lo que está sobre él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 21, 'Y el que jurare por el templo, jura por él, y por Aquél que habita en él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 22, 'Y el que jura por el cielo, jura por el trono de Dios, y por Aquél que está sentado sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 23, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque diezmáis la menta y el eneldo y el comino, y dejasteis lo que es lo más grave de la ley, es á saber, el juicio y la misericordia y la fe: esto era menester hacer, y no dejar lo otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 24, '¡Guías ciegos, que coláis el mosquito, mas tragáis el camello!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 25, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque limpiais lo que está de fuera del vaso y del plato; mas de dentro están llenos de robo y de injusticia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 26, '¡Fariseo ciego, limpia primero lo de dentro del vaso y del plato, para que también lo de fuera se haga limpio!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 27, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque sois semejantes á sepulcros blanqueados, que de fuera, á la verdad, se muestran hermosos, mas de dentro están llenos de huesos de muertos y de toda suciedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 28, 'Así también vosotros de fuera, á la verdad, os mostráis justos á los hombres; mas de dentro, llenos estáis de hipocresía é iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 29, '¡Ay de vosotros, escribas y Fariseos, hipócritas! porque edificáis los sepulcros de los profetas, y adornáis los monumentos de los justos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 30, 'Y decís: Si fuéramos en los días de nuestros padres, no hubiéramos sido sus compañeros en la sangre de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 31, 'Así que, testimonio dais á vosotros mismos, que sois hijos de aquellos que mataron á los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 32, '¡Vosotros también henchid la medida de vuestros padres!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 33, '¡Serpientes, generación de víboras! ¿cómo evitaréis el juicio del infierno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 34, 'Por tanto, he aquí, yo envío á vosotros profetas, y sabios, y escribas: y de ellos, á unos mataréis y crucificaréis, y á otros de ellos azotaréis en vuestras sinagogas, y perseguiréis de ciudad en ciudad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 35, 'Para que venga sobre vosotros toda la sangre justa que se ha derramado sobre la tierra, desde la sangre de Abel el justo, hasta la sangre de Zacarías, hijo de Barachîas, al cual matasteis entre el templo y el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 36, 'De cierto os digo que todo esto vendrá sobre esta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 37, '¡Jerusalem, Jerusalem, que matas á los profetas, y apedreas á los que son enviados á ti! ¡cuántas veces quise juntar tus hijos, como la gallina junta sus pollos debajo de las alas, y no quisiste!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 38, 'He aquí vuestra casa os es dejada desierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 23, 39, 'Porque os digo que desde ahora no me veréis, hasta que digáis: Bendito el que viene en el nombre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 1, 'Y SALIDO Jesús, íbase del templo; y se llegaron sus discípulos, para mostrarle los edificios del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 2, 'Y respondiendo él, les dijo: ¿Veis todo esto? de cierto os digo, que no será dejada aquí piedra sobre piedra, que no sea destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 3, 'Y sentándose él en el monte de las Olivas, se llegaron á él los discípulos aparte, diciendo: Dinos, ¿cuándo serán estas cosas, y qué señal habrá de tu venida, y del fin del mundo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 4, 'Y respondiendo Jesús, les dijo: Mirad que nadie os engañe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 5, 'Porque vendrán muchos en mi nombre, diciendo: Yo soy el Cristo; y á muchos engañarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 6, 'Y oiréis guerras, y rumores de guerras: mirad que no os turbéis; porque es menester que todo esto acontezca; mas aún no es el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 7, 'Porque se levantará nación contra nación, y reino contra reino; y habrá pestilencias, y hambres, y terremotos por los lugares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 8, 'Y todas estas cosas, principio de dolores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 9, 'Entonces os entregarán para ser afligidos, y os matarán; y seréis aborrecidos de todas las gentes por causa de mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 10, 'Y muchos entonces serán escandalizados; y se entregarán unos á otros, y unos á otros se aborrecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 11, 'Y muchos falsos profetas se levantarán y engañarán á muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 12, 'Y por haberse multiplicado la maldad, la caridad de muchos se resfriará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 13, 'Mas el que perseverare hasta el fin, éste será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 14, 'Y será predicado este evangelio del reino en todo el mundo, por testimonio á todos los Gentiles; y entonces vendrá el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 15, 'Por tanto, cuando viereis la abominación del asolamiento, que fué dicha por Daniel profeta, que estará en el lugar santo, (el que lee, entienda),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 16, 'Entonces los que están en Judea, huyan á los montes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 17, 'Y el que sobre el terrado, no descienda á tomar algo de su casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 18, 'Y el que en el campo, no vuelva atrás á tomar sus vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 19, 'Mas ¡ay de las preñadas, y de las que crían en aquellos días!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 20, 'Orad, pues, que vuestra huída no sea en invierno ni en sábado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 21, 'Porque habrá entonces grande aflicción, cual no fué desde el principio del mundo hasta ahora, ni será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 22, 'Y si aquellos días no fuesen acortados, ninguna carne sería salva; mas por causa de los escogidos, aquellos días serán acortados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 23, 'Entonces, si alguno os dijere: He aquí está el Cristo, ó allí, no creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 24, 'Porque se levantarán falsos Cristos, y falsos profetas, y darán señales grandes y prodigios; de tal manera que engañarán, si es posible, aun á los escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 25, 'He aquí os lo he dicho antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 26, 'Así que, si os dijeren: He aquí en el desierto está; no salgáis: He aquí en las cámaras; no creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 27, 'Porque como el relámpago que sale del oriente y se muestra hasta el occidente, así será también la venida del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 28, 'Porque donde quiera que estuviere el cuerpo muerto, allí se juntarán las águilas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 29, 'Y luego después de la aflicción de aquellos días, el sol se obscurecerá, y la luna no dará su lumbre, y las estrellas caerán del cielo, y las virtudes de los cielos serán conmovidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 30, 'Y entonces se mostrará la señal del Hijo del hombre en el cielo; y entonces lamentarán todas las tribus de la tierra, y verán al Hijo del hombre que vendrá sobre las nubes del cielo, con grande poder y gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 31, 'Y enviará sus ángeles con gran voz de trompeta, y juntarán sus escogidos de los cuatro vientos, de un cabo del cielo hasta el otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 32, 'De la higuera aprended la parábola: Cuando ya su rama se enternece, y las hojas brotan, sabéis que el verano está cerca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 33, 'Así también vosotros, cuando viereis todas estas cosas, sabed que está cercano, á las puertas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 34, 'De cierto os digo, que no pasará esta generación, que todas estas cosas no acontezcan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 35, 'El cielo y la tierra pasarán, mas mis palabras no pasarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 36, 'Empero del día y hora nadie sabe, ni aun los ángeles de los cielos, sino mi Padre solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 37, 'Mas como los días de Noé, así será la venida del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 38, 'Porque como en los días antes del diluvio estaban comiendo y bebiendo, casándose y dando en casamiento, hasta el día que Noé entró en el arca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 39, 'Y no conocieron hasta que vino el diluvio y llevó á todos, así será también la venida del Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 40, 'Entonces estarán dos en el campo; el uno será tomado, y el otro será dejado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 41, 'Dos mujeres moliendo á un molinillo; la una será tomada, y la otra será dejada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 42, 'Velad pues, porque no sabéis á qué hora ha de venir vuestro Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 43, 'Esto empero sabed, que si el padre de la familia supiese á cuál vela el ladrón había de venir, velaría, y no dejaría minar su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 44, 'Por tanto, también vosotros estad apercibidos; porque el Hijo del hombre ha de venir á la hora que no pensáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 45, '¿Quién pues es el siervo fiel y prudente, al cual puso su señor sobre su familia para que les dé alimento á tiempo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 46, 'Bienaventurado aquel siervo, al cual, cuando su señor viniere, le hallare haciendo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 47, 'De cierto os digo, que sobre todos sus bienes le pondrá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 48, 'Y si aquel siervo malo dijere en su corazón Mi señor se tarda en venir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 49, 'Y comenzare á herir á sus consiervos, y aun á comer y á beber con los borrachos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 50, 'Vendrá el señor de aquel siervo en el día que no espera, y á la hora que no sabe,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 24, 51, 'Y le cortará por medio, y pondrá su parte con los hipócritas: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 1, 'ENTONCES el reino de los cielos será semejante á diez vírgenes, que tomando sus lámparas, salieron á recibir al esposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 2, 'Y las cinco de ellas eran prudentes, y las cinco fatuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 3, 'Las que eran fatuas, tomando sus lámparas, no tomaron consigo aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 4, 'Mas las prudentes tomaron aceite en sus vasos, juntamente con sus lámparas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 5, 'Y tardándose el esposo, cabecearon todas, y se durmieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 6, 'Y á la media noche fué oído un clamor: He aquí, el esposo viene; salid á recibirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 7, 'Entonces todas aquellas vírgenes se levantaron, y aderezaron sus lámparas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 8, 'Y las fatuas dijeron á las prudentes: Dadnos de vuestro aceite; porque nuestras lámparas se apagan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 9, 'Mas las prudentes respondieron, diciendo. Porque no nos falte á nosotras y á vosotras, id antes á los que venden, y comprad para vosotras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 10, 'Y mientras que ellas iban á comprar, vino el esposo; y las que estaban apercibidas, entraron con él á las bodas; y se cerró la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 11, 'Y después vinieron también las otras vírgenes, diciendo: Señor, Señor, ábrenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 12, 'Mas respondiendo él, dijo: De cierto os digo, que no os conozco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 13, 'Velad, pues, porque no sabéis el día ni la hora en que el Hijo del hombre ha de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 14, 'Porque el reino de los cielos es como un hombre que partiéndose lejos llamó á sus siervos, y les entregó sus bienes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 15, 'Y á éste dió cinco talentos, y al otro dos, y al otro uno: á cada uno conforme á su facultad; y luego se partió lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 16, 'Y el que había recibido cinco talentos se fué, y granjeó con ellos, é hizo otros cinco talentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 17, 'Asimismo el que había recibido dos, ganó también él otros dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 18, 'Mas el que había recibido uno, fué y cavó en la tierra, y escondió el dinero de su señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 19, 'Y después de mucho tiempo, vino el señor de aquellos siervos, é hizo cuentas con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 20, 'Y llegando el que había recibido cinco talentos, trajo otros cinco talentos, diciendo: Señor, cinco talentos me entregaste; he aquí otros cinco talentos he ganado sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 21, 'Y su señor le dijo: Bien, buen siervo y fiel; sobre poco has sido fiel, sobre mucho te pondré: entra en el gozo de tu señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 22, 'Y llegando también el que había recibido dos talentos, dijo: Señor, dos talentos me entregaste; he aquí otros dos talentos he ganado sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 23, 'Su señor le dijo: Bien, buen siervo y fiel; sobre poco has sido fiel, sobre mucho te pondré: entra en el gozo de tu señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 24, 'Y llegando también el que había recibido un talento, dijo: Señor, te conocía que eres hombre duro, que siegas donde no sembraste, y recoges donde no esparciste;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 25, 'Y tuve miedo, y fuí, y escondí tu talento en la tierra: he aquí tienes lo que es tuyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 26, 'Y respondiendo su señor, le dijo: Malo y negligente siervo, sabías que siego donde no sembré y que recojo donde no esparcí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 27, 'Por tanto te convenía dar mi dinero á los banqueros, y viniendo yo, hubiera recibido lo que es mío con usura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 28, 'Quitadle pues el talento, y dadlo al que tiene diez talentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 29, 'Porque á cualquiera que tuviere, le será dado, y tendrá más; y al que no tuviere, aun lo que tiene le será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 30, 'Y al siervo inútil echadle en las tinieblas de afuera: allí será el lloro y el crujir de dientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 31, 'Y cuando el Hijo del hombre venga en su gloria, y todos los santos ángeles con él, entonces se sentará sobre el trono de su gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 32, 'Y serán reunidas delante de él todas las gentes: y los apartará los unos de los otros, como aparta el pastor las ovejas de los cabritos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 33, 'Y pondrá las ovejas á su derecha, y los cabritos á la izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 34, 'Entonces el Rey dirá á los que estarán á su derecha: Venid, benditos de mi Padre, heredad el reino preparado para vosotros desde la fundación del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 35, 'Porque tuve hambre, y me disteis de comer; tuve sed, y me disteis de beber; fuí huésped, y me recogisteis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 36, 'Desnudo, y me cubristeis; enfermo, y me visitasteis; estuve en la cárcel, y vinisteis á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 37, 'Entonces los justos le responderán, diciendo: Señor, ¿cuándo te vimos hambriento, y te sustentamos? ¿ó sediento, y te dimos de beber?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 38, '¿Y cuándo te vimos huésped, y te recogimos? ¿ó desnudo, y te cubrimos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 39, '¿O cuándo te vimos enfermo, ó en la cárcel, y vinimos á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 40, 'Y respondiendo el Rey, les dirá: De cierto os digo que en cuanto lo hicisteis á uno de estos mis hermanos pequeñitos, á mí lo hicisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 41, 'Entonces dirá también á los que estarán á la izquierda: Apartaos de mí, malditos, al fuego eterno preparado para el diablo y para sus ángeles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 42, 'Porque tuve hambre, y no me disteis de comer; tuve sed, y no me disteis de beber;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 43, 'Fuí huésped, y no me recogisteis; desnudo, y no me cubristeis; enfermo, y en la cárcel, y no me visitasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 44, 'Entonces también ellos le responderán, diciendo: Señor, ¿cuándo te vimos hambriento, ó sediento, ó huésped, ó desnudo, ó enfermo, ó en la cárcel, y no te servimos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 45, 'Entonces les responderá, diciendo: De cierto os digo que en cuanto no lo hicisteis á uno de estos pequeñitos, ni á mí lo hicisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 25, 46, 'E irán éstos al tormento eterno, y los justos á la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 1, 'Y ACONTECIO que, como hubo acabado Jesús todas estas palabras, dijo á sus discípulos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 2, 'Sabéis que dentro de dos días se hace la pascua, y el Hijo del hombre es entregado para ser crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 3, 'Entonces los príncipes de los sacerdotes, y los escribas, y los ancianos del pueblo se juntaron al patio del pontífice, el cual se llamaba Caifás;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 4, 'Y tuvieron consejo para prender por engaño á Jesús, y matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 5, 'Y decían: No en el día de la fiesta, porque no se haga alboroto en el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 6, 'Y estando Jesús en Bethania, en casa de Simón el leproso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 7, 'Vino á él una mujer, teniendo un vaso de alabastro de unguento de gran precio, y lo derramó sobre la cabeza de él, estando sentado á la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 8, 'Lo cual viendo sus discípulos, se enojaron, diciendo: ¿Por qué se pierde esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 9, 'Porque esto se podía vender por gran precio, y darse á los pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 10, 'Y entendiéndolo Jesús, les dijo: ¿Por qué dais pena á esta mujer? Pues ha hecho conmigo buena obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 11, 'Porque siempre tendréis pobres con vosotros, mas á mí no siempre me tendréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 12, 'Porque echando este unguento sobre mi cuerpo, para sepultarme lo ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 13, 'De cierto os digo, que donde quiera que este evangelio fuere predicado en todo el mundo, también será dicho para memoria de ella, lo que ésta ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 14, 'Entonces uno de los doce, que se llamaba Judas Iscariote, fué á los príncipes de los sacerdotes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 15, 'Y les dijo: ¿Qué me queréis dar, y yo os lo entregaré? Y ellos le señalaron treinta piezas de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 16, 'Y desde entonces buscaba oportunidad para entregarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 17, 'Y el primer día de la fiesta de los panes sin levadura, vinieron los discípulos á Jesús, diciéndole: ¿Dónde quieres que aderecemos para ti para comer la pascua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 18, 'Y él dijo: Id á la ciudad á cierto hombre, y decidle: El Maestro dice: Mi tiempo está cerca; en tu casa haré la pascua con mis discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 19, 'Y los discípulos hicieron como Jesús les mandó, y aderezaron la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 20, 'Y como fué la tarde del día, se sentó á la mesa con los doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 21, 'Y comiendo ellos, dijo: De cierto os digo, que uno de vosotros me ha de entregar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 22, 'Y entristecidos ellos en gran manera, comenzó cada uno de ellos á decirle: ¿Soy yo, Señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 23, 'Entonces él respondiendo, dijo: El que mete la mano conmigo en el plato, ése me ha de entregar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 24, 'A la verdad el Hijo del hombre va, como está escrito de él, mas ¡ay de aquel hombre por quien el Hijo del hombre es entregado! bueno le fuera al tal hombre no haber nacido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 25, 'Entonces respondiendo Judas, que le entregaba, dijo. ¿Soy yo, Maestro? Dícele: Tú lo has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 26, 'Y comiendo ellos, tomó Jesús el pan, y bendijo, y lo partió, y dió á sus discípulos, y dijo: Tomad, comed. esto es mi cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 27, 'Y tomando el vaso, y hechas gracias, les dió, diciendo: Bebed de él todos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 28, 'Porque esto es mi sangre del nuevo pacto, la cual es derramada por muchos para remisión de los pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 29, 'Y os digo, que desde ahora no beberé más de este fruto de la vid, hasta aquel día, cuando lo tengo de beber nuevo con vosotros en el reino de mi Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 30, 'Y habiendo cantado el himno, salieron al monte de las Olivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 31, 'Entonces Jesús les dice: Todos vosotros seréis escandalizados en mí esta noche; porque escrito está: Heriré al Pastor, y las ovejas de la manada serán dispersas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 32, 'Mas después que haya resucitado, iré delante de vosotros á Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 33, 'Y respondiendo Pedro, le dijo: Aunque todos sean escandalizados en ti, yo nunca seré escandalizado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 34, 'Jesús le dice: De cierto te digo que esta noche, antes que el gallo cante, me negarás tres veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 35, 'Dícele Pedro. Aunque me sea menester morir contigo, no te negaré. Y todos los discípulos dijeron lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 36, 'Entonces llegó Jesús con ellos á la aldea que se llama Gethsemaní, y dice á sus discípulos: Sentaos aquí, hasta que vaya allí y ore.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 37, 'Y tomando á Pedro, y á los dos hijos de Zebedeo, comenzó á entristecerse y á angustiarse en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 38, 'Entonces Jesús les dice: Mi alma está muy triste hasta la muerte; quedaos aquí, y velad conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 39, 'Y yéndose un poco más adelante, se postró sobre su rostro, orando, y diciendo: Padre mío, si es posible, pase de mí este vaso; empero no como yo quiero, sino como tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 40, 'Y vino á sus discípulos, y los halló durmiendo, y dijo á Pedro: ¿Así no habéis podido velar conmigo una hora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 41, 'Velad y orad, para que no entréis en tentación: el espíritu á la verdad está presto, mas la carne enferma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 42, 'Otra vez fué, segunda vez, y oró diciendo. Padre mío, si no puede este vaso pasar de mí sin que yo lo beba, hágase tu voluntad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 43, 'Y vino, y los halló otra vez durmiendo; porque los ojos de ellos estaban agravados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 44, 'Y dejándolos fuése de nuevo, y oró tercera vez, diciendo las mismas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 45, 'Entonces vino á sus discípulos y díceles: Dormid ya, y descansad: he aquí ha llegado la hora, y el Hijo del hombre es entregado en manos de pecadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 46, 'Levantaos, vamos: he aquí ha llegado el que me ha entregado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 47, 'Y hablando aún él, he aquí Judas, uno de los doce, vino, y con él mucha gente con espadas y con palos, de parte de los príncipes de los sacerdotes, y de los ancianos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 48, 'Y el que le entregaba les había dado señal, diciendo: Al que yo besare, aquél es: prendedle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 49, 'Y luego que llegó á Jesús, dijo: Salve, Maestro. Y le besó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 50, 'Y Jesús le dijo: Amigo, ¿á qué vienes? Entonces llegaron, y echaron mano á Jesús, y le prendieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 51, 'Y he aquí, uno de los que estaban con Jesús, extendiendo la mano, sacó su espada, é hiriendo á un siervo del pontífice, le quitó la oreja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 52, 'Entonces Jesús le dice: Vuelve tu espada á su lugar; porque todos los que tomaren espada, á espada perecerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 53, '¿Acaso piensas que no puedo ahora orar á mi Padre, y él me daría más de doce legiones de ángeles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 54, '¿Cómo, pues, se cumplirían las Escrituras, que así conviene que sea hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 55, 'En aquella hora dijo Jesús á las gentes: ¿Como á ladrón habéis salido con espadas y con palos á prenderme? Cada día me sentaba con vosotros enseñando en el templo, y no me prendisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 56, 'Mas todo esto se hace, para que se cumplan las Escrituras de los profetas. Entonces todos los discípulos huyeron, dejándole.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 57, 'Y ellos, prendido Jesús, le llevaron á Caifás pontífice, donde los escribas y los ancianos estaban juntos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 58, 'Mas Pedro le seguía de lejos hasta el patio del pontífice; y entrando dentro, estábase sentado con los criados, para ver el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 59, 'Y los príncipes de los sacerdotes, y los ancianos, y todo el consejo, buscaban falso testimonio contra Jesús, para entregale á la muerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 60, 'Y no lo hallaron, aunque muchos testigos falsos se llegaban; mas á la postre vinieron dos testigos falsos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 61, 'Que dijeron: Este dijo: Puedo derribar el templo de Dios, y en tres días reedificarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 62, 'Y levantándose el pontífice, le dijo: ¿No respondes nada? ¿qué testifican éstos contra ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 63, 'Mas Jesús callaba. Respondiendo el pontífice, le dijo: Te conjuro por el Dios viviente, que nos digas si eres tú el Cristo, Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 64, 'Jesús le dijo: Tú lo has dicho: y aun os digo, que desde ahora habéis de ver al Hijo de los hombres sentado á la diestra de la potencia de Dios, y que viene en las nubes del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 65, 'Entonces el pontífice rasgó sus vestidos, diciendo: Blasfemado ha: ¿qué más necesidad tenemos de testigos? He aquí, ahora habéis oído su blasfemia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 66, '¿Qué os parece? Y respondiendo ellos, dijeron: Culpado es de muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 67, 'Entonces le escupieron en el rostro, y le dieron de bofetadas; y otros le herían con mojicones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 68, 'Diciendo: Profetízanos tú, Cristo, quién es el que te ha herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 69, 'Y Pedro estaba sentado fuera en el patio: y se llegó á él una criada, diciendo: Y tú con Jesús el Galileo estabas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 70, 'Mas él negó delante de todos, diciendo: No sé lo que dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 71, 'Y saliendo él á la puerta, le vió otra, y dijo á los que estaban allí: También éste estaba con Jesús Nazareno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 72, 'Y nego otra vez con juramento: No conozco al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 73, 'Y un poco después llegaron los que estaban por allí, y dijeron á Pedro: Verdaderamente también tú eres de ellos, porque aun tu habla te hace manifiesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 74, 'Entonces comienzó á hacer imprecaciones, y á jurar, diciendo: No conozco al hombre. Y el gallo cantó luego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 26, 75, 'Y se acordó Pedro de las palabras de Jesús, que le dijo: Antes que cante el gallo, me negarás tres veces. Y saliéndose fuera, lloró amargamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 1, 'Y VENIDA la mañana, entraron en consejo todos los príncipes de los sacerdotes, y los ancianos del pueblo, contra Jesús, para entregarle á muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 2, 'Y le llevaron atado, y le entregaron á Poncio Pilato presidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 3, 'Entonces Judas, el que le había entregado, viendo que era condenado, volvió arrepentido las treinta piezas de plata á los príncipes de los sacerdotes y á los ancianos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 4, 'Diciendo: Yo he pecado entregando la sangre inocente. Mas ellos dijeron: ¿Qué se nos da á nosotros? Viéras lo tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 5, 'Y arrojando las piezas de plata en el templo, partióse; y fué, y se ahorcó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 6, 'Y los príncipes de los sacerdotes, tomando las piezas de plata, dijeron: No es lícito echarlas en el tesoro de los dones, porque es precio de sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 7, 'Mas habido consejo, compraron con ellas el campo del alfarero, por sepultura para los extranjeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 8, 'Por lo cual fué llamado aquel campo, Campo de sangre, hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 9, 'Entonces se cumplió lo que fué dicho por el profeta Jeremías, que dijo: Y tomaron las treinta piezas de plata, precio del apreciado, que fué apreciado por los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 10, 'Y las dieron para el campo del alfarero, como me ordenó el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 11, 'Y Jesús estuvo delante del presidente; y el presidente le preguntó, diciendo: ¿Eres tú el Rey de los judíos? Y Jesús le dijo: Tú lo dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 12, 'Y siendo acusado por los príncipes de los sacerdotes, y por los ancianos, nada respondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 13, 'Pilato entonces le dice: ¿No oyes cuántas cosas testifican contra tí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 14, 'Y no le respondió ni una palabra; de tal manera que el presidente se maravillaba mucho,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 15, 'Y en el día de la fiesta acostumbraba el presidente soltar al pueblo un preso, cual quisiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 16, 'Y tenían entonces un preso famoso que se llamaba Barrabás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 17, 'Y juntos ellos, les dijo Pilato; ¿Cuál queréis que os suelte? ¿á Barrabás ó á Jesús que se dice el Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 18, 'Porque sabía que por envidia le habían entregado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 19, 'Y estando él sentado en el tribunal, su mujer envió á él, diciendo: No tengas que ver con aquel justo; porque hoy he padecido muchas cosas en sueños por causa de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 20, 'Mas los príncipes de los sacerdotes y los ancianos, persuadieron al pueblo que pidiese á Barrabás, y á Jesús matase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 21, 'Y respondiendo el presidente les dijo: ¿Cuál de los dos queréis que os suelte? Y ellos dijeron: á Barrabás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 22, 'Pilato les dijo: ¿Qué pues haré de Jesús que se dice el Cristo? Dícenle todos: Sea crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 23, 'Y el presidente les dijo: Pues ¿qué mal ha hecho? Mas ellos gritaban más, diciendo: Sea crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 24, 'Y viendo Pilato que nada adelantaba, antes se hacía más alboroto, tomando agua se lavó las manos delante del pueblo, diciendo: Inocente soy yo de la sangre de este justo veréis lo vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 25, 'Y respondiendo todo el pueblo, dijo: Su sangre sea sobre nosotros, y sobre nuestros hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 26, 'Entonces les soltó á Barrabás: y habiendo azotado á Jesús, le entregó para ser crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 27, 'Entonces los soldados del presidente llevaron á Jesús al pretorio, y juntaron á él toda la cuadrilla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 28, 'Y desnudándole, le echaron encima un manto de grana;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 29, 'Y pusieron sobre su cabeza una corona tejida de espinas, y una caña en su mano derecha; é hincando la rodilla delante de él, le burlaban, diciendo: ¡Salve, Rey de los Judíos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 30, 'Y escupiendo en él, tomaron la caña, y le herían en la cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 31, 'Y después que le hubieron escarnecido, le desnudaron el manto, y le vistieron de sus vestidos, y le llevaron para crucificarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 32, 'Y saliendo, hallaron á un Cireneo, que se llamaba Simón: á éste cargaron para que llevase su cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 33, 'Y como llegaron al lugar que se llamaba Gólgotha, que es dicho, El lugar de la calavera,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 34, 'Le dieron á beber vinagre mezclado con hiel: y gustando, no quiso beber lo');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 35, 'Y después que le hubieron crucificado, repartieron sus vestidos, echando suertes: para que se cumpliese lo que fué dicho por el profeta: Se repartieron mis vestidos, y sobre mi ropa echaron suertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 36, 'Y sentados le guardaban allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 37, 'Y pusieron sobre su cabeza su causa escrita: ESTE ES JESUS EL REY DE LOS JUDIOS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 38, 'Entonces crucificaron con él dos ladrones, uno á la derecha, y otro á la izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 39, 'Y los que pasaban, le decían injurias, meneando sus cabezas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 40, 'Y diciendo: Tú, el que derribas el templo, y en tres días lo reedificas, sálvate á ti mismo: si eres Hijo de Dios, desciende de la cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 41, 'De esta manera también los príncipes de los sacerdotes, escarneciendo con los escribas y los Fariseos y los ancianos, decían:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 42, 'á otros salvó, á sí mismo no puede salvar: si es el Rey de Israel, descienda ahora de la cruz, y creeremos en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 43, 'Confió en Dios: líbrele ahora si le quiere: porque ha dicho: Soy Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 44, 'Lo mismo también le zaherían los ladrones que estaban crucificados con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 45, 'Y desde la hora de sexta fueron tinieblas sobre toda la tierra hasta la hora de nona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 46, 'Y cerca de la hora de nona, Jesús exclamó con grande voz, diciendo: Eli, Eli, ¿lama sabachtani? Esto es: Dios mío, Dios mío, ¿por qué me has desamparado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 47, 'Y algunos de los que estaban allí, oyéndolo, decían: A Elías llama éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 48, 'Y luego, corriendo uno de ellos, tomó una esponja, y la hinchió de vinagre, y poniéndola en una caña, dábale de beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 49, 'Y los otros decían: Deja, veamos si viene Elías á librarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 50, 'Mas Jesús, habiendo otra vez exclamado con grande voz, dió el espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 51, 'Y he aquí, el velo del templo se rompió en dos, de alto á bajo: y la tierra tembló, y las piedras se hendieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 52, 'Y abriéronse los sepulcros, y muchos cuerpos de santos que habían dormido, se levantaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 53, 'Y salidos de los sepulcros, después de su resurrección, vinieron á la santa ciudad, y aparecieron á muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 54, 'Y el centurión, y los que estaban con él guardando á Jesús, visto el terremoto, y las cosas que habían sido hechas, temieron en gran manera, diciendo: Verdaderamente Hijo de Dios era éste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 55, 'Y estaban allí muchas mujeres mirando de lejos, las cuales habían seguido de Galilea á Jesús, sirviéndole:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 56, 'Entre las cuales estaban María Magdalena, y María la madre de Jacobo y de José, y la madre de los hijos de Zebedeo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 57, 'Y como fué la tarde del día, vino un hombre rico de Arimatea, llamado José, el cual también había sido discípulo de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 58, 'Este llegó á Pilato, y pidió el cuerpo de Jesús: entonces Pilato mandó que se le diese el cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 59, 'Y tomando José el cuerpo, lo envolvió en una sábana limpia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 60, 'Y lo puso en su sepulcro nuevo, que había labrado en la peña: y revuelta una grande piedra á la puerta del sepulcro, se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 61, 'Y estaban allí María Magdalena, y la otra María, sentadas delante del sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 62, 'Y el siguiente día, que es después de la preparación, se juntaron los príncipes de los sacerdotes y los Fariseos á Pilato,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 63, 'Diciendo: Señor, nos acordamos que aquel engañador dijo, viviendo aún: Después de tres días resucitaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 64, 'Manda, pues, que se asegure el sepulcro hasta el día tercero; porque no vengan sus discípulos de noche, y le hurten, y digan al pueblo: Resucitó de los muertos. Y será el postrer error peor que el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 65, 'Y Pilato les dijo: Tenéis una guardia: id, aseguradlo como sabéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 27, 66, 'Y yendo ellos, aseguraron el sepulcro, sellando la piedra, con la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 1, 'Y LA víspera de sábado, que amanece para el primer día de la semana, vino María Magdalena, y la otra María, á ver el sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 2, 'Y he aquí, fué hecho un gran terremoto: porque el ángel del Señor, descendiendo del cielo y llegando, había revuelto la piedra, y estaba sentado sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 3, 'Y su aspecto era como un relámpago, y su vestido blanco como la nieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 4, 'Y de miedo de él los guardas se asombraron, y fueron vueltos como muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 5, 'Y respondiendo el ángel, dijo á las mujeres: No temáis vosotras; porque yo sé que buscáis á Jesús, que fué crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 6, 'No está aquí; porque ha resucitado, como dijo. Venid, ved el lugar donde fué puesto el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 7, 'E id presto, decid á sus discípulos que ha resucitado de los muertos: y he aquí va delante de vosotros á Galilea; allí le veréis; he aquí, os lo he dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 8, 'Entonces ellas, saliendo del sepulcro con temor y gran gozo, fueron corriendo á dar las nuevas á sus discípulos. Y mientras iban á dar las nuevas á sus discípulos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 9, 'He aquí, Jesús les sale al encuentro, diciendo: Salve. Y ellas se llegaron y abrazaron sus pies, y le adoraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 10, 'Entonces Jesús les dice: No temáis: id, dad las nuevas á mis hermanos, para que vayan á Galilea, y allí me verán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 11, 'Y yendo ellas, he aquí unos de la guardia vinieron á la ciudad, y dieron aviso á los príncipes de los sacerdotes de todas las cosas que habían acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 12, 'Y juntados con los ancianos, y habido consejo, dieron mucho dinero á los soldados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 13, 'Diciendo: Decid: Sus discípulos vinieron de noche, y le hurtaron, durmiendo nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 14, 'Y si esto fuere oído del presidente, nosotros le persuadiremos, y os haremos seguros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 15, 'Y ellos, tomando el dinero, hicieron como estaban instruídos: y este dicho fué divulgado entre los Judíos hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 16, 'Mas los once discípulos se fueron á Galilea, al monte donde Jesús les había ordenado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 17, 'Y como le vieron, le adoraron: mas algunos dudaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 18, 'Y llegando Jesús, les habló, diciendo: Toda potestad me es dada en el cielo y en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 19, 'Por tanto, id, y doctrinad á todos los Gentiles, bautizándolos en el nombre del Padre, y del Hijo, y del Espíritu Santo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAT', 'Mateo', 28, 20, 'Enseñándoles que guarden todas las cosas que os he mandado: y he aquí, yo estoy con vosotros todos los días, hasta el fin del mundo. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 1, 'EN el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 2, 'Este era en el principio con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 3, 'Todas las cosas por él fueron hechas; y sin él nada de lo que es hecho, fué hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 4, 'En él estaba la vida, y la vida era la luz de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 5, 'Y la luz en las tinieblas resplandece; mas las tinieblas no la comprendieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 6, 'Fué un hombre enviado de Dios, el cual se llamaba Juan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 7, 'Este vino por testimonio, para que diese testimonio de la luz, para que todos creyesen por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 8, 'No era él la luz, sino para que diese testimonio de la luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 9, 'Aquel era la luz verdadera, que alumbra á todo hombre que viene á este mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 10, 'En el mundo estaba, y el mundo fué hecho por él; y el mundo no le conoció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 11, 'A lo suyo vino, y los suyos no le recibieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 12, 'Mas á todos los que le recibieron, dióles potestad de ser hechos hijos de Dios, á los que creen en su nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 13, 'Los cuales no son engendrados de sangre, ni de voluntad de carne, ni de voluntad de varón, mas de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 14, 'Y aquel Verbo fué hecho carne, y habitó entre nosotros (y vimos su gloria, gloria como del unigénito del Padre), lleno de gracia y de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 15, 'Juan dió testimonio de él, y clamó diciendo: Este es del que yo decía: El que viene tras mí, es antes de mí: porque es primero que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 16, 'Porque de su plenitud tomamos todos, y gracia por gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 17, 'Porque la ley por Moisés fué dada: mas la gracia y la verdad por Jesucristo fué hecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 18, 'A Dios nadie le vió jamás: el unigénito Hijo, que está en el seno del Padre, él le declaró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 19, 'Y éste es el testimonio de Juan, cuando los Judíos enviaron de Jerusalem sacerdotes y Levitas, que le preguntasen: ¿Tú, quién eres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 20, 'Y confesó, y no negó; mas declaró: No soy yo el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 21, 'Y le preguntaron: ¿Qué pues? ¿Eres tú Elías? Dijo: No soy. ¿Eres tú el profeta? Y respondió: No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 22, 'Dijéronle: ¿Pues quién eres? para que demos respuesta á los que nos enviaron. ¿Qué dices de ti mismo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 23, 'Dijo: Yo soy la voz del que clama en el desierto: Enderezad el camino del Señor, como dijo Isaías profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 24, 'Y los que habían sido enviados eran de los Fariseos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 25, 'Y preguntáronle, y dijéronle: ¿Por qué pues bautizas, si tú no eres el Cristo, ni Elías, ni el profeta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 26, 'Y Juan les respondió, diciendo: Yo bautizo con agua; mas en medio de vosotros ha estado á quien vosotros no conocéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 27, 'Este es el que ha de venir tras mí, el cual es antes de mí: del cual yo no soy digno de desatar la correa del zapato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 28, 'Estas cosas acontecieron en Betábara, de la otra parte del Jordán, donde Juan bautizaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 29, 'El siguiente día ve Juan á Jesús que venía á él, y dice: He aquí el Cordero de Dios, que quita el pecado del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 30, 'Este es del que dije: Tras mí viene un varón, el cual es antes de mí: porque era primero que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 31, 'Y yo no le conocía; más para que fuese manifestado á Israel, por eso vine yo bautizando con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 32, 'Y Juan dió testimonio, diciendo: Vi al Espíritu que descendía del cielo como paloma, y reposó sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 33, 'Y yo no le conocía; mas el que me envió á bautizar con agua, aquél me dijo: Sobre quien vieres descender el Espíritu, y que reposa sobre él, éste es el que bautiza con Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 34, 'Y yo le vi, y he dado testimonio que éste es el Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 35, 'El siguiente día otra vez estaba Juan, y dos de sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 36, 'Y mirando á Jesús que andaba por allí, dijo: He aquí el Cordero de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 37, 'Y oyéronle los dos discípulos hablar, y siguieron á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 38, 'Y volviéndose Jesús, y viéndolos seguir le, díceles: ¿Qué buscáis? Y ellos le dijeron: Rabbí (que declarado quiere decir Maestro) ¿dónde moras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 39, 'Díceles: Venid y ved. Vinieron, y vieron donde moraba, y quedáronse con él aquel día: porque era como la hora de las diez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 40, 'Era Andrés, hermano de Simón Pedro, uno de los dos que habían oído de Juan, y le habían seguido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 41, 'Este halló primero á su hermano Simón, y díjole: Hemos hallado al Mesías (que declarado es, el Cristo).');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 42, 'Y le trajo á Jesús. Y mirándole Jesús, dijo: Tú eres Simón, hijo de Jonás: tú serás llamado Cephas (que quiere decir, Piedra).');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 43, 'El siguiente día quiso Jesús ir á Galilea, y halla á Felipe, al cual dijo: Sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 44, 'Y era Felipe de Bethsaida, la ciudad de Andrés y de Pedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 45, 'Felipe halló á Natanael, y dícele: Hemos hallado á aquel de quien escribió Moisés en la ley, y los profetas: á Jesús, el hijo de José, de Nazaret.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 46, 'Y díjole Natanael: ¿De Nazaret puede haber algo de bueno? Dícele Felipe: Ven y ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 47, 'Jesús vió venir á sí á Natanael, y dijo de él: He aquí un verdadero Israelita, en el cual no hay engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 48, 'Dícele Natanael: ¿De dónde me conoces? Respondió Jesús, y díjole: Antes que Felipe te llamara, cuando estabas debajo de la higuera te vi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 49, 'Respondió Natanael, y díjole: Rabbí, tú eres el Hijo de Dios; tú eres el Rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 50, 'Respondió Jesús y díjole: ¿Porque te dije, te vi debajo de la higuera, crees? cosas mayores que éstas verás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 1, 51, 'Y dícele: De cierto, de cierto os digo: De aquí adelante veréis el cielo abierto, y los ángeles de Dios que suben y descienden sobre el Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 1, 'Y AL tercer día hiciéronse unas bodas en Caná de Galilea; y estaba allí la madre de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 2, 'Y fué también llamado Jesús y sus discípulos á las bodas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 3, 'Y faltando el vino, la madre de Jesús le dijo: Vino no tienen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 4, 'Y dícele Jesús: ¿Qué tengo yo contigo, mujer? aun no ha venido mi hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 5, 'Su madre dice á los que servían: Haced todo lo que os dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 6, 'Y estaban allí seis tinajuelas de piedra para agua, conforme á la purificación de los Judíos, que cabían en cada una dos ó tres cántaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 7, 'Díceles Jesús: Henchid estas tinajuelas de agua. E hinchiéronlas hasta arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 8, 'Y díceles: Sacad ahora, y presentad al maestresala. Y presentáron le.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 9, 'Y como el maestresala gustó el agua hecha vino, que no sabía de dónde era (mas lo sabían los sirvientes que habían sacado el agua), el maestresala llama al esposo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 10, 'Y dícele: Todo hombre pone primero el buen vino, y cuando están satisfechos, entonces lo que es peor; mas tú has guardado el buen vino hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 11, 'Este principio de señales hizo Jesús en Caná de Galilea, y manifestó su gloria; y sus discípulos creyeron en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 12, 'Después de esto descendió á Capernaun, él, y su madre, y hermanos, y discípulos; y estuvieron allí no muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 13, 'Y estaba cerca la Pascua de los Judíos; y subió Jesús á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 14, 'Y halló en el templo á los que vendían bueyes, y ovejas, y palomas, y á los cambiadores sentados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 15, 'Y hecho un azote de cuerdas, echólos á todos del templo, y las ovejas, y los bueyes; y derramó los dineros de los cambiadores, y trastornó las mesas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 16, 'Y á los que vendían las palomas, dijo: Quitad de aquí esto, y no hagáis la casa de mi Padre casa de mercado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 17, 'Entonces se acordaron sus discípulos que está escrito: El celo de tu casa me comió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 18, 'Y los Judíos respondieron, y dijéronle: ¿Qué señal nos muestras de que haces esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 19, 'Respondió Jesús, y díjoles: Destruid este templo, y en tres días lo levantaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 20, 'Dijeron luego los Judíos: En cuarenta y seis años fue este templo edificado, ¿y tú en tres días lo levantarás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 21, 'Mas él hablaba del templo de su cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 22, 'Por tanto, cuando resucitó de los muertos, sus discípulos se acordaron que había dicho esto; y creyeron á la Escritura, y á la palabra que Jesús había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 23, 'Y estando en Jerusalem en la Pascua, en el día de la fiesta, muchos creyeron en su nombre, viendo las señales que hacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 24, 'Mas el mismo Jesús no se confiaba á sí mismo de ellos, porque él conocía á todos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 2, 25, 'Y no tenía necesidad que alguien le diese testimonio del hombre; porque él sabía lo que había en el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 1, 'Y HABIA un hombre de los Fariseos que se llamaba Nicodemo, príncipe de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 2, 'Este vino á Jesús de noche, y díjole: Rabbí, sabemos que has venido de Dios por maestro; porque nadie puede hacer estas señales que tú haces, si no fuere Dios con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 3, 'Respondió Jesús, y díjole: De cierto, de cierto te digo, que el que no naciere otra vez, no puede ver el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 4, 'Dícele Nicodemo: ¿Cómo puede el hombre nacer siendo viejo? ¿puede entrar otra vez en el vientre de su madre, y nacer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 5, 'Respondió Jesús: De cierto, de cierto te digo, que el que no naciere de agua y del Espíritu, no puede entrar en el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 6, 'Lo que es nacido de la carne, carne es; y lo que es nacido del Espíritu, espíritu es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 7, 'No te maravilles de que te dije: Os es necesario nacer otra vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 8, 'El viento de donde quiere sopla, y oyes su sonido; mas ni sabes de dónde viene, ni á dónde vaya: así es todo aquel que es nacido del Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 9, 'Respondió Nicodemo, y díjole: ¿Cómo puede esto hacerse?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 10, 'Respondió Jesús, y díjole: ¿Tú eres el maestro de Israel, y no sabes esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 11, 'De cierto, de cierto te digo, que lo que sabemos hablamos, y lo que hemos visto, testificamos; y no recibís nuestro testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 12, 'Si os he dicho cosas terrenas, y no creéis, ¿cómo creeréis si os dijere las celestiales?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 13, 'Y nadie subió al cielo, sino el que descendió del cielo, el Hijo del hombre, que está en el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 14, 'Y como Moisés levantó la serpiente en el desierto, así es necesario que el Hijo del hombre sea levantado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 15, 'Para que todo aquel que en él creyere, no se pierda, sino que tenga vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 16, 'Porque de tal manera amó Dios al mundo, que ha dado á su Hijo unigénito, para que todo aquel que en él cree, no se pierda, mas tenga vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 17, 'Porque no envió Dios á su Hijo al mundo, para que condene al mundo, mas para que el mundo sea salvo por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 18, 'El que en él cree, no es condenado; mas el que no cree, ya es condenado, porque no creyó en el nombre del unigénito Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 19, 'Y esta es la condenación: porque la luz vino al mundo, y los hombres amaron más las tinieblas que la luz; porque sus obras eran malas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 20, 'Porque todo aquel que hace lo malo, aborrece la luz y no viene á la luz, porque sus obras no sean redargüidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 21, 'Mas el que obra verdad, viene á la luz, para que sus obras sean manifestadas que son hechas en Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 22, 'Pasado esto, vino Jesús con sus discípulos á la tierra de Judea; y estaba allí con ellos, y bautizaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 23, 'Y bautizaba también Juan en Enón junto á Salim, porque había allí muchas aguas; y venían, y eran bautizados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 24, 'Porque Juan, no había sido aún puesto en la carcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 25, 'Y hubo cuestión entre los discípulos de Juan y los Judíos acerca de la purificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 26, 'Y vinieron á Juan, y dijéronle: Rabbí, el que estaba contigo de la otra parte del Jordán, del cual tú diste testimonio, he aquí bautiza, y todos vienen á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 27, 'Respondió Juan, y dijo: No puede el hombre recibir algo, si no le fuere dado del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 28, 'Vosotros mismos me sois testigos que dije: Yo no soy el Cristo, sino que soy enviado delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 29, 'El que tiene la esposa, es el esposo; mas el amigo del esposo, que está en pie y le oye, se goza grandemente de la voz del esposo; así pues, este mi gozo es cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 30, 'A él conviene crecer, mas á mí menguar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 31, 'El que de arriba viene, sobre todos es: el que es de la tierra, terreno es, y cosas terrenas habla: el que viene del cielo, sobre todos es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 32, 'Y lo que vió y oyó, esto testifica: y nadie recibe su testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 33, 'El que recibe su testimonio, éste signó que Dios es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 34, 'Porque el que Dios envió, las palabras de Dios habla: porque no da Dios el Espíritu por medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 35, 'El Padre ama al Hijo, y todas las cosas dió en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 3, 36, 'El que cree en el Hijo, tiene vida eterna; mas el que es incrédulo al Hijo, no verá la vida, sino que la ira de Dios está sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 1, 'DE manera que como Jesús entendió que los Fariseos habían oído que Jesús hacía y bautizaba más discípulos que Juan,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 2, '(Aunque Jesús no bautizaba, sino sus discípulos),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 3, 'Dejó á Judea, y fuése otra vez á Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 4, 'Y era menester que pasase por Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 5, 'Vino, pues, á una ciudad de Samaria que se llamaba Sichâr, junto á la heredad que Jacob dió á José su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 6, 'Y estaba allí la fuente de Jacob. Pues Jesús, cansado del camino, así se sentó á la fuente. Era como la hora de sexta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 7, 'Vino una mujer de Samaria á sacar agua: y Jesús le dice: Dame de beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 8, '(Porque sus discípulos habían ido á la ciudad á comprar de comer.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 9, 'Y la mujer Samaritana le dice: ¿Cómo tú, siendo Judío, me pides á mí de beber, que soy mujer Samaritana? porque los Judíos no se tratan con los Samaritanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 10, 'Respondió Jesús y díjole: Si conocieses el don de Dios, y quién es el que te dice: Dame de beber: tú pedirías de él, y él te daría agua viva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 11, 'La mujer le dice: Señor, no tienes con qué sacar la, y el pozo es hondo: ¿de dónde, pues, tienes el agua viva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 12, '¿Eres tú mayor que nuestro padre Jacob, que nos dió este pozo, del cual él bebió, y sus hijos, y sus ganados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 13, 'Respondió Jesús y díjole: Cualquiera que bebiere de esta agua, volverá á tener sed;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 14, 'Mas el que bebiere del agua que yo le daré, para siempre no tendrá sed: mas el agua que yo le daré, será en él una fuente de agua que salte para vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 15, 'La mujer le dice: Señor, dame esta agua, para que no tenga sed, ni venga acá á sacar la.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 16, 'Jesús le dice: Ve, llama á tu marido, y ven acá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 17, 'Respondió la mujer, y dijo: No tengo marido. Dícele Jesús: Bien has dicho, No tengo marido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 18, 'Porque cinco maridos has tenido: y el que ahora tienes no es tu marido; esto has dicho con verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 19, 'Dícele la mujer: Señor, paréceme que tú eres profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 20, 'Nuestros padres adoraron en este monte, y vosotros decís que en Jerusalem es el lugar donde es necesario adorar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 21, 'Dícele Jesús: Mujer, créeme, que la hora viene, cuando ni en este monte, ni en Jerusalem adoraréis al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 22, 'Vosotros adoráis lo que no sabéis; nosotros adoramos lo que sabemos: porque la salud viene de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 23, 'Mas la hora viene, y ahora es, cuando los verdaderos adoradores adorarán al Padre en espíritu y en verdad; porque también el Padre tales adoradores busca que adoren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 24, 'Dios es Espíritu; y los que le adoran, en espíritu y en verdad es necesario que adoren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 25, 'Dícele la mujer: Sé que el Mesías ha de venir, el cual se dice el Cristo: cuando él viniere nos declarará todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 26, 'Dícele Jesús: Yo soy, que hablo contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 27, 'Y en esto vinieron sus discípulos, y maravilláronse de que hablaba con mujer; mas ninguno dijo: ¿Qué preguntas? ó, ¿Qué hablas con ella?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 28, 'Entonces la mujer dejó su cántaro, y fué á la ciudad, y dijo á aquellos hombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 29, 'Venid, ved un hombre que me ha dicho todo lo que he hecho: ¿si quizás es éste el Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 30, 'Entonces salieron de la ciudad, y vinieron á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 31, 'Entre tanto los discípulos le rogaban, diciendo: Rabbí, come.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 32, 'Y él les dijo: Yo tengo una comida que comer, que vosotros no sabéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 33, 'Entonces los discípulos decían el uno al otro: ¿Si le habrá traído alguien de comer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 34, 'Díceles Jesús: Mi comida es que haga la voluntad del que me envió, y que acabe su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 35, '¿No decís vosotros: Aun hay cuatro meses hasta que llegue la siega? He aquí os digo: Alzad vuestros ojos, y mirad las regiones, porque ya están blancas para la siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 36, 'Y el que siega, recibe salario, y allega fruto para vida eterna; para que el que siembra también goce, y el que siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 37, 'Porque en esto es el dicho verdadero: Que uno es el que siembra, y otro es el que siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 38, 'Yo os he enviado á segar lo que vosotros no labrasteis: otros labraron, y vosotros habéis entrado en sus labores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 39, 'Y muchos de los Samaritanos de aquella ciudad creyeron en él por la palabra de la mujer, que daba testimonio, diciendo: Que me dijo todo lo que he hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 40, 'Viniendo pues los Samaritanos á él, rogáronle que se quedase allí: y se quedó allí dos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 41, 'Y creyeron muchos más por la palabra de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 42, 'Y decían á la mujer: Ya no creemos por tu dicho; porque nosotros mismos hemos oído, y sabemos que verdaderamente éste es el Salvador del mundo, el Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 43, 'Y dos días después, salió de allí, y fuése á Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 44, 'Porque el mismo Jesús dió testimonio de que el profeta en su tierra no tiene honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 45, 'Y como vino á Galilea, los Galileos le recibieron, vistas todas las cosas que había hecho en Jerusalem en el día de la fiesta: porque también ellos habían ido á la fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 46, 'Vino pues Jesús otra vez á Caná de Galilea, donde había hecho el vino del agua. Y había en Capernaum uno del rey, cuyo hijo estaba enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 47, 'Este, como oyó que Jesús venía de Judea á Galilea, fué á él, y rogábale que descendiese, y sanase á su hijo, porque se comenzaba á morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 48, 'Entonces Jesús le dijo: Si no viereis señales y milagros no creeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 49, 'El del rey le dijo: Señor, desciende antes que mi hijo muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 50, 'Dícele Jesús: Ve, tu hijo vive. Y el hombre creyó á la palabra que Jesús le dijo, y se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 51, 'Y cuando ya él descendía, los siervos le salieron á recibir, y le dieron nuevas, diciendo: Tu hijo vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 52, 'Entonces él les preguntó á qué hora comenzó á estar mejor. Y dijéronle: Ayer á las siete le dejó la fiebre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 53, 'El padre entonces entendió, que aquella hora era cuando Jesús le dijo: Tu hijo vive; y creyó él y toda su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 4, 54, 'Esta segunda señal volvió Jesús á hacer, cuando vino de Judea á Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 1, 'DESPUÉS de estas cosas, era un día de fiesta de los Judíos, y subió Jesús á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 2, 'Y hay en Jerusalem á la puerta del ganado un estanque, que en hebraico es llamado Bethesda, el cual tiene cinco portales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 3, 'En éstos yacía multitud de enfermos, ciegos, cojos, secos, que estaban esperando el movimiento del agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 4, 'Porque un ángel descendía á cierto tiempo al estanque, y revolvía el agua; y el que primero descendía en el estanque después del movimiento del agua, era sano de cualquier enfermedad que tuviese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 5, 'Y estaba allí un hombre que había treinta y ocho años que estaba enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 6, 'Como Jesús vió á éste echado, y entendió que ya había mucho tiempo, dícele: ¿Quieres ser sano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 7, 'Señor, le respondió el enfermo, no tengo hombre que me meta en el estánque cuando el agua fuere revuelta; porque entre tanto que yo vengo, otro antes de mí ha descendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 8, 'Dícele Jesús: Levántate, toma tu lecho, y anda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 9, 'Y luego aquel hombre fué sano, y tomó su lecho, é íbase. Y era sábado aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 10, 'Entonces los Judíos decían á aquel que había sido sanado: Sábado es: no te es lícito llevar tu lecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 11, 'Respondióles: El que me sanó, él mismo me dijo: Toma tu lecho y anda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 12, 'Preguntáronle entonces: ¿Quién es el que te dijo: Toma tu lecho y anda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 13, 'Y el que había sido sanado, no sabía quién fuese; porque Jesús se había apartado de la gente que estaba en aquel lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 14, 'Después le halló Jesús en el templo, y díjole: He aquí, has sido sanado; no peques más, porque no te venga alguna cosa peor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 15, 'El se fué, y dió aviso á los Judíos, que Jesús era el que le había sanado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 16, 'Y por esta causa los Judíos perseguían á Jesús, y procuraban matarle, porque hacía estas cosas en sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 17, 'Y Jesús les respondió: Mi Padre hasta ahora obra, y yo obro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 18, 'Entonces, por tanto, más procuraban los Judíos matarle, porque no sólo quebrantaba el sábado, sino que también á su Padre llamaba Dios, haciéndose igual á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 19, 'Respondió entonces Jesús, y díjoles: De cierto, de cierto os digo: No puede el Hijo hacer nada de sí mismo, sino lo que viere hacer al Padre: porque todo lo que él hace, esto también hace el Hijo juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 20, 'Porque el Padre ama al Hijo, y le muestra todas las cosas que él hace; y mayores obras que éstas le mostrará, de suerte que vosotros os maravilléis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 21, 'Porque como el Padre levanta los muertos, y les da vida, así también el Hijo á los que quiere da vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 22, 'Porque el Padre á nadie juzga, mas todo el juicio dió al Hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 23, 'Para que todos honren al Hijo como honran al Padre. El que no honra al Hijo, no honra al Padre que le envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 24, 'De cierto, de cierto os digo: El que oye mi palabra, y cree al que me ha enviado, tiene vida eterna; y no vendrá á condenación, mas pasó de muerte á vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 25, 'De cierto, de cierto os digo: Vendrá hora, y ahora es, cuando los muertos oirán la voz del Hijo de Dios: y los que oyeren vivirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 26, 'Porque como el Padre tiene vida en sí mismo, así dió también al Hijo que tuviese vida en sí mismo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 27, 'Y también le dió poder de hacer juicio, en cuanto es el Hijo del hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 28, 'No os maravilléis de esto; porque vendrá hora, cuando todos los que están en los sepulcros oirán su voz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 29, 'Y los que hicieron bien, saldrán á resurrección de vida; mas los que hicieron mal, á resurrección de condenación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 30, 'No puedo yo de mí mismo hacer nada: como oigo, juzgo: y mi juicio es justo; porque no busco mi voluntad, mas la voluntad del que me envió, del Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 31, 'Si yo doy testimonio de mí mismo, mi testimonio no es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 32, 'Otro es el que da testimonio de mí; y sé que el testimonio que da de mí, es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 33, 'Vosotros enviasteis á Juan, y él dió testimonio á la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 34, 'Empero yo no tomo el testimonio de hombre; mas digo esto, para que vosotros seáis salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 35, 'El era antorcha que ardía y alumbraba: y vosotros quisisteis recrearos por un poco á su luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 36, 'Mas yo tengo mayor testimonio que el de Juan: porque las obras que el Padre me dió que cumpliese, las mismas obras que yo hago, dan testimonio de mí, que el Padre me haya enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 37, 'Y el que me envió, el Padre, él ha dado testimonio de mí. Ni nunca habéis oído su voz, ni habéis visto su parecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 38, 'Ni tenéis su palabra permanente en vosotros; porque al que él envió, á éste vosotros no creéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 39, 'Escudriñad las Escrituras, porque á vosotros os parece que en ellas tenéis la vida eterna; y ellas son las que dan testimonio de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 40, 'Y no queréis venir á mí, para que tengáis vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 41, 'Gloria de los hombres no recibo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 42, 'Mas yo os conozco, que no tenéis amor de Dios en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 43, 'Yo he venido en nombre de mi Padre, y no me recibís: si otro viniere en su propio nombre, á aquél recibiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 44, '¿Cómo podéis vosotros creer, pues tomáis la gloria los unos de los otros, y no buscáis la gloria que de sólo Dios viene?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 45, 'No penséis que yo os tengo de acusar delante del Padre; hay quien os acusa, Moisés, en quien vosotros esperáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 46, 'Porque si vosotros creyeseis á Moisés, creeríais á mí; porque de mí escribió él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 5, 47, 'Y si á sus escritos no creéis, ¿cómo creeréis á mis palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 1, 'PASADAS estas cosas, fuése Jesús de la otra parte de la mar de Galilea, que es de Tiberias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 2, 'Y seguíale grande multitud, porque veían sus señales que hacía en los enfermos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 3, 'Y subió Jesús á un monte, y se sentó allí con sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 4, 'Y estaba cerca la Pascua, la fiesta de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 5, 'Y como alzó Jesús los ojos, y vió que había venido á él grande multitud, dice á Felipe: ¿De dónde compraremos pan para que coman éstos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 6, 'Mas esto decía para probarle; porque él sabía lo que había de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 7, 'Respondióle Felipe: Doscientos denarios de pan no les bastarán, para que cada uno de ellos tome un poco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 8, 'Dícele uno de sus discípulos, Andrés, hermano de Simón Pedro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 9, 'Un muchacho está aquí que tiene cinco panes de cebada y dos pececillos; ¿mas qué es esto entre tantos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 10, 'Entonces Jesús dijo: Haced recostar la gente. Y había mucha hierba en aquel lugar: y recostáronse como número de cinco mil varones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 11, 'Y tomó Jesús aquellos panes, y habiendo dado gracias, repartió á los discípulos, y los discípulos á los que estaban recostados: asimismo de los peces, cuanto querían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 12, 'Y como fueron saciados, dijo á sus discípulos: Recoged los pedazos que han quedado, porque no se pierda nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 13, 'Cogieron pues, é hinchieron doce cestas de pedazos de los cinco panes de cebada, que sobraron á los que habían comido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 14, 'Aquellos hombres entonces, como vieron la señal que Jesús había hecho, decían: Este verdaderamente es el profeta que había de venir al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 15, 'Y entendiendo Jesús que habían de venir para arrebatarle, y hacerle rey, volvió á retirarse al monte, él solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 16, 'Y como se hizo tarde, descendieron sus discípulos á la mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 17, 'Y entrando en un barco, venían de la otra parte de la mar hacia Capernaum. Y era ya oscuro, y Jesús no había venido á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 18, 'Y levantábase la mar con un gran viento que soplaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 19, 'Y como hubieron navegado como veinticinco ó treinta estadios, ven á Jesús que andaba sobre la mar, y se acercaba al barco: y tuvieron miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 20, 'Mas él les dijo: Yo soy; no tengáis miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 21, 'Ellos entonces gustaron recibirle en el barco: y luego el barco llegó á la tierra donde iban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 22, 'El día siguiente, la gente que estaba de la otra parte de la mar, como vió que no había allí otra navecilla sino una, y que Jesús no había entrado con sus discípulos en ella, sino que sus discípulos se habían ido solos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 23, 'Y que otras navecillas habían arribado de Tiberias junto al lugar donde habían comido el pan después de haber el Señor dado gracias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 24, 'Como vió pues la gente que Jesús no estaba allí, ni sus discípulos, entraron ellos en las navecillas, y vinieron á Capernaum buscando á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 25, 'Y hallándole de la otra parte de la mar, dijéronle: Rabbí, ¿cuándo llegaste acá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 26, 'Respondióles Jesús, y dijo; De cierto, de cierto os digo, que me buscáis, no porque habéis visto las señales, sino porque comisteis el pan y os hartasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 27, 'Trabajad no por la comida que perece, mas por la comida que á vida eterna permanece, la cual el Hijo del hombre os dará: porque á éste señaló el Padre, que es Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 28, 'Y dijéronle: ¿Qué haremos para que obremos las obras de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 29, 'Respondió Jesús, y díjoles: Esta es la obra de Dios, que creáis en el que él ha enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 30, 'Dijéronle entonces: ¿Qué señal pues haces tú, para que veamos, y te creamos? ¿Qué obras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 31, 'Nuestros padres comieron el maná en el desierto, como está escrito: Pan del cielo les dió á comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 32, 'Y Jesús les dijo: De cierto, de cierto os digo: No os dió Moisés pan del cielo; mas mi Padre os da el verdadero pan del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 33, 'Porque el pan de Dios es aquel que descendió del cielo y da vida al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 34, 'Y dijéronle: Señor, danos siempre este pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 35, 'Y Jesús les dijo: Yo soy el pan de vida: el que á mí viene, nunca tendrá hambre; y el que en mí cree, no tendrá sed jamás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 36, 'Mas os he dicho, que aunque me habéis visto, no creéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 37, 'Todo lo que el Padre me da, vendrá á mí; y al que á mí viene, no le hecho fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 38, 'Porque he descendido del cielo, no para hacer mi voluntad, mas la voluntad del que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 39, 'Y esta es la voluntad del que me envió, del Padre: Que todo lo que me diere, no pierda de ello, sino que lo resucite en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 40, 'Y esta es la voluntad del que me ha enviado: Que todo aquel que ve al Hijo, y cree en él, tenga vida eterna: y yo le resucitaré en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 41, 'Murmuraban entonces de él los Judíos, porque había dicho: Yo soy el pan que descendí del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 42, 'Y decían: ¿No es éste Jesús, el hijo de José, cuyo padre y madre nosotros conocemos? ¿cómo, pues, dice éste: Del cielo he descendido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 43, 'Y Jesús respondió, y díjoles: No murmuréis entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 44, 'Ninguno puede venir á mí, si el Padre que me envió no le trajere; y yo le resucitaré en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 45, 'Escrito está en los profetas: Y serán todos enseñados de Dios. Así que, todo aquel que oyó del Padre, y aprendió, viene á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 46, 'No que alguno haya visto al Padre, sino aquel que vino de Dios, éste ha visto al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 47, 'De cierto, de cierto os digo: El que cree en mí, tiene vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 48, 'Yo soy el pan de vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 49, 'Vuestros padres comieron el maná en el desierto, y son muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 50, 'Este es el pan que desciende del cielo, para que el que de él comiere, no muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 51, 'Yo soy el pan vivo que he descendido del cielo: si alguno comiere de este pan, vivirá para siempre; y el pan que yo daré es mi carne, la cual yo daré por la vida del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 52, 'Entonces los Judíos contendían entre sí, diciendo: ¿Cómo puede éste darnos su carne á comer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 53, 'Y Jesús les dijo: De cierto, de cierto os digo: Si no comiereis la carne del Hijo del hombre, y bebiereis su sangre, no tendréis vida en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 54, 'El que come mi carne y bebe mi sangre, tiene vida eterna: y yo le resucitaré en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 55, 'Porque mi carne es verdadera comida, y mi sangre es verdadera bebida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 56, 'El que come mi carne y bebe mi sangre, en mí permanece, y yo en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 57, 'Como me envió el Padre viviente, y yo vivo por el Padre, asimismo el que me come, él también vivirá por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 58, 'Este es el pan que descendió del cielo: no como vuestros padres comieron el maná, y son muertos: el que come de este pan, vivirá eternamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 59, 'Estas cosas dijo en la sinagoga, enseñando en Capernaum.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 60, 'Y muchos de sus discípulos oyéndo lo, dijeron: Dura es esta palabra: ¿quién la puede oir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 61, 'Y sabiendo Jesús en sí mismo que sus discípulos murmuraban de esto, díjoles: ¿Esto os escandaliza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 62, '¿Pues qué, si viereis al Hijo del hombre que sube donde estaba primero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 63, 'El espíritu es el que da vida; la carne nada aprovecha: las palabras que yo os he hablado, son espíritu y son vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 64, 'Mas hay algunos de vosotros que no creen. Porque Jesús desde el principio sabía quiénes eran los que no creían, y quién le había de entregar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 65, 'Y dijo: Por eso os he dicho que ninguno puede venir á mí, si no le fuere dado del Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 66, 'Desde esto, muchos de sus discípulos volvieron atrás, y ya no andaban con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 67, 'Dijo entonces Jesús á los doce: ¿Queréis vosotros iros también?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 68, 'Y respondióle Simón Pedro: Señor, ¿á quién iremos? tú tienes palabras de vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 69, 'Y nosotros creemos y conocemos que tú eres el Cristo, el Hijo de Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 70, 'Jesús le respondió: ¿No he escogido yo á vosotros doce, y uno de vosotros es diablo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 6, 71, 'Y hablaba de Judas Iscariote, hijo de Simón, porque éste era el que le había de entregar, el cual era uno de los doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 1, 'Y PASADAS estas cosas andaba Jesús en Galilea: que no quería andar en Judea, porque los Judíos procuraban matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 2, 'Y estaba cerca la fiesta de los Judíos, la de los tabernáculos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 3, 'Y dijéronle sus hermanos: Pásate de aquí, y vete á Judea, para que también tus discípulos vean las obras que haces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 4, 'Que ninguno que procura ser claro, hace algo en oculto. Si estas cosas haces, manifiéstate al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 5, 'Porque ni aun sus hermanos creían en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 6, 'Díceles entonces Jesús: Mi tiempo aun no ha venido; mas vuestro tiempo siempre está presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 7, 'No puede el mundo aborreceros á vosotros; mas á mí me aborrece, porque yo doy testimonio de él, que sus obras son malas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 8, 'Vosotros subid á esta fiesta; yo no subo aún á esta fiesta, porque mi tiempo aun no es cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 9, 'Y habiéndoles dicho esto, quedóse en Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 10, 'Mas como sus hermanos hubieron subido, entonces él también subió á la fiesta, no manifiestamente, sino como en secreto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 11, 'Y buscábanle los Judíos en la fiesta, y decían: ¿Dónde está aquél?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 12, 'Y había grande murmullo de él entre la gente: porque unos decían: Bueno es; y otros decían: No, antes engaña á las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 13, 'Mas ninguno hablaba abiertamente de él, por miedo de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 14, 'Y al medio de la fiesta subió Jesús al templo, y enseñaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 15, 'y maravillábanse los Judíos, diciendo: ¿Cómo sabe éste letras, no habiendo aprendido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 16, 'Respondióles Jesús, y dijo: Mi doctrina no es mía, sino de aquél que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 17, 'El que quisiere hacer su voluntad, conocerá de la doctrina si viene de Dios, ó si yo hablo de mí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 18, 'El que habla de sí mismo, su propia gloria busca; mas el que busca la gloria del que le envió, éste es verdadero, y no hay en él injusticia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 19, '¿No os dió Moisés la ley, y ninguno de vosotros hace la ley? ¿Por qué me procuráis matar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 20, 'Respondió la gente, y dijo: Demonio tienes: ¿quién te procura matar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 21, 'Jesús respondió, y díjoles: Una obra hice, y todos os maravilláis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 22, 'Cierto, Moisés os dió la circuncisión (no porque sea de Moisés, mas de los padres); y en sábado circuncidáis al hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 23, 'Si recibe el hombre la circuncisión en sábado, para que la ley de Moisés no sea quebrantada, ¿os enojáis conmigo porque en sábado hice sano todo un hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 24, 'No juzguéis según lo que parece, mas juzgad justo juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 25, 'Decían entonces unos de los de Jerusalem: ¿No es éste al que buscan para matarlo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 26, 'Y he aquí, habla públicamente, y no le dicen nada; ¿si habrán entendido verdaderamente los príncipes, que éste es el Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 27, 'Mas éste, sabemos de dónde es: y cuando viniere el Cristo, nadie sabrá de dónde sea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 28, 'Entonces clamaba Jesús en el templo, enseñando y diciendo: Y á mí me conocéis, y sabéis de dónde soy: y no he venido de mí mismo; mas el que me envió es verdadero, al cual vosotros no conocéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 29, 'Yo le conozco, porque de él soy, y él me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 30, 'Entonces procuraban prenderle; mas ninguno puso en él mano, porque aun no había venido su hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 31, 'Y muchos del pueblo creyeron en él, y decían: El Cristo, cuando viniere, ¿hará más señales que las que éste hace?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 32, 'Los Fariseos oyeron á la gente que murmuraba de él estas cosas; y los príncipes de los sacerdotes y los Fariseos enviaron servidores que le prendiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 33, 'Y Jesús dijo: Aun un poco de tiempo estaré con vosotros, é iré al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 34, 'Me buscaréis, y no me hallaréis; y donde yo estaré, vosotros no podréis venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 35, 'Entonces los Judíos dijeron entre sí: ¿A dónde se ha de ir éste que no le hallemos? ¿Se ha de ir á los esparcidos entre los Griegos, y á enseñar á los Griegos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 36, '¿Qué dicho es éste que dijo: Me buscaréis, y no me hallaréis; y donde yo estaré, vosotros no podréis venir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 37, 'Mas en el postrer día grande de la fiesta, Jesús se ponía en pie y clamaba, diciendo: Si alguno tiene sed, venga á mí y beba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 38, 'El que cree en mí, como dice la Escritura, ríos de agua viva correrán de su vientre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 39, '(Y esto dijo del Espíritu que habían de recibir los que creyesen en él: pues aun no había venido el Espíritu Santo; porque Jesús no estaba aún glorificado.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 40, 'Entonces algunos de la multitud, oyendo este dicho, decían: Verdaderamente éste es el profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 41, 'Otros decían: Este es el Cristo. Algunos empero decían: ¿De Galilea ha de venir el Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 42, '¿No dice la Escritura, que de la simiente de David, y de la aldea de Bethlehem, de donde era David, vendrá el Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 43, 'Así que había disensión entre la gente acerca de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 44, 'Y algunos de ellos querían prenderle; mas ninguno echó sobre él manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 45, 'Y los ministriles vinieron á los principales sacerdotes y á los Fariseos; y ellos les dijeron: ¿Por qué no le trajisteis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 46, 'Los ministriles respondieron: Nunca ha hablado hombre así como este hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 47, 'Entonces los Fariseos les respondieron: ¿Estáis también vosotros engañados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 48, '¿Ha creído en él alguno de los príncipes, ó de los Fariseos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 49, 'Mas estos comunales que no saben la ley, malditos son.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 50, 'Díceles Nicodemo (el que vino á él de noche, el cual era uno de ellos):');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 51, '¿Juzga nuestra ley á hombre, si primero no oyere de él, y entendiere lo que ha hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 52, 'Respondieron y dijéronle: ¿Eres tú también Galileo? Escudriña y ve que de Galilea nunca se levantó profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 7, 53, 'Y fuése cada uno á su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 1, 'Y JESUS se fué al monte de las Olivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 2, 'Y por la mañana volvió al templo, y todo el pueblo vino á él: y sentado él, los enseñaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 3, 'Entonces los escribas y los Fariseos le traen una mujer tomada en adulterio; y poniéndola en medio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 4, 'Dícenle: Maestro, esta mujer ha sido tomada en el mismo hecho, adulterando;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 5, 'Y en la ley Moisés nos mandó apedrear á las tales: tú pues, ¿qué dices?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 6, 'Mas esto decían tentándole, para poder acusarle. Empero Jesús, inclinado hacia abajo, escribía en tierra con el dedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 7, 'Y como perseverasen preguntándole, enderezóse, y díjoles: El que de vosotros esté sin pecado, arroje contra ella la piedra el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 8, 'Y volviéndose á inclinar hacia abajo, escribía en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 9, 'Oyendo, pues, ellos, redargüidos de la conciencia, salíanse uno á uno, comenzando desde los más viejos hasta los postreros: y quedó solo Jesús, y la mujer que estaba en medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 10, 'Y enderezándose Jesús, y no viendo á nadie más que á la mujer, díjole: ¿Mujer, dónde están los que te acusaban? ¿Ninguno te ha condenado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 11, 'Y ella dijo: Señor, ninguno. Entonces Jesús le dijo: Ni yo te condeno: vete, y no peques más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 12, 'Y hablóles Jesús otra vez, diciendo: Yo soy la luz del mundo: el que me sigue, no andará en tinieblas, mas tendrá la lumbre de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 13, 'Entonces los Fariseos le dijeron: Tú de ti mismo das testimonio: tu testimonio no es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 14, 'Respondió Jesús, y díjoles: Aunque yo doy testimonio de mí mismo, mi testimonio es verdadero, porque sé de dónde he venido y á dónde voy; mas vosotros no sabéis de dónde vengo, y á dónde voy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 15, 'Vosotros según la carne juzgáis; mas yo no juzgo á nadie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 16, 'Y si yo juzgo, mi juicio es verdadero; porque no soy solo, sino yo y el que me envió, el Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 17, 'Y en vuestra ley está escrito que el testimonio de dos hombres es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 18, 'Yo soy el que doy testimonio de mí mismo: y da testimonio de mí el que me envió, el Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 19, 'Y decíanle: ¿Dónde está tu Padre? Respondió Jesús: Ni á mí me conocéis, ni á mi Padre; si á mí me conocieseis, á mi Padre también conocierais.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 20, 'Estas palabras habló Jesús en el lugar de las limosnas, enseñando en el templo: y nadie le prendió; porque aun no había venido su hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 21, 'Y díjoles otra vez Jesús: Yo me voy, y me buscaréis, mas en vuestro pecado moriréis: á donde yo voy, vosotros no podéis venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 22, 'Decían entonces los Judíos: ¿Hase de matar á sí mismo, que dice: A donde yo voy, vosotros no podéis venir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 23, 'Y decíales: Vosotros sois de abajo, yo soy de arriba; vosotros sois de este mundo, yo no soy de este mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 24, 'Por eso os dije que moriréis en vuestros pecados: porque si no creyereis que yo soy, en vuestros pecados moriréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 25, 'Y decíanle: ¿Tú quién eres? Entonces Jesús les dijo: El que al principio también os he dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 26, 'Muchas cosas tengo que decir y juzgar de vosotros: mas el que me envió, es verdadero: y yo, lo que he oído de él, esto hablo en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 27, 'Mas no entendieron que él les hablaba del Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 28, 'Díjoles pues, Jesús: Cuando levantareis al Hijo del hombre, entonces entenderéis que yo soy, y que nada hago de mí mismo; mas como el Padre me enseñó, esto hablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 29, 'Porque el que me envió, conmigo está; no me ha dejado solo el Padre; porque yo, lo que á él agrada, hago siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 30, 'Hablando él estas cosas, muchos creyeron en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 31, 'Y decía Jesús á los Judíos que le habían creído: Si vosotros permaneciereis en mi palabra, seréis verdaderamente mis discípulos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 32, 'Y conoceréis la verdad, y la verdad os libertará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 33, 'Y respondiéronle: Simiente de Abraham somos, y jamás servimos á nadie: ¿cómo dices tú: Seréis libres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 34, 'Jesús les respondió: De cierto, de cierto os digo, que todo aquel que hace pecado, es siervo de pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 35, 'Y el siervo no queda en casa para siempre: el hijo queda para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 36, 'Así que, si el Hijo os libertare, seréis verdaderamente libres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 37, 'Sé que sois simiente de Abraham, mas procuráis matarme, porque mi palabra no cabe en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 38, 'Yo hablo lo que he visto cerca del Padre; y vosotros hacéis lo que habéis oído cerca de vuestro padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 39, 'Respondieron y dijéronle: Nuestro padre es Abraham. Díceles Jesús: Si fuerais hijos de Abraham, las obras de Abraham harías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 40, 'Empero ahora procuráis matarme, hombre que os he hablado la verdad, la cual he oído de Dios: no hizo esto Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 41, 'Vosotros hacéis las obras de vuestro padre. Dijéronle entonces: Nosotros no somos nacidos de fornicación; un padre tenemos, que es Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 42, 'Jesús entonces les dijo: Si vuestro padre fuera Dios, ciertamente me amaríais: porque yo de Dios he salido, y he venido; que no he venido de mí mismo, mas él me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 43, '¿Por qué no reconocéis mi lenguaje? porque no podéis oir mi palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 44, 'Vosotros de vuestro padre el diablo sois, y los deseos de vuestro padre queréis cumplir. Él, homicida ha sido desde el principio, y no permaneció en la verdad, porque no hay verdad en él. Cuando habla mentira, de suyo habla; porque es mentiroso, y padre de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 45, 'Y porque yo digo verdad, no me creéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 46, '¿Quién de vosotros me redarguye de pecado? Pues si digo verdad, ¿por qué vosotros no me creéis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 47, 'El que es de Dios, las palabras de Dios oye: por esto no las oís vosotros, porque no sois de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 48, 'Respondieron entonces los Judíos, y dijéronle: ¿No decimos bien nosotros, que tú eres Samaritano, y tienes demonio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 49, 'Respondió Jesús: Yo no tengo demonio, antes honro á mi Padre; y vosotros me habéis deshonrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 50, 'Y no busco mi gloria: hay quien la busque, y juzgue.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 51, 'De cierto, de cierto os digo, que el que guardare mi palabra, no verá muerte para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 52, 'Entonces los Judíos le dijeron: Ahora conocemos que tienes demonio. Abraham murió, y los profetas, y tú dices: El que guardare mi palabra, no gustará muerte para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 53, '¿Eres tú mayor que nuestro padre Abraham, el cual murió? y los profetas murieron: ¿quién te haces á ti mismo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 54, 'Respondió Jesús: Si yo me glorifico á mí mismo, mi gloria es nada: mi Padre es el que me glorifica; el que vosotros decís que es vuestro Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 55, 'Y no le conocéis: mas yo le conozco; y si dijere que no le conozco, seré como vosotros mentiroso: mas le conozco, y guardo su palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 56, 'Abraham vuestro padre se gozó por ver mi día; y lo vió, y se gozó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 57, 'Dijéronle entonces los Judíos: Aun no tienes cincuenta años, ¿y has visto á Abraham?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 58, 'Díjoles Jesús: De cierto, de cierto os digo: Antes que Abraham fuese, yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 8, 59, 'Tomaron entonces piedras para tirarle: mas Jesús se encubrió, y salió del templo; y atravesando por medio de ellos, se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 1, 'Y PASANDO Jesús, vió un hombre ciego desde su nacimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 2, 'Y preguntáronle sus discípulos, diciendo: Rabbí, ¿quién pecó, éste ó sus padres, para que naciese ciego?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 3, 'Respondió Jesús: Ni éste pecó, ni sus padres: mas para que las obras de Dios se manifiesten en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 4, 'Conviéneme obrar las obrar del que me envió, entre tanto que el día dura: la noche viene, cuando nadie puede obrar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 5, 'Entre tanto que estuviere en el mundo, luz soy del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 6, 'Esto dicho, escupió en tierra, é hizo lodo con la saliva, y untó con el lodo sobre los ojos del ciego,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 7, 'Y díjole: Ve, lávate en el estanque de Siloé (que significa, si lo interpretares, Enviado). Y fué entonces, y lavóse, y volvió viendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 8, 'Entonces los vecinos, y los que antes le habían visto que era ciego, decían: ¿no es éste el que se sentaba y mendigaba?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 9, 'Unos decían: Este es; y otros: A él se parece. El decía: Yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 10, 'Y dijéronle: ¿Cómo te fueron abiertos los ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 11, 'Respondió él y dijo: El hombre que se llama Jesús, hizo lodo, y me untó los ojos, y me dijo: Ve al Siloé, y lávate: y fuí, y me lavé, y recibí la vista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 12, 'Entonces le dijeron: ¿Dónde está aquél? El dijo: No sé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 13, 'Llevaron á los Fariseos al que antes había sido ciego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 14, 'Y era sábado cuando Jesús había hecho el lodo, y le había abierto los ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 15, 'Y volviéronle á preguntar también los Fariseos de qué manera había recibido la vista. Y él les dijo: Púsome lodo sobre los ojos, y me lavé, y veo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 16, 'Entonces unos de los Fariseos decían: Este hombre no es de Dios, que no guarda el sábado. Otros decían: ¿Cómo puede un hombre pecador hacer estas señales? Y había disensión entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 17, 'Vuelven á decir al ciego: ¿Tú, qué dices del que te abrió los ojos? Y él dijo: Que es profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 18, 'Mas los Judíos no creían de él, que había sido ciego, y hubiese recibido la vista, hasta que llamaron á los padres del que había recibido la vista;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 19, 'Y preguntáronles, diciendo: ¿Es éste vuestro hijo, el que vosotros decís que nació ciego? ¿Cómo, pues, ve ahora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 20, 'Respondiéronles sus padres y dijeron: Sabemos que éste es nuestro hijo, y que nació ciego:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 21, 'Mas cómo vea ahora, no sabemos; ó quién le haya abierto los ojos, nosotros no lo sabemos; él tiene edad, preguntadle á él; él hablará de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 22, 'Esto dijeron sus padres, porque tenían miedo de los Judíos: porque ya los Judíos habían resuelto que si alguno confesase ser él el Mesías, fuese fuera de la sinagoga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 23, 'Por eso dijeron sus padres: Edad tiene, preguntadle á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 24, 'Así que, volvieron á llamar al hombre que había sido ciego, y dijéronle: Da gloria á Dios: nosotros sabemos que este hombre es pecador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 25, 'Entonces él respondió, y dijo: Si es pecador, no lo sé: una cosa sé, que habiendo yo sido ciego, ahora veo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 26, 'Y volviéronle á decir: ¿Qué te hizo? ¿Cómo te abrió los ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 27, 'Respondióles: Ya os lo he dicho, y no habéis atendido: ¿por qué lo queréis otra vez oir? ¿queréis también vosotros haceros sus discípulos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 28, 'Y le ultrajaron, y dijeron: Tú eres su discípulo; pero nosotros discípulos de Moisés somos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 29, 'Nosotros sabemos que á Moisés habló Dios: mas éste no sabemos de dónde es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 30, 'Respondió aquel hombre, y díjoles: Por cierto, maravillosa cosa es ésta, que vosotros no sabéis de dónde sea, y á mí me abrió los ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 31, 'Y sabemos que Dios no oye á los pecadores: mas si alguno es temeroso de Dios, y hace su voluntad, á éste oye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 32, 'Desde el siglo no fué oído, que abriese alguno los ojos de uno que nació ciego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 33, 'Si éste no fuera de Dios, no pudiera hacer nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 34, 'Respondieron, y dijéronle: En pecados eres nacido todo, ¿y tú nos enseñas? Y echáronle fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 35, 'Oyó Jesús que le habían echado fuera; y hallándole, díjole: ¿Crees tú en el Hijo de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 36, 'Respondió él, y dijo: ¿Quién es, Señor, para que crea en él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 37, 'Y díjole Jesús: Y le has visto, y el que habla contigo, él es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 38, 'Y él dice: Creo, Señor; y adoróle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 39, 'Y dijo Jesús: Yo, para juicio he venido á este mundo: para que los que no ven, vean; y los que ven, sean cegados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 40, 'Y ciertos de los Fariseos que estaban con él oyeron esto, y dijéronle: ¿Somos nosotros también ciegos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 9, 41, 'Díjoles Jesús: Si fuerais ciegos, no tuvierais pecado: mas ahora porque decís, Vemos, por tanto vuestro pecado permanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 1, 'DE cierto, de cierto os digo: El que no entra por la puerta en el corral de las ovejas, mas sube por otra parte, el tal es ladrón y robador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 2, 'Mas el que entra por la puerta, el pastor de las ovejas es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 3, 'A éste abre el portero, y las ovejas oyen su voz: y á sus ovejas llama por nombre, y las saca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 4, 'Y como ha sacado fuera todas las propias, va delante de ellas; y las ovejas le siguen, porque conocen su voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 5, 'Mas al extraño no seguirán, antes huirán de él: porque no conocen la voz de los extraños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 6, 'Esta parábola les dijo Jesús; mas ellos no entendieron qué era lo que les decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 7, 'Volvióles, pues, Jesús á decir: De cierto, de cierto os digo: Yo soy la puerta de las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 8, 'Todos los que antes de mí vinieron, ladrones son y robadores; mas no los oyeron las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 9, 'Yo soy la puerta: el que por mí entrare, será salvo; y entrará, y saldrá, y hallará pastos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 10, 'El ladrón no viene sino para hurtar, y matar, y destruir: yo he venido para que tengan vida, y para que la tengan en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 11, 'Yo soy el buen pastor: el buen pastor su vida da por las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 12, 'Mas el asalariado, y que no es el pastor, de quien no son propias las ovejas, ve al lobo que viene, y deja las ovejas, y huye, y el lobo las arrebata, y esparce las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 13, 'Así que, el asalariado, huye, porque es asalariado, y no tiene cuidado de las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 14, 'Yo soy el buen pastor; y conozco mis ovejas, y las mías me conocen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 15, 'Como el Padre me conoce, y yo conozco al Padre; y pongo mi vida por las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 16, 'También tengo otras ovejas que no son de este redil; aquéllas también me conviene traer, y oirán mi voz; y habrá un rebaño, y un pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 17, 'Por eso me ama el Padre, porque yo pongo mi vida, para volverla á tomar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 18, 'Nadie me la quita, mas yo la pongo de mí mismo. Tengo poder para ponerla, y tengo poder para volverla á tomar. Este mandamiento recibí de mi Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 19, 'Y volvió á haber disensión entre los Judíos por estas palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 20, 'Y muchos de ellos decían: Demonio tiene, y está fuera de sí; ¿para qué le oís?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 21, 'Decían otros: Estas palabras no son de endemoniado: ¿puede el demonio abrir los ojos de los ciegos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 22, 'Y se hacía la fiesta de la dedicación en Jerusalem; y era invierno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 23, 'Y Jesús andaba en el templo por el portal de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 24, 'Y rodeáronle los Judíos y dijéronle: ¿Hasta cuándo nos has de turbar el alma? Si tú eres el Cristo, dínos lo abiertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 25, 'Respondióles Jesús: Os lo he dicho, y no creéis: las obras que yo hago en nombre de mi Padre, ellas dan testimonio de mí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 26, 'Mas vosotros no creéis, porque no sois de mis ovejas, como os he dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 27, 'Mis ovejas oyen mi voz, y yo las conozco, y me siguen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 28, 'Y yo les doy vida eterna y no perecerán para siempre, ni nadie las arrebatará de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 29, 'Mi Padre que me las dió, mayor que todos es y nadie las puede arrebatar de la mano de mi Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 30, 'Yo y el Padre una cosa somos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 31, 'Entonces volvieron á tomar piedras los Judíos para apedrearle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 32, 'Respondióles Jesús: Muchas buenas obras os he mostrado de mi Padre, ¿por cuál obra de esas me apedreáis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 33, 'Respondiéronle los Judíos, diciendo: Por buena obra no te apedreamos, sino por la blasfemia; y porque tú, siendo hombre, te haces Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 34, 'Respondióles Jesús: ¿No está escrito en vuestra ley: Yo dije, Dioses sois?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 35, 'Si dijo, dioses, á aquellos á los cuales fué hecha palabra de Dios (y la Escritura no puede ser quebrantada);');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 36, '¿A quien el Padre santificó y envió al mundo, vosotros decís: Tú blasfemas, porque dije: Hijo de Dios soy?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 37, 'Si no hago obras de mi Padre, no me creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 38, 'Mas si las hago, aunque á mí no creáis, creed á las obras; para que conozcáis y creáis que el Padre está en mí, y yo en el Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 39, 'Y procuraban otra vez prenderle; mas él se salió de sus manos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 40, 'Y volvióse tras el Jordán, á aquel lugar donde primero había estado bautizando Juan; y estúvose allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 41, 'Y muchos venían á él, y decían: Juan, á la verdad, ninguna señal hizo; mas todo lo que Juan dijo de éste, era verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 10, 42, 'Y muchos creyeron allí en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 1, 'ESTABA entonces enfermo uno llamado Lázaro, de Bethania, la aldea de María y de Marta su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 2, '(Y María, cuyo hermano Lázaro estaba enfermo, era la que ungió al Señor con ungüento, y limpió sus pies con sus cabellos)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 3, 'Enviaron, pues, sus hermanas á él, diciendo: Señor, he aquí, el que amas está enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 4, 'Y oyéndolo Jesús, dijo: Esta enfermedad no es para muerte, mas por gloria de Dios, para que el Hijo de Dios sea glorificado por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 5, 'Y amaba Jesús á Marta, y á su hermana, y á Lázaro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 6, 'Como oyó pues que estaba enfermo, quedóse aún dos días en aquel lugar donde estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 7, 'Luego, después de esto, dijo á los discípulos: Vamos á Judea otra vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 8, 'Dícenle los discípulos: Rabbí, ahora procuraban los Judíos apedrearte, ¿y otra vez vas allá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 9, 'Respondió Jesús: ¿No tiene el día doce horas? El que anduviere de día, no tropieza, porque ve la luz de este mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 10, 'Mas el que anduviere de noche, tropieza, porque no hay luz en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 11, 'Dicho esto, díceles después: Lázaro nuestro amigo duerme; mas voy á despertarle del sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 12, 'Dijeron entonces sus discípulos: Señor, si duerme, salvo estará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 13, 'Mas esto decía Jesús de la muerte de él: y ellos pensaron que hablaba del reposar del sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 14, 'Entonces, pues, Jesús les dijo claramente: Lázaro es muerto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 15, 'Y huélgome por vosotros, que yo no haya estado allí, para que creáis: mas vamos á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 16, 'Dijo entonces Tomás, el que se dice el Dídimo, á sus condiscípulos: Vamos también nosotros, para que muramos con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 17, 'Vino pues Jesús, y halló que había ya cuatro días que estaba en el sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 18, 'Y Bethania estaba cerca de Jerusalem, como quince estadios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 19, 'Y muchos de los Judíos habían venido á Marta y á María, á consolarlas de su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 20, 'Entonces Marta, como oyó que Jesús venía, salió á encontrarle; mas María se estuvo en casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 21, 'Y Marta dijo á Jesús: Señor, si hubieses estado aquí, mi hermano no fuera muerto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 22, 'Mas también sé ahora, que todo lo que pidieres de Dios, te dará Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 23, 'Dícele Jesús: Resucitará tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 24, 'Marta le dice: Yo sé que resucitará en la resurrección en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 25, 'Dícele Jesús: Yo soy la resurrección y la vida: el que cree en mí, aunque esté muerto, vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 26, 'Y todo aquel que vive y cree en mí, no morirá eternamente. ¿Crees esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 27, 'Dícele: Sí Señor; yo he creído que tú eres el Cristo, el Hijo de Dios, que has venido al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 28, 'Y esto dicho, fuése, y llamó en secreto á María su hermana, diciendo: El Maestro está aquí y te llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 29, 'Ella, como lo oyó, levántase prestamente y viene á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 30, '(Que aun no había llegado Jesús á la aldea, mas estaba en aquel lugar donde Marta le había encontrado.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 31, 'Entonces los Judíos que estaban en casa con ella, y la consolaban, como vieron que María se había levantado prestamente, y había salido, siguiéronla, diciendo: Va al sepulcro á llorar allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 32, 'Mas María, como vino donde estaba Jesús, viéndole, derribóse á sus pies, diciéndole: Señor, si hubieras estado aquí, no fuera muerto mi hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 33, 'Jesús entonces, como la vió llorando, y á los Judíos que habían venido juntamente con ella llorando, se conmovió en espíritu, y turbóse,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 34, 'Y dijo: ¿Dónde le pusisteis? Dicenle: Señor, ven, y ve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 35, 'Y lloró Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 36, 'Dijeron entonces los Judíos: Mirad cómo le amaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 37, 'Y algunos de ellos dijeron: ¿No podía éste que abrió los ojos al ciego, hacer que éste no muriera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 38, 'Y Jesús, conmoviéndose otra vez en sí mismo, vino al sepulcro. Era una cueva, la cual tenía una piedra encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 39, 'Dice Jesús: Quitad la piedra. Marta, la hermana del que se había muerto, le dice: Señor, hiede ya, que es de cuatro días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 40, 'Jesús le dice: ¿No te he dicho que, si creyeres, verás la gloria de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 41, 'Entonces quitaron la piedra de donde el muerto había sido puesto. Y Jesús, alzando los ojos arriba, dijo: Padre, gracias te doy que me has oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 42, 'Que yo sabía que siempre me oyes; mas por causa de la compañía que está alrededor, lo dije, para que crean que tú me has enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 43, 'Y habiendo dicho estas cosas, clamó á gran voz: Lázaro, ven fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 44, 'Y el que había estado muerto, salió, atadas las manos y los pies con vendas; y su rostro estaba envuelto en un sudario. Díceles Jesús: Desatadle, y dejadle ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 45, 'Entonces muchos de los Judíos que habían venido á María, y habían visto lo que había hecho Jesús, creyeron en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 46, 'Mas algunos de ellos fueron á los Fariseos, y dijéronles lo que Jesús había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 47, 'Entonces los pontífices y los Fariseos juntaron concilio, y decían: ¿Qué hacemos? porque este hombre hace muchas señales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 48, 'Si le dejamos así, todos creerán en él: y vendrán los Romanos, y quitarán nuestro lugar y la nación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 49, 'Y Caifás, uno de ellos, sumo pontífice de aquel año, les dijo: Vosotros no sabéis nada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 50, 'Ni pensáis que nos conviene que un hombre muera por el pueblo, y no que toda la nación se pierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 51, 'Mas esto no lo dijo de sí mismo; sino que, como era el sumo pontífice de aquel año, profetizó que Jesús había de morir por la nación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 52, 'Y no solamente por aquella nación, mas también para que juntase en uno los hijos de Dios que estaban derramados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 53, 'Así que, desde aquel día consultaban juntos de matarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 54, 'Por tanto, Jesús ya no andaba manifiestamente entre los Judíos; mas fuése de allí á la tierra que está junto al desierto, á una ciudad que se llama Ephraim: y estábase allí con sus discípulos');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 55, 'Y la Pascua de los Judíos estaba cerca: y muchos subieron de aquella tierra á Jerusalem antes de la Pascua, para purificarse;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 56, 'Y buscaban á Jesús, y hablaban los unos con los otros estando en el templo. ¿Qué os parece, que no vendrá á la fiesta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 11, 57, 'Y los pontífices y los Fariseos habían dado mandamiento, que si alguno supiese dónde estuviera, lo manifestase, para que le prendiesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 1, 'Y JESUS, seis días antes de la Pascua, vino á Bethania, donde estaba Lázaro, que había sido muerto, al cual había resucitado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 2, 'E hiciéronle allí una cena y Marta servía, y Lázaro era uno de los que estaban sentados á la mesa juntamente con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 3, 'Entonces María tomó una libra de ungüento de nardo líquido de mucho precio, y ungió los pies de Jesús, y limpió sus pies con sus cabellos: y la casa se llenó del olor del ungüento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 4, 'Y dijo uno de sus discípulos, Judas Iscariote, hijo de Simón, el que le había de entregar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 5, '¿Por qué no se ha vendido este ungüento por trescientos dineros, y se dió á los pobres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 6, 'Mas dijo esto, no por el cuidado que él tenía de los pobres: sino porque era ladrón, y tenía la bolsa, y traía lo que se echaba en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 7, 'Entonces Jesús dijo: Déjala; para el día de mi sepultura ha guardado esto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 8, 'Porque á los pobres siempre los tenéis con vosotros, mas á mí no siempre me tenéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 9, 'Entonces mucha gente de los Judíos entendió que él estaba allí; y vinieron no solamente por causa de Jesús, mas también por ver á Lázaro, al cual había resucitado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 10, 'Consultaron asimismo los príncipes de los sacerdotes, de matar también á Lázaro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 11, 'Porque muchos de los Judíos iban y creían en Jesús por causa de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 12, 'El siguiente día, mucha gente que había venido á la fiesta, como oyeron que Jesús venía á Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 13, 'Tomaron ramos de palmas, y salieron á recibirle, y clamaban: ¡Hosanna, Bendito el que viene en el nombre del Señor, el Rey de Israel!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 14, 'Y halló Jesús un asnillo, y se sentó sobre él, como está escrito:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 15, 'No temas, hija de Sión: he aquí tu Rey viene, sentado sobre un pollino de asna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 16, 'Estas cosas no las entendieron sus discípulos de primero: empero cuando Jesús fué glorificado, entonces se acordaron de que estas cosas estaban escritas de él, y que le hicieron estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 17, 'Y la gente que estaba con él, daba testimonio de cuando llamó á Lázaro del sepulcro, y le resucitó de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 18, 'Por lo cual también había venido la gente á recibirle, porque había oído que él había hecho esta señal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 19, 'Mas los Fariseos dijeron entre sí: ¿Veis que nada aprovecháis? he aquí, el mundo se va tras de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 20, 'Y había ciertos Griegos de los que habían subido á adorar en la fiesta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 21, 'Estos pues, se llegaron á Felipe, que era de Bethsaida de Galilea, y rogáronle, diciendo: Señor, querríamos ver á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 22, 'Vino Felipe, y díjolo á Andrés: Andrés entonces, y Felipe, lo dicen á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 23, 'Entonces Jesús les respondió, diciendo: La hora viene en que el Hijo del hombre ha de ser glorificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 24, 'De cierto, de cierto os digo, que si el grano de trigo no cae en la tierra y muere, él solo queda; mas si muriere, mucho fruto lleva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 25, 'El que ama su vida, la perderá; y el que aborrece su vida en este mundo, para vida eterna la guardará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 26, 'Si alguno me sirve, sígame: y donde yo estuviere, allí también estará mi servidor. Si alguno me sirviere, mi Padre le honrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 27, 'Ahora está turbada mi alma; ¿y qué diré? Padre, sálvame de esta hora. Mas por esto he venido en esta hora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 28, 'Padre, glorifica tu nombre. Entonces vino una voz del cielo: Y lo he glorificado, y lo glorificaré otra vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 29, 'Y la gente que estaba presente, y había oído, decía que había sido trueno. Otros decían: Angel le ha hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 30, 'Respondió Jesús, y dijo: No ha venido esta voz por mi causa, mas por causa de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 31, 'Ahora es el juicio de este mundo: ahora el príncipe de este mundo será echado fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 32, 'Y yo, si fuere levantado de la tierra, á todos traeré á mí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 33, 'Y esto decía dando á entender de qué muerte había de morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 34, 'Respondióle la gente: Nosotros hemos oído de la ley, que el Cristo permanece para siempre: ¿cómo pues dices tú: Conviene que el Hijo del hombre sea levantado? ¿Quién es este Hijo del hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 35, 'Entonces Jesús les dice: Aun por un poco estará la luz entre vosotros: andad entre tanto que tenéis luz, porque no os sorprendan las tinieblas; porque el que anda en tinieblas, no sabe dónde va.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 36, 'Entre tanto que tenéis la luz, creed en la luz, para que seáis hijos de luz. Estas cosas habló Jesús, y fuése, y escondióse de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 37, 'Empero habiendo hecho delante de ellos tantas señales, no creían en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 38, 'Para que se cumpliese el dicho que dijo el profeta Isaías: ¿Señor, quién ha creído á nuestro dicho? ¿Y el brazo del Señor, á quién es revelado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 39, 'Por esto no podían creer, porque otra vez dijo Isaías:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 40, 'Cegó los ojos de ellos, y endureció su corazón; Porque no vean con los ojos, y entiendan de corazón, Y se conviertan, Y yo los sane.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 41, 'Estas cosas dijo Isaías cuando vió su gloria, y habló de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 42, 'Con todo eso, aun de los príncipes, muchos creyeron en él; mas por causa de los Fariseos no lo confesaban, por no ser echados de la sinagoga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 43, 'Porque amaban más la gloria de los hombres que la gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 44, 'Mas Jesús clamó y dijo: El que cree en mí, no cree en mí, sino en el que me envió;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 45, 'Y el que me ve, ve al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 46, 'Yo la luz he venido al mundo, para que todo aquel que cree en mí no permanezca en tinieblas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 47, 'Y el que oyere mis palabras, y no las creyere, yo no le juzgo; porque no he venido á juzgar al mundo, sino á salvar al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 48, 'El que me desecha, y no recibe mis palabras, tiene quien le juzgue: la palabra que he hablado, ella le juzgará en el día postrero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 49, 'Porque yo no he hablado de mí mismo; mas el Padre que me envió, él me dió mandamiento de lo que he de decir, y de lo que he de hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 12, 50, 'Y sé que su mandamiento es vida eterna: así que, lo que yo hablo, como el Padre me lo ha dicho, así hablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 1, 'ANTES de la fiesta de la Pascua, sabiendo Jesús que su hora había venido para que pasase de este mundo al Padre, como había amado á los suyos que estaban en el mundo, amólos hasta el fin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 2, 'Y la cena acabada, como el diablo ya había metido en el corazón de Judas, hijo de Simón Iscariote, que le entregase,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 3, 'Sabiendo Jesús que el Padre le había dado todas las cosas en las manos, y que había salido de Dios, y á Dios iba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 4, 'Levántase de la cena, y quítase su ropa, y tomando una toalla, ciñóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 5, 'Luego puso agua en un lebrillo, y comenzó á lavar los pies de los discípulos, y á limpiarlos con la toalla con que estaba ceñido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 6, 'Entonces vino á Simón Pedro; y Pedro le dice: ¿Señor, tú me lavas los pies?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 7, 'Respondió Jesús, y díjole: Lo que yo hago, tú no entiendes ahora; mas lo entenderás después.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 8, 'Dícele Pedro: No me lavarás los pies jamás. Respondióle Jesús: Si no te lavare, no tendrás parte conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 9, 'Dícele Simón Pedro: Señor, no sólo mis pies, mas aun las manos y la cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 10, 'Dícele Jesús: El que está lavado, no necesita sino que lave los pies, mas está todo limpio: y vosotros limpios estáis, aunque no todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 11, 'Porque sabía quién le había de entregar; por eso dijo: No estáis limpios todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 12, 'Así que, después que les hubo lavado los pies, y tomado su ropa, volviéndose á sentar á la mesa, díjoles: ¿Sabéis lo que os he hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 13, 'Vosotros me llamáis, Maestro, y, Señor: y decís bien; porque lo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 14, 'Pues si yo, el Señor y el Maestro, he lavado vuestros pies, vosotros también debéis lavar los pies los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 15, 'Porque ejemplo os he dado, para que como yo os he hecho, vosotros también hagáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 16, 'De cierto, de cierto os digo: El siervo no es mayor que su señor, ni el apóstol es mayor que el que le envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 17, 'Si sabéis estas cosas, bienaventurados seréis, si las hiciereis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 18, 'No hablo de todos vosotros: yo sé los que he elegido: mas para que se cumpla la Escritura: El que come pan conmigo, levantó contra mí su calcañar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 19, 'Desde ahora os lo digo antes que se haga, para que cuando se hiciere, creáis que yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 20, 'De cierto, de cierto os digo: El que recibe al que yo enviare, á mí recibe; y el que á mí recibe, recibe al que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 21, 'Como hubo dicho Jesús esto, fué conmovido en el espíritu, y protestó, y dijo: De cierto, de cierto os digo, que uno de vosotros me ha de entregar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 22, 'Entonces los discípulos mirábanse los unos á los otros, dudando de quién decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 23, 'Y uno de sus discípulos, al cual Jesús amaba, estaba recostado en el seno de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 24, 'A éste, pues, hizo señas Simón Pedro, para que preguntase quién era aquél de quien decía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 25, 'El entonces recostándose sobre el pecho de Jesús, dícele: Señor, ¿quién es?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 26, 'Respondió Jesús: Aquél es, á quien yo diere el pan mojado. Y mojando el pan, diólo á Judas Iscariote, hijo de Simón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 27, 'Y tras el bocado Satanás entró en él. Entonces Jesús le dice: Lo que haces, haz lo más presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 28, 'Mas ninguno de los que estaban á la mesa entendió á qué propósito le dijo esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 29, 'Porque los unos pensaban, por que Judas tenía la bolsa, que Jesús le decía: Compra lo que necesitamos para la fiesta: ó, que diese algo á los pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 30, 'Como él pues hubo tomado el bocado, luego salió: y era ya noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 31, 'Entonces como él salió, dijo Jesús: Ahora es glorificado el Hijo del hombre, y Dios es glorificado en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 32, 'Si Dios es glorificado en él, Dios también le glorificará en sí mismo, y luego le glorificará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 33, 'Hijitos, aun un poco estoy con vosotros. Me buscaréis; mas, como dije á los Judíos: Donde yo voy, vosotros no podéis venir; así digo á vosotros ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 34, 'Un mandamiento nuevo os doy: Que os améis unos á otros: como os he amado, que también os améis los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 35, 'En esto conocerán todos que sois mis discípulos, si tuviereis amor los unos con los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 36, 'Dícele Simón Pedro: Señor, ¿adónde vas? Respondióle Jesús: Donde yo voy, no me puedes ahora seguir; mas me seguirás después.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 37, 'Dícele Pedro: Señor, ¿por qué no te puedo seguir ahora? mi alma pondré por ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 13, 38, 'Respondióle Jesús: ¿Tu alma pondrás por mí? De cierto, de cierto te digo: No cantará el gallo, sin que me hayas negado tres veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 1, 'NO se turbe vuestro corazón; creéis en Dios, creed también en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 2, 'En la casa de mi Padre muchas moradas hay: de otra manera os lo hubiera dicho: voy, pues, á preparar lugar para vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 3, 'Y si me fuere, y os aparejare lugar, vendré otra vez, y os tomaré á mí mismo: para que donde yo estoy, vosotros también estéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 4, 'Y sabéis á dónde yo voy; y sabéis el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 5, 'Dícele Tomás: Señor, no sabemos á dónde vas: ¿cómo, pues, podemos saber el camino?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 6, 'Jesús le dice: Yo soy el camino, y la verdad, y la vida: nadie viene al Padre, sino por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 7, 'Si me conocieseis, también á mi Padre conocierais: y desde ahora le conocéis, y le habéis visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 8, 'Dícele Felipe: Señor, muéstranos el Padre, y nos basta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 9, 'Jesús le dice: ¿Tanto tiempo ha que estoy con vosotros, y no me has conocido, Felipe? El que me ha visto, ha visto al Padre; ¿cómo, pues, dices tú: Muéstranos el Padre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 10, '¿No crees que yo soy en el Padre, y el Padre en mí? Las palabras que yo os hablo, no las hablo de mí mismo: mas el Padre que está en mí, él hace las obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 11, 'Creedme que yo soy en el Padre, y el Padre en mí: de otra manera, creedme por las mismas obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 12, 'De cierto, de cierto os digo: El que en mí cree, las obras que yo hago también él las hará; y mayores que éstas hará; porque yo voy al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 13, 'Y todo lo que pidiereis al Padre en mi nombre, esto haré, para que el Padre sea glorificado en el Hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 14, 'Si algo pidiereis en mi nombre, yo lo haré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 15, 'Si me amáis, guardad mis mandamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 16, 'Y yo rogaré al Padre, y os dará otro Consolador, para que esté con vosotros para siempre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 17, 'Al Espíritu de verdad, al cual el mundo no puede recibir, porque no le ve, ni le conoce: mas vosotros le conocéis; porque está con vosotros, y será en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 18, 'No os dejaré huérfanos: vendré á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 19, 'Aun un poquito, y el mundo no me verá más; empero vosotros me veréis; porque yo vivo, y vosotros también viviréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 20, 'En aquel día vosotros conoceréis que yo estoy en mi Padre, y vosotros en mí, y yo en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 21, 'El que tiene mis mandamientos, y los guarda, aquél es el que me ama; y el que me ama, será amado de mi Padre, y yo le amaré, y me manifestaré á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 22, 'Dícele Judas, no el Iscariote: Señor, ¿qué hay porque te hayas de manifestar á nosotros, y no al mundo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 23, 'Respondió Jesús, y díjole: El que me ama, mi palabra guardará; y mi Padre le amará, y vendremos á él, y haremos con él morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 24, 'El que no me ama, no guarda mis palabras: y la palabra que habéis oído, no es mía, sino del Padre que me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 25, 'Estas cosas os he hablado estando con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 26, 'Mas el Consolador, el Espíritu Santo, al cual el Padre enviará en mi nombre, él os enseñará todas las cosas, y os recordará todas las cosas que os he dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 27, 'La paz os dejo, mi paz os doy: no como el mundo la da, yo os la doy. No se turbe vuestro corazón, ni tenga miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 28, 'Habéis oído cómo yo os he dicho: Voy, y vengo á vosotros. Si me amaseis, ciertamente os gozaríais, porque he dicho que voy al Padre: porque el Padre mayor es que yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 29, 'Y ahora os lo he dicho antes que se haga; para que cuando se hiciere, creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 30, 'Ya no hablaré mucho con vosotros: porque viene el príncipe de este mundo; mas no tiene nada en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 14, 31, 'Empero para que conozca el mundo que amo al Padre, y como el Padre me dió el mandamiento, así hago. Levantaos, vamos de aquí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 1, 'YO soy la vid verdadera, y mi Padre es el labrador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 2, 'Todo pámpano que en mí no lleva fruto, le quitará: y todo aquel que lleva fruto, le limpiará, para que lleve más fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 3, 'Ya vosotros sois limpios por la palabra que os he hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 4, 'Estad en mí, y yo en vosotros. Como el pámpano no puede llevar fruto de sí mismo, si no estuviere en la vid; así ni vosotros, si no estuviereis en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 5, 'Yo soy la vid, vosotros los pámpanos: el que está en mí, y yo en él, éste lleva mucho fruto; porque sin mí nada podéis hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 6, 'El que en mí no estuviere, será echado fuera como mal pámpano, y se secará; y los cogen, y los echan en el fuego, y arden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 7, 'Si estuviereis en mí, y mis palabras estuvieren en vosotros, pedid todo lo que quisiereis, y os será hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 8, 'En esto es glorificado mi Padre, en que llevéis mucho fruto, y seáis así mis discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 9, 'Como el Padre me amó, también yo os he amado: estad en mi amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 10, 'Si guardareis mis mandamientos, estaréis en mi amor; como yo también he guardado los mandamientos de mi Padre, y estoy en su amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 11, 'Estas cosas os he hablado, para que mi gozo esté en vosotros, y vuestro gozo sea cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 12, 'Este es mi mandamiento: Que os améis los unos á los otros, como yo os he amado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 13, 'Nadie tiene mayor amor que este, que ponga alguno su vida por sus amigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 14, 'Vosotros sois mis amigos, si hiciereis las cosas que yo os mando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 15, 'Ya no os llamaré siervos, porque el siervo no sabe lo que hace su señor: mas os he llamado amigos, porque todas las cosas que oí de mi Padre, os he hecho notorias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 16, 'No me elegisteis vosotros á mí, mas yo os elegí á vosotros; y os he puesto para que vayáis y llevéis fruto, y vuestro fruto permanezca: para que todo lo que pidiereis del Padre en mi nombre, él os lo dé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 17, 'Esto os mando: Que os améis los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 18, 'Si el mundo os aborrece, sabed que á mí me aborreció antes que á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 19, 'Si fuerais del mundo, el mundo amaría lo suyo; mas porque no sois del mundo, antes yo os elegí del mundo, por eso os aborrece el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 20, 'Acordaos de la palabra que yo os he dicho: No es el siervo mayor que su señor. Si á mí mé han perseguido, también á vosotros perseguirán: si han guardado mi palabra, también guardarán la vuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 21, 'Mas todo esto os harán por causa de mi nombre, porque no conocen al que me ha enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 22, 'Si no hubiera venido, ni les hubiera hablado, no tendrían pecado, mas ahora no tienen excusa de su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 23, 'El que me aborrece, también á mi Padre aborrece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 24, 'Si no hubiese hecho entre ellos obras cuales ningún otro ha hecho, no tendrían pecado; mas ahora, y las han visto, y me aborrecen á mí y á mi Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 25, 'Mas para que se cumpla la palabra que está escrita en su ley: Que sin causa me aborrecieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 26, 'Empero cuando viniere el Consolador, el cual yo os enviaré del Padre, el Espíritu de verdad, el cual procede del Padre, él dará testimonio de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 15, 27, 'Y vosotros daréis testimonio, porque estáis conmigo desde el principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 1, 'ESTAS cosas os he hablado, para que no os escandalicéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 2, 'Os echarán de los sinagogas; y aun viene la hora, cuando cualquiera que os matare, pensará que hace servició á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 3, 'Y estas cosas os harán, porque no conocen al Padre ni á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 4, 'Mas os he dicho esto, para que cuando aquella hora viniere, os acordeis que yo os lo había dicho. Esto empero no os lo dije al principio, porque yo estaba con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 5, 'Mas ahora voy al que me envió; y ninguno de vosotros me pregunta: ¿Adónde vas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 6, 'Antes, porque os he hablado estas cosas, tristeza ha henchido vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 7, 'Empero yo os digo la verdad: Os es necesario que yo vaya: porque si yo no fuese, el Consolador no vendría á vosotros; mas si yo fuere, os le enviaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 8, 'Y cuando él viniere redargüirá al mundo de pecado, y de justicia, y de juicio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 9, 'De pecado ciertamente, por cuanto no creen en mí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 10, 'Y de justicia, por cuanto voy al Padre, y no me veréis más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 11, 'Y de juicio, por cuanto el príncipe de este mundo es juzgado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 12, 'Aun tengo muchas cosas que deciros, mas ahora no las podéis llevar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 13, 'Pero cuando viniere aquel Espíritu de verdad, él os guiará á toda verdad; porque no hablará de sí mismo, sino que hablará todo lo que oyere, y os hará saber las cosas que han de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 14, 'El me glorificará: porque tomará de lo mío, y os lo hará saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 15, 'Todo lo que tiene el Padre, mío es: por eso dije que tomará de lo mío, y os lo hará saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 16, 'Un poquito, y no me veréis; y otra vez un poquito, y me veréis: porque yo voy al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 17, 'Entonces dijeron algunos de sus discípulos unos á otros: ¿Qué es esto que nos dice: Un poquito, y no me veréis; y otra vez un poquito, y me veréis: y, por que yo voy al Padre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 18, 'Decían pues: ¿Qué es esto que dice: Un poquito? No entendemos lo que habla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 19, 'Y conoció Jesús que le querían preguntar, y díjoles: ¿Preguntáis entre vosotros de esto que dije: Un poquito, y no me veréis, y otra vez un poquito, y me veréis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 20, 'De cierto, de cierto os digo, que vosotros lloraréis y lamentaréis, y el mundo se alegrará: empero aunque vosotros estaréis tristes, vuestra tristeza se tornará en gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 21, 'La mujer cuando pare, tiene dolor, porque es venida su hora; mas después que ha parido un niño, ya no se acuerda de la angustia, por el gozo de que haya nacido un hombre en el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 22, 'También, pues, vosotros ahora ciertamente tenéis tristeza; mas otra vez os veré, y se gozará vuestro corazón, y nadie quitará de vosotros vuestro gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 23, 'Y aquel día no me preguntaréis nada. De cierto, de cierto os digo, que todo cuanto pidiereis al Padre en mi nombre, os lo dará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 24, 'Hasta ahora nada habéis pedido en mi nombre: pedid, y recibiréis, para que vuestro gozo sea cumplido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 25, 'Estas cosas os he hablado en proverbios: la hora viene cuando ya no os hablaré por proverbios, pero claramente os anunciaré del Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 26, 'Aquel día pediréis en mi nombre: y no os digo, que yo rogaré al Padre por vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 27, 'Pues el mismo Padre os ama, porque vosotros me amasteis, y habéis creído que yo salí de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 28, 'Salí del Padre, y he venido al mundo: otra vez dejo el mundo, y voy al Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 29, 'Dícenle sus discípulos: He aquí, ahora hablas claramente, y ningún proverbio dices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 30, 'Ahora entendemos que sabes todas las cosas, y no necesitas que nadie te pregunte: en esto creemos que has salido de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 31, 'Respondióles Jesús: ¿Ahora creéis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 32, 'He aquí, la hora viene, y ha venido, que seréis esparcidos cada uno por su parte, y me dejaréis solo: mas no estoy solo, porque el Padre está conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 16, 33, 'Estas cosas os he hablado, para que en mí tengáis paz. En el mundo tendréis aflicción: mas confiad, yo he vencido al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 1, 'ESTAS cosas habló Jesús, y levantados los ojos al cielo, dijo: Padre, la hora es llegada; glorifica á tu Hijo, para que también tu Hijo te glorifique á ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 2, 'Como le has dado la potestad de toda carne, para que dé vida eterna á todos los que le diste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 3, 'Esta empero es la vida eterna: que te conozcan el solo Dios verdadero, y á Jesucristo, al cual has enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 4, 'Yo te he glorificado en la tierra: he acabado la obra que me diste que hiciese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 5, 'Ahora pues, Padre, glorifícame tú cerca de ti mismo con aquella gloria que tuve cerca de ti antes que el mundo fuese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 6, 'He manifestado tu nombre á los hombres que del mundo me diste: tuyos eran, y me los diste, y guardaron tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 7, 'Ahora han conocido que todas las cosas que me diste, son de ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 8, 'Porque las palabras que me diste, les he dado; y ellos las recibieron, y han conocido verdaderamente que salí de ti, y han creído que tú me enviaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 9, 'Yo ruego por ellos: no ruego por el mundo, sino por los que me diste; porque tuyos son:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 10, 'Y todas mis cosas son tus cosas, y tus cosas son mis cosas: y he sido glorificado en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 11, 'Y ya no estoy en el mundo; mas éstos están en el mundo, y yo á ti vengo. Padre santo, á los que me has dado, guárdalos por tu nombre, para que sean una cosa, como también nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 12, 'Cuando estaba con ellos en el mundo, yo los guardaba en tu nombre; á los que me diste, yo los guardé, y ninguno de ellos se perdió, sino el hijo de perdición; para que la Escritura se cumpliese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 13, 'Mas ahora vengo á ti; y hablo esto en el mundo, para que tengan mi gozo cumplido en sí mismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 14, 'Yo les he dado tu palabra; y el mundo los aborreció, porque no son del mundo, como tampoco yo soy del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 15, 'No ruego que los quites del mundo, sino que los guardes del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 16, 'No son del mundo, como tampoco yo soy del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 17, 'Santifícalos en tu verdad: tu palabra es verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 18, 'Como tú me enviaste al mundo, también los he enviado al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 19, 'Y por ellos yo me santifico á mí mismo, para que también ellos sean santificados en verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 20, 'Mas no ruego solamente por éstos, sino también por los que han de creer en mí por la palabra de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 21, 'Para que todos sean una cosa; como tú, oh Padre, en mí, y yo en ti, que también ellos sean en nosotros una cosa: para que el mundo crea que tú me enviaste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 22, 'Y yo, la gloria que me diste les he dado; para que sean una cosa, como también nosotros somos una cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 23, 'Yo en ellos, y tú en mí, para que sean consumadamente una cosa; que el mundo conozca que tú me enviaste, y que los has amado, como también á mí me has amado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 24, 'Padre, aquellos que me has dado, quiero que donde yo estoy, ellos estén también conmigo; para que vean mi gloria que me has dado: por cuanto me has amado desde antes de la constitución del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 25, 'Padre justo, el mundo no te ha conocido, mas yo te he conocido; y éstos han conocido que tú me enviaste;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 17, 26, 'Y yo les he manifestado tu nombre, y manifestaré lo aún; para que el amor con que me has amado, esté en ellos, y yo en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 1, 'COMO Jesús hubo dicho estas cosas, salióse con sus discípulos tras el arroyo de Cedrón, donde estaba un huerto, en el cual entró Jesús y sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 2, 'Y también Judas, el que le entregaba, sabía aquel lugar; porque muchas veces Jesús se juntaba allí con sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 3, 'Judas pues tomando una compañía, y ministros de los pontífices y de los Fariseos, vino allí con linternas y antorchas, y con armas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 4, 'Empero Jesús, sabiendo todas las cosas que habían de venir sobre él, salió delante, y díjoles: ¿A quién buscáis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 5, 'Respondiéronle: A Jesús Nazareno. Díceles Jesús; Yo soy (Y estaba también con ellos Judas, el que le entregaba.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 6, 'Y como les dijo, Yo soy, volvieron atrás, y cayeron en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 7, 'Volvióles, pues, á preguntar: ¿A quién buscáis? Y ellos dijeron: A Jesús Nazareno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 8, 'Respondió Jesús: Os he dicho que yo soy: pues si á mi buscáis, dejad ir á éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 9, 'Para que se cumpliese la palabra que había dicho: De los que me diste, ninguno de ellos perdí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 10, 'Entonces Simón Pedro, que tenía espada, sacóla, é hirió al siervo del pontífice, y le cortó la oreja derecha. Y el siervo se llamaba Malco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 11, 'Jesús entonces dijo á Pedro: Mete tu espada en la vaina: el vaso que el Padre me ha dado, ¿no lo tengo de beber?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 12, 'Entonces la compañía y el tribuno, y los ministros de los Judíos, prendieron á Jesús y le ataron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 13, 'Y lleváronle primeramente á Anás; porque era suegro de Caifás, el cual era pontífice de aquel año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 14, 'Y era Caifás el que había dado el consejo á los Judíos, que era necesario que un hombre muriese por el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 15, 'Y seguía á Jesús Simón Pedro, y otro discípulo. Y aquel discípulo era conocido del pontífice, y entró con Jesús al atrio del pontífice;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 16, 'Mas Pedro estaba fuera á la puerta. Y salió aquel discípulo que era conocido del pontífice, y habló á la portera, y metió dentro á Pedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 17, 'Entonces la criada portera dijo á Pedro: ¿No eres tú también de los discípulos de este hombre? Dice él: No soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 18, 'Y estaban en pie los siervos y los ministros que habían allegado las ascuas; porque hacía frío, y calentábanse: y estaba también con ellos Pedro en pie, calentándose.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 19, 'Y el pontífice preguntó á Jesús acerca de sus discípulos y de su doctrina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 20, 'Jesús le respondió: Yo manifiestamente he hablado al mundo: yo siempre he enseñado en la sinagoga y en el templo, donde se juntan todos los Judíos, y nada he hablado en oculto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 21, '¿Qué me preguntas á mí? Pregunta á los que han oído, qué les haya yo hablado: he aquí, ésos saben lo que yo he dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 22, 'Y como él hubo dicho esto, uno de los criados que estaba allí, dió una bofetada á Jesús, diciendo: ¿Así respondes al pontífice?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 23, 'Respondióle Jesús: Si he hablado mal, da testimonio del mal: y si bien, ¿por qué me hieres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 24, 'Y Anás le había enviado atado á Caifás pontífice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 25, 'Estaba pues Pedro en pie calentándose. Y dijéronle: ¿No eres tú de sus discípulos? El negó, y dijo: No soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 26, 'Uno de los siervos del pontífice, pariente de aquél á quien Pedro había cortado la oreja, le dice: ¿No te vi yo en el huerto con él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 27, 'Y negó Pedro otra vez: y luego el gallo cantó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 28, 'Y llevaron á Jesús de Caifás al pretorio: y era por la mañana: y ellos no entraron en el pretorio por no ser contaminados, sino que comiesen la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 29, 'Entonces salió Pilato á ellos fuera, y dijo: ¿Qué acusación traéis contra este hombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 30, 'Respondieron y dijéronle: Si éste no fuera malhechor, no te le habríamos entregado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 31, 'Díceles entonces Pilato: Tomadle vosotros, y juzgadle según vuestra ley. Y los Judíos le dijeron: A nosotros no es lícito matar á nadie:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 32, 'Para que se cumpliese el dicho de Jesús, que había dicho, dando á entender de qué muerte había de morir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 33, 'Así que, Pilato volvió á entrar en el pretorio, y llamó á Jesús, y díjole: ¿Eres tú el Rey de los Judíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 34, 'Respondióle Jesús: ¿Dices tú esto de ti mismo, ó te lo han dicho otros de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 35, 'Pilato respondió: ¿Soy yo Judío? Tu gente, y los pontífices, te han entregado á mí: ¿qué has hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 36, 'Respondió Jesús: Mi reino no es de este mundo: si de este mundo fuera mi reino, mis servidores pelearían para que yo no fuera entregado á los Judíos: ahora, pues, mi reino no es de aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 37, 'Díjole entonces Pilato: ¿Luego rey eres tu? Respondió Jesús: Tu dices que yo soy rey. Yo para esto he nacido, y para esto he venido al mundo, para dar testimonio á la verdad. Todo aquél que es de la verdad, oye mi voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 38, 'Dícele Pilato: ¿Qué cosa es verdad? Y como hubo dicho esto, salió otra vez á los Judíos, y díceles: Yo no hallo en él ningún crimen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 39, 'Empero vosotros tenéis costumbre, que os suelte uno en la Pascua: ¿queréis, pues, que os suelte al Rey de los Judíos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 18, 40, 'Entonces todos dieron voces otra vez, diciendo: No á éste, sino á Barrabás. Y Barrabás era ladrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 1, 'ASI que, entonces tomó Pilato á Jesús, y le azotó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 2, 'Y los soldados entretejieron de espinas una corona, y pusiéron la sobre su cabeza, y le vistieron de una ropa de grana;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 3, 'Y decían: ¡Salve, Rey de los Judíos! y dábanle de bofetadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 4, 'Entonces Pilato salió otra vez fuera, y díjoles: He aquí, os le traigo fuera, para que entendáis que ningún crimen hallo en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 5, 'Y salió Jesús fuera, llevando la corona de espinas y la ropa de grana. Y díceles Pilato: He aquí el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 6, 'Y como le vieron los príncipes de los sacerdotes, y los servidores, dieron voces diciendo: Crucifícale, crucifícale. Díceles Pilato: Tomadle vosotros, y crucificadle; porque yo no hallo en él crimen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 7, 'Respondiéronle los Judíos: Nosotros tenemos ley, y según nuestra ley debe morir, porque se hizo Hijo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 8, 'Y como Pilato oyó esta palabra, tuvo más miedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 9, 'Y entró otra vez en el pretorio, y dijo á Jesús: ¿De dónde eres tú? Mas Jesús no le dió respuesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 10, 'Entonces dícele Pilato: ¿A mí no me hablas? ¿no sabes que tengo potestad para crucificarte, y que tengo potestad para soltarte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 11, 'Respondió Jesús: Ninguna potestad tendrías contra mí, si no te fuese dado de arriba: por tanto, el que á ti me ha entregado, mayor pecado tiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 12, 'Desde entonces procuraba Pilato soltarle; mas los Judíos daban voces, diciendo: Si á éste sueltas, no eres amigo de César: cualquiera que se hace rey, á César contradice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 13, 'Entonces Pilato, oyendo este dicho, llevó fuera á Jesús, y se sentó en el tribunal en el lugar que se dice Lithóstrotos, y en hebreo Gabbatha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 14, 'Y era la víspera de la Pascua, y como la hora de sexta. Entonces dijo á los Judíos: He aquí vuestro Rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 15, 'Mas ellos dieron voces: Quita, quita, crucifícale. Díceles Pilato: ¿A vuestro Rey he de crucificar? Respondieron los pontífices: No tenemos rey sino á César.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 16, 'Así que entonces lo entregó á ellos para que fuese crucificado. Y tomaron á Jesús, y le llevaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 17, 'Y llevando su cruz, salió al lugar que se dice de la Calavera, y en hebreo, Gólgotha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 18, 'Donde le crucificaron, y con él otros dos, uno á cada lado, y Jesús en medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 19, 'Y escribió también Pilato un título, que puso encima de la cruz. Y el escrito era: JESUS NAZARENO, REY DE LOS JUDIOS.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 20, 'Y muchos de los Judíos leyeron este título: porque el lugar donde estaba crucificado Jesús era cerca de la ciudad: y estaba escrito en hebreo, en griego, y en latín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 21, 'Y decían á Pilato los pontífices de los Judíos: No escribas, Rey de los Judíos: sino, que él dijo: Rey soy de los Judíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 22, 'Respondió Pilato: Lo que he escrito, he escrito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 23, 'Y como los soldados hubieron crucificado á Jesús, tomaron sus vestidos, é hicieron cuatro partes (para cada soldado una parte); y la túnica; mas la túnica era sin costura, toda tejida desde arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 24, 'Y dijeron entre ellos: No la partamos, sino echemos suertes sobre ella, de quién será; para que se cumpliese la Escritura, que dice: Partieron para sí mis vestidos, Y sobre mi vestidura echaron suertes. Y los soldados hicieron esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 25, 'Y estaban junto á la cruz de Jesús su madre, y la hermana de su madre, María mujer de Cleofas, y María Magdalena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 26, 'Y como vió Jesús á la madre, y al discípulo que él amaba, que estaba presente, dice á su madre: Mujer, he ahí tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 27, 'Después dice al discípulo: He ahí tu madre. Y desde aquella hora el discípulo la recibió consigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 28, 'Después de esto, sabiendo Jesús que todas las cosas eran ya cumplidas, para que la Escritura se cumpliese, dijo: Sed tengo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 29, 'Y estaba allí un vaso lleno de vinagre: entonces ellos hinchieron una esponja de vinagre, y rodeada á un hisopo, se la llegaron á la boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 30, 'Y como Jesús tomó el vinagre, dijo: Consumado es. Y habiendo inclinado la cabeza, dió el espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 31, 'Entonces los Judíos, por cuanto era la víspera de la Pascua, para que los cuerpos no quedasen en la cruz en el sábado, pues era el gran día del sábado, rogaron á Pilato que se les quebrasen las piernas, y fuesen quitados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 32, 'Y vinieron los soldados, y quebraron las piernas al primero, y asimismo al otro que había sido crucificado con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 33, 'Mas cuando vinieron á Jesús, como le vieron ya muerto, no le quebraron las piernas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 34, 'Empero uno de los soldados le abrió el costado con una lanza, y luego salió sangre y agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 35, 'Y el que lo vió, da testimonio, y su testimonio es verdadero: y él sabe que dice verdad, para que vosotros también creáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 36, 'Porque estas cosas fueron hechas para que se cumpliese la Escritura: Hueso no quebrantaréis de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 37, 'Y también otra Escritura dice: Mirarán al que traspasaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 38, 'Después de estas cosas, José de Arimatea, el cual era discípulo de Jesús, mas secreto por miedo de los Judíos, rogó á Pilato que pudiera quitar el cuerpo de Jesús: y permitióselo Pilato. Entonces vino, y quitó el cuerpo de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 39, 'Y vino también Nicodemo, el que antes había venido á Jesús de noche, trayendo un compuesto de mirra y de áloes, como cien libras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 40, 'Tomaron pues el cuerpo de Jesús, y envolviéronlo en lienzos con especias, como es costumbre de los Judíos sepultar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 41, 'Y en aquel lugar donde había sido crucificado, había un huerto; y en el huerto un sepulcro nuevo, en el cual aun no había sido puesto ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 19, 42, 'Allí, pues, por causa de la víspera de la Pascua de los Judíos, porque aquel sepulcro estaba cerca, pusieron á Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 1, 'Y EL primer día de la semana, María Magdalena vino de mañana, siendo aún obscuro, al sepulcro; y vió la piedra quitada del sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 2, 'Entonces corrió, y vino á Simón Pedro, y al otro discípulo, al cual amaba Jesús, y les dice: Han llevado al Señor del sepulcro, y no sabemos dónde le han puesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 3, 'Y salió Pedro, y el otro discípulo, y vinieron al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 4, 'Y corrían los dos juntos; mas el otro discípulo corrió más presto que Pedro, y llegó primero al sepulcro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 5, 'Y bajándose á mirar, vió los lienzos echados; mas no entró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 6, 'Llegó luego Simón Pedro siguiéndole, y entró en el sepulcro, y vió los lienzos echados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 7, 'Y el sudario, que había estado sobre su cabeza, no puesto con los lienzos, sino envuelto en un lugar aparte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 8, 'Y entonces entró también el otro discípulo, que había venido primero al sepulcro, y vió, y creyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 9, 'Porque aun no sabían la Escritura, que era necesario que él resucitase de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 10, 'Y volvieron los discípulos á los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 11, 'Empero María estaba fuera llorando junto al sepulcro: y estando llorando, bajóse á mirar el sepulcro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 12, 'Y vió dos ángeles en ropas blancas que estaban sentados, el uno á la cabecera, y el otro á los pies, donde el cuerpo de Jesús había sido puesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 13, 'Y dijéronle: Mujer, ¿por qué lloras? Díceles: Porque se han llevado á mi Señor, y no sé dónde le han puesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 14, 'Y como hubo dicho esto, volvióse atrás, y vió á Jesús que estaba allí; mas no sabía que era Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 15, 'Dícele Jesús: Mujer, ¿por qué lloras? ¿á quién buscas? Ella, pensando que era el hortelano, dícele: Señor, si tú lo has llevado, dime dónde lo has puesto, y yo lo llevaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 16, 'Dícele Jesús: ¡María! Volviéndose ella, dícele: ¡Rabboni! que quiere decir, Maestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 17, 'Dícele Jesús: No me toques: porque aun no he subido á mi Padre: mas ve á mis hermanos, y diles: Subo á mi Padre y á vuestro Padre, á mi Dios y á vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 18, 'Fué María Magdalena dando las nuevas á los discípulos de que había visto al Señor, y que él le había dicho estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 19, 'Y como fué tarde aquel día, el primero de la semana, y estando las puertas cerradas donde los discípulos estaban juntos por miedo de los Judíos, vino Jesús, y púsose en medio, y díjoles: Paz á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 20, 'Y como hubo dicho esto, mostróles las manos y el costado. Y los discípulos se gozaron viendo al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 21, 'Entonces les dijo Jesús otra vez: Paz á vosotros: como me envió el Padre, así también yo os envío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 22, 'Y como hubo dicho esto, sopló, y díjoles: Tomad el Espíritu Santo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 23, 'A los que remitiereis los pecados, les son remitidos: á quienes los retuviereis, serán retenidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 24, 'Empero Tomás, uno de los doce, que se dice el Dídimo, no estaba con ellos cuando Jesús vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 25, 'Dijéronle pues los otros discípulos: Al Señor hemos visto. Y él les dijo: Si no viere en sus manos la señal de los clavos, y metiere mi dedo en el lugar de los clavos, y metiere mi mano en su costado, no creeré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 26, 'Y ocho días después, estaban otra vez sus discípulos dentro, y con ellos Tomás. Vino Jesús, las puertas cerradas, y púsose en medio, y dijo: Paz á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 27, 'Luego dice á Tomás: Mete tu dedo aquí, y ve mis manos: y alarga acá tu mano, y métela en mi costado: y no seas incrédulo, sino fiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 28, 'Entonces Tomás respondió, y díjole: ¡Señor mío, y Dios mío!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 29, 'Dícele Jesús: Porque me has visto, Tomás, creiste: bienaventurados los que no vieron y creyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 30, 'Y también hizo Jesús muchas otras señales en presencia de sus discípulos, que no están escritas en este libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 20, 31, 'Estas empero son escritas, para que creáis que Jesús es el Cristo, el Hijo de Dios; y para que creyendo, tengáis vida en su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 1, 'DESPUÉS se manifestó Jesús otra vez á sus discípulos en la mar de Tiberias; y manifestóse de esta manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 2, 'Estaban juntos Simón Pedro, y Tomás, llamado al Dídimo, y Natanael, el que era de Caná de Galilea, y los hijos de Zebedeo, y otros dos de sus discípulos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 3, 'Díceles Simón: A pescar voy. Dícenle: Vamos nosotros también contigo. Fueron, y subieron en una barca; y aquella noche no cogieron nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 4, 'Y venida la mañana, Jesús se puso á la ribera: mas los discípulos no entendieron que era Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 5, 'Y díjoles: Mozos, ¿tenéis algo de comer? Respondiéronle: No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 6, 'Y él les dice: Echad la red á la mano derecha del barco, y hallaréis. Entonces la echaron, y no la podían en ninguna manera sacar, por la multitud de los peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 7, 'Entonces aquel discípulo, al cual amaba Jesús, dijo á Pedro: El Señor es. Y Simón Pedro, como oyó que era el Señor, ciñóse la ropa, porque estaba desnudo, y echóse á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 8, 'Y los otros discípulos vinieron con el barco (porque no estaban lejos de tierra sino como doscientos codos), trayendo la red de peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 9, 'Y como descendieron á tierra, vieron ascuas puestas, y un pez encima de ellas, y pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 10, 'Díceles Jesús; Traed de los peces que cogisteis ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 11, 'Subió Simón Pedro, y trajo la red á tierra, llena de grandes peces, ciento cincuenta y tres: y siendo tantos, la red no se rompió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 12, 'Díceles Jesús: Venid, comed. Y ninguno de los discípulos osaba preguntarle: ¿Tú, quién eres? sabiendo que era el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 13, 'Viene pues Jesús, y toma el pan, y les da; y asimismo del pez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 14, 'Esta era ya la tercera vez que Jesús se manifestó á sus discípulos, habiendo resucitado de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 15, 'Y cuando hubieron comido, Jesús dijo á Simón Pedro: Simón, hijo de Jonás, ¿me amas más que estos? Dícele; Sí Señor: tú sabes que te amo. Dícele: Apacienta mis corderos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 16, 'Vuélvele á decir la segunda vez: Simón, hijo de Jonás, ¿me amas? Respóndele: Sí, Señor: tú sabes que te amo. Dícele: Apacienta mis ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 17, 'Dícele la tercera vez: Simón, hijo de Jonás, ¿me amas? Entristecióse Pedro de que le dijese la tercera vez: ¿Me amas? y dícele: Señor, tú sabes todas las cosas; tú sabes que te amo. Dícele Jesús: Apacienta mis ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 18, 'De cierto, de cierto te digo: Cuando eras más mozo, te ceñías, é ibas donde querías; mas cuando ya fueres viejo, extenderás tus manos, y te ceñirá otro, y te llevará á donde no quieras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 19, 'Y esto dijo, dando á entender con qué muerte había de glorificar á Dios. Y dicho esto, dícele: Sígueme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 20, 'Volviéndose Pedro, ve á aquel discípulo al cual amaba Jesús, que seguía, el que también se había recostado á su pecho en la cena, y le había dicho: Señor, ¿quién es el que te ha de entregar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 21, 'Así que Pedro vió á éste, dice á Jesús: Señor, ¿y éste, qué?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 22, 'Dícele Jesús: Si quiero que él quede hasta que yo venga, ¿qué á tí? Sígueme tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 23, 'Salió entonces este dicho entre los hermanos, que aquel discípulo no había de morir. Mas Jesús no le dijo, No morirá; sino: Si quiero que él quede hasta que yo venga ¿qué á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 24, 'Este es aquel discípulo que da testimonio de estas cosas, y escribió estas cosas: y sabemos que su testimonio es verdadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JHN', 'Juan', 21, 25, 'Y hay también otras muchas cosas que hizo Jesús, que si se escribiesen cada una por sí, ni aun en el mundo pienso que cabrían los libros que se habrían de escribir. Amén.');
